	/**
	 * Install a store-provided gate for background rebuilds. Returning {@code false} pauses refresh-thread rebuild
	 * attempts until the gate opens again.
	 */
	public void setRebuildAllowedSupplier(BooleanSupplier supplier) {
		this.rebuildAllowedSupplier = supplier;
	}

	public void startBackgroundRefresh(int stalenessThreshold) {
		if (running) {
			return;
		}
		running = true;

		refresher = new Thread(() -> {
			while (running) {
				if (!isRebuildAllowed()) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				if (rebuildRequired.get()) {
					try {
						rebuild();
					} catch (Throwable t) {
						logger.error("Error while rebuilding join estimator", t);
					}
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				if (!sketchesLoaded && lazyLoadEnabled) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}

				boolean stale = isStale(stalenessThreshold);
				if (!stale) {
					try {
						Thread.sleep(refreshSleepMillis);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						break;
					}
					continue;
				}
//				Staleness staleness = staleness();
//				System.out.println(staleness.toString());

				try {
					rebuild();
				} catch (Throwable t) {

					logger.error("Error while rebuilding join estimator", t);
				}

				try {
					Thread.sleep(refreshSleepMillis);
				} catch (InterruptedException ie) {
					Thread.currentThread().interrupt();
					break;
				}

				logger.debug("RdfJoinEstimator: Rebuilt join estimator.");
			}
		}, REFRESH_THREAD_NAME);

		refresher.setDaemon(true);
		refresher.start();
	}

	public void stop() {
		running = false;
		Thread refreshThread = refresher;
		if (refreshThread != null) {
			refreshThread.interrupt();
			if (Thread.currentThread() == refreshThread) {
				return;
			}
			try {
				while (refreshThread.isAlive()) {
					refreshThread.join(250L);
				}
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
			} finally {
				refresher = null;
			}
		}
	}

	public void close() {
		flushPendingIncremental();
		stop();
		try {
			persistIfDirty();
		} finally {
			closeMemoryMonitor();
			shutdownAsyncIncrementalIngest();
			clearEstimateCache();
			closePersistenceStore();
		}
	}

	private void startMemoryMonitor() {
		closeMemoryMonitor();
		SketchEstimatorMemoryMonitor monitor = new SketchEstimatorMemoryMonitor(memoryProbe, memoryPolicy,
				new SketchEstimatorMemoryMonitor.EvictionController() {
					@Override
					public void enforceResidentCeiling() {
						enforceSketchBudget();
					}

					@Override
					public int evictLruBatch(int batchSize) {
						return evictResidentSketchBatch(batchSize);
					}

					@Override
					public int activeLoadedBucketCount() {
						return SketchBasedJoinEstimator.this.activeLoadedBucketCount();
					}
				}, logger);
		memoryMonitor = monitor;
		monitor.start();
	}

	private void closeMemoryMonitor() {
		SketchEstimatorMemoryMonitor monitor = memoryMonitor;
		memoryMonitor = null;
		if (monitor != null) {
			monitor.close();
		}
	}

	private void closePersistenceStore() {
		SketchEstimatorPersistenceStore store = persistenceStore;
		persistenceStore = null;
		if (store != null) {
			store.close();
		}
	}

	private void shutdownAsyncIncrementalIngest() {
		asyncIncrementalExecutor.shutdownNow();
		try {
			asyncIncrementalWorker.get(1, TimeUnit.SECONDS);
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
		} catch (Exception e) {
			logger.debug("Join estimator async ingestion worker stopped with an exception", e);
		} finally {
			ingestPartitionExecutor.shutdownNow();
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Rebuild */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Rebuild the inactive buffer from scratch (blocking). <br>
	 * Readers stay lock‑free; once complete a single volatile store publishes the fresh {@code State}.
	 *
	 * @return number of statements scanned.
	 */
	public synchronized long rebuild() {
		flushPendingIncremental();
		clearEstimateCacheIfPopulated();

		boolean rebuildIntoA = !usingA; // remember before toggling

		State tgt = rebuildIntoA ? bufA : bufB;
		byte previousCurrentSlot = slotByte(slotOf(current));
		byte targetSlot = slotByte(slotOf(tgt));
		clearResidentTrackingForSlot(slotOf(tgt));
		clearSlotPersistence(targetSlot);
		slotGenerations[targetSlot]++;
		tgt.clear(); // wipe everything (add + del)
		rebuildEpoch.incrementAndGet(); // mark rebuild in progress (odd epoch)
		long seen = 0L;
		long l = System.currentTimeMillis();
		long lastLoggedRebuildMillion = -1L;
		try {
			try (
					SailDataset ds = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
					CloseableIteration<? extends Statement> it = ds.getStatements(null, null, null)) {
				IngestEvent[] rebuildBatch = new IngestEvent[REBUILD_BATCH_SIZE];
				int rebuildBatchSize = 0;

				while (it.hasNext()) {
					if (Thread.currentThread().isInterrupted() || !running && Thread.currentThread() == refresher) {
						break;
					}
					Statement st = it.next();
					try {
						IngestEvent event = toIngestEvent(str(st.getSubject()), str(st.getPredicate()),
								str(st.getObject()),
								str(st.getContext()), false);
						if (event == null) {
							continue;
						}
						rebuildBatch[rebuildBatchSize] = event;
						rebuildBatchSize++;
						if (rebuildBatchSize == rebuildBatch.length) {
							ingestRebuildBatch(tgt, rebuildBatch, rebuildBatchSize);
							rebuildBatchSize = 0;
							if (logger.isDebugEnabled()) {
								long seenMillion = seen / 1_000_000;
								if (seenMillion != lastLoggedRebuildMillion) {
									lastLoggedRebuildMillion = seenMillion;
									logger.debug(
											"RdfJoinEstimator: Rebuilding {}, seen {} million triples so far. Elapsed: {} s.",
											rebuildIntoA ? "bufA" : "bufB",
											seenMillion,
											(System.currentTimeMillis() - l) / 1000);
								}
							}

						}
					} catch (MemoryPressureAbort | OutOfMemoryError pressureFailure) {

						return seen;
					} catch (Throwable e) {
						throw e;
					}

					seen++;

//					if (seen % throttleEveryN == 0 && throttleMillis > 0) {
//						try {
//							Thread.sleep(throttleMillis);
//						} catch (InterruptedException ie) {
//							Thread.currentThread().interrupt();
//							break;
//						}
//					}

				}
				if (seen > 0) {
					if (rebuildBatchSize > 0) {
						ingestRebuildBatch(tgt, rebuildBatch, rebuildBatchSize);
					}
				}
			}

			synchronized (tgt) {
				rebuildResidentTrackingForSlot(tgt);
			}
			current = tgt; // single volatile write → visible to all readers
			seenTriples = seen;
			approxStoreSize.set(seen);
			sketchesLoaded = true;
			rebuildRequired.set(false);
			dirty.set(true);
			indexDirty.set(true);
			usingA = !usingA;
			synchronized (sketchCacheLock) {
				cacheDirectory.clearDirtyForSlot(previousCurrentSlot);
			}

			// staleness: publish times & reset churn sampler
			lastRebuildPublishMs = System.currentTimeMillis();
			churnSampler.reset();

			return seen;
		} catch (MemoryPressureAbort | OutOfMemoryError pressureFailure) {

			return seen;
		} finally {
			if ((rebuildEpoch.get() & 1L) != 0L) {
				rebuildEpoch.incrementAndGet(); // mark rebuild complete (even epoch)
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Incremental updates */
	/* ────────────────────────────────────────────────────────────── */

	public void addStatement(Statement st) {
		Objects.requireNonNull(st);
		clearEstimateCacheIfPopulated();
		if (!rebuildRequired.get() && !sketchesLoaded && persistenceEnabled && persistenceFile != null
				&& hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.incrementAndGet();
			rebuildRequired.set(true);
			return;
		}

		String s = str(st.getSubject());
		String p = str(st.getPredicate());
		String o = str(st.getObject());
		String c = str(st.getContext());
		churnSampler.recordAdd(s, p, o, c, samplingInterval());
		seenTriples = approxStoreSize.incrementAndGet();

		try {
			ingestIncremental(s, p, o, c, false);

		} catch (MemoryPressureAbort | OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator update; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void addStatement(Resource s, IRI p, Value o, Resource c) {
		addStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void addStatement(Resource s, IRI p, Value o) {
		addStatement(s, p, o, null);
	}

	public void deleteStatement(Statement st) {
		Objects.requireNonNull(st);
		clearEstimateCacheIfPopulated();
		if (!rebuildRequired.get() && !sketchesLoaded && persistenceEnabled && persistenceFile != null
				&& hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));
			rebuildRequired.set(true);
			return;
		}

		String s = str(st.getSubject());
		String p = str(st.getPredicate());
		String o = str(st.getObject());
		String c = str(st.getContext());
		churnSampler.recordDelete(s, p, o, c, samplingInterval());
		seenTriples = approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));

		try {
			ingestIncremental(s, p, o, c, true);
		} catch (MemoryPressureAbort | OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator delete; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void deleteStatement(Resource s, IRI p, Value o, Resource c) {
		deleteStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void deleteStatement(Resource s, IRI p, Value o) {
		deleteStatement(s, p, o, null);
	}

	private IngestEvent ingestIncremental(String s, String p, String o, String c, boolean isDelete) {
		rethrowAsyncIncrementalFailure();
		IngestEvent event = toIngestEvent(s, p, o, c, isDelete);
		if (event == null) {
			return null;
		}
		IngestEvent[] batch = null;
		synchronized (incrementalBufferLock) {
			ensureIncrementalBufferCapacity(incrementalBufferCount + 1);
			incrementalBuffer[incrementalBufferCount++] = event;
			if (incrementalBufferCount >= INCREMENTAL_BATCH_SIZE) {
				if (logger.isDebugEnabled()) {
					logger.debug("RdfJoinEstimator: Flushing incremental batch of {} events. Seen triples: {}",
							incrementalBufferCount, seenTriples);
				}
				batch = drainIncrementalBufferLocked();
			}
		}
		if (batch != null) {
			enqueueIncrementalBatch(batch);
		}
		return event;
	}

	private IngestEvent toIngestEvent(String s, String p, String o, String c, boolean isDelete) {
		try {
			int si = hash(s);
			int pi = hash(p);
			int oi = hash(o);
			int ci = hash(c);

			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long thetaHs = thetaHash(hs);
			long thetaHp = thetaHash(hp);
			long thetaHo = thetaHash(ho);
			long thetaHc = thetaHash(hc);
			long thetaSig = thetaHash(sig);
			long spKey = pairKey(si, pi);
			long soKey = pairKey(si, oi);
			long scKey = pairKey(si, ci);
			long poKey = pairKey(pi, oi);
			long pcKey = pairKey(pi, ci);
			long ocKey = pairKey(oi, ci);
			return new IngestEvent(isDelete, si, pi, oi, ci, thetaHs, thetaHp, thetaHo, thetaHc, thetaSig, spKey, soKey,
					scKey, poKey, pcKey, ocKey);
		} catch (NullPointerException npe) {
			return null;
		}
	}

	private void ensureIncrementalBufferCapacity(int minCapacity) {
		if (minCapacity <= incrementalBuffer.length) {
			return;
		}
		int next = incrementalBuffer.length;
		while (next < minCapacity) {
			next <<= 1;
		}
		incrementalBuffer = Arrays.copyOf(incrementalBuffer, next);
	}

	private IngestEvent[] drainIncrementalBufferLocked() {
		if (incrementalBufferCount == 0) {
			return null;
		}
		IngestEvent[] drained = Arrays.copyOf(incrementalBuffer, incrementalBufferCount);
		Arrays.fill(incrementalBuffer, 0, incrementalBufferCount, null);
		incrementalBufferCount = 0;
		return drained;
	}

	private void flushPendingIncremental() {
		rethrowAsyncIncrementalFailure();
		waitForAsyncIncrementalBatches();
		while (true) {
			IngestEvent[] batch;
			synchronized (incrementalBufferLock) {
				batch = drainIncrementalBufferLocked();
				if (batch == null) {
					break;
				}
			}
			applyIncrementalBatch(batch, batch.length);
			waitForAsyncIncrementalBatches();
		}
		rethrowAsyncIncrementalFailure();
	}

	private void enqueueIncrementalBatch(IngestEvent[] batch) {
		if (batch.length == 0) {
			return;
		}
		incrementAsyncIncrementalBatchCount();
		boolean queued = false;
		try {
			while (!queued) {
				rethrowAsyncIncrementalFailure();
				queued = asyncIncrementalBatches.offer(batch, ASYNC_INCREMENTAL_QUEUE_OFFER_TIMEOUT_MILLIS,
						TimeUnit.MILLISECONDS);
			}
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			recordAsyncIncrementalFailure(e);
			throw new RuntimeException("Interrupted while queueing incremental join-estimator ingestion", e);
		} finally {
			if (!queued) {
				completeAsyncIncrementalBatch();
			}
		}
		rethrowAsyncIncrementalFailure();
	}

	private void runAsyncIncrementalIngest() {
		while (!Thread.currentThread().isInterrupted()) {
			IngestEvent[] batch;
			try {
				batch = asyncIncrementalBatches.take();
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				return;
			}
			try {
				applyIncrementalBatch(batch, batch.length);
			} catch (Throwable t) {
				recordAsyncIncrementalFailure(t);
				return;
			} finally {
				completeAsyncIncrementalBatch();
			}
		}
	}

	private void incrementAsyncIncrementalBatchCount() {
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalBatchCount++;
		}
	}

	private void completeAsyncIncrementalBatch() {
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalBatchCount--;
			asyncIncrementalDrainLock.notifyAll();
		}
	}

	private void waitForAsyncIncrementalBatches() {
		synchronized (asyncIncrementalDrainLock) {
			while (asyncIncrementalBatchCount > 0) {
				if (asyncIncrementalFailure.get() != null) {
					break;
				}
				try {
					asyncIncrementalDrainLock.wait();
				} catch (InterruptedException e) {
					Thread.currentThread().interrupt();
					recordAsyncIncrementalFailure(e);
					throw new RuntimeException("Interrupted while waiting for incremental join-estimator ingestion", e);
				}
			}
		}
		rethrowAsyncIncrementalFailure();
	}

	private void recordAsyncIncrementalFailure(Throwable failure) {
		asyncIncrementalFailure.compareAndSet(null, failure);
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalDrainLock.notifyAll();
		}
	}

	private void rethrowAsyncIncrementalFailure() {
		Throwable failure = asyncIncrementalFailure.get();
		if (failure == null) {
			return;
		}
		if (failure instanceof Error) {
			throw (Error) failure;
		}
		if (failure instanceof RuntimeException) {
			throw (RuntimeException) failure;
		}
		throw new RuntimeException("Asynchronous incremental join-estimator ingestion failed", failure);
	}

	private void applyIncrementalBatch(IngestEvent[] batch, int batchSize) {
		if (batchSize == 0) {
			return;
		}

		BatchUpdateAccumulator[] updates = buildBatchUpdates(batch, batchSize);
		while (true) {
			long epoch = rebuildEpoch.get();
			if ((epoch & 1L) != 0L) {
				synchronized (bufA) {
					applyBatchUpdates(bufA, updates);
				}
				synchronized (bufB) {
					applyBatchUpdates(bufB, updates);
				}
				return;
			}

			State target = current;
			synchronized (target) {
				if (rebuildEpoch.get() != epoch) {
					continue;
				}
				applyBatchUpdates(target, updates);
				return;
			}
		}
	}

	private void ingestBatch(State state, IngestEvent[] batch, int batchSize) {
		BatchUpdateAccumulator[] updates = buildBatchUpdates(batch, batchSize);
		synchronized (state) {
			applyBatchUpdates(state, updates);
		}
	}

	private void ingestRebuildBatch(State state, IngestEvent[] batch, int batchSize) {
		if (batchSize == 0) {
			return;
		}
		ingestBatch(state, batch, batchSize);
	}

	private void applyBatchUpdates(State state, BatchUpdateAccumulator[] batchUpdates) {
		byte slot = slotByte(slotOf(state));
		for (BatchUpdateAccumulator updates : batchUpdates) {
			updates.applyTo(this, state, slot);
		}
		enforceSketchBudget();
	}

	@SuppressWarnings("unchecked")
	private BatchUpdateAccumulator[] buildBatchUpdates(IngestEvent[] batch, int batchSize) {
		if (batchSize < PARALLEL_INGEST_MIN_BATCH_SIZE || batchSize > PARALLEL_INGEST_MAX_BATCH_SIZE) {
			return new BatchUpdateAccumulator[] { buildBatchUpdates(batch, batchSize, null) };
		}
		Future<BatchUpdateAccumulator>[] futures = new Future[INGEST_PARTITIONS.length];
		try {
			for (IngestPartition partition : INGEST_PARTITIONS) {
				futures[partition.ordinal()] = ingestPartitionExecutor.submit(() -> buildBatchUpdates(batch, batchSize,
						partition));
			}
			BatchUpdateAccumulator[] updates = new BatchUpdateAccumulator[futures.length];
			for (int i = 0; i < futures.length; i++) {
				updates[i] = futures[i].get();
			}
			return updates;
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new RuntimeException("Interrupted while preparing join-estimator batch", e);
		} catch (ExecutionException e) {
			throw new RuntimeException("Failed to prepare join-estimator batch", e.getCause());
		}
	}

	private BatchUpdateAccumulator buildBatchUpdates(IngestEvent[] batch, int batchSize, IngestPartition partition) {
		BatchUpdateAccumulator updates = new BatchUpdateAccumulator(Math.max(64, expectedBatchUpdates(batchSize,
				partition)));
		for (int i = 0; i < batchSize; i++) {
			IngestEvent event = batch[i];
			if (event == null) {
				continue;
			}
			accumulateIngestEvent(updates, event, partition);
		}
		return updates;
	}

	private int expectedBatchUpdates(int batchSize, IngestPartition partition) {
		if (partition == null) {
			return batchSize << 5;
		}
		if (partition == IngestPartition.SINGLES) {
			return expectedSingleBatchUpdates(batchSize);
		}
		return batchSize << 1;
	}

	private int expectedSingleBatchUpdates(int batchSize) {
		long batchEstimate = (long) batchSize << 3;
		long addressBound = ((long) nominalEntries << 5) + 8L;
		return (int) Math.min(Integer.MAX_VALUE, Math.min(batchEstimate, Math.max(64L, addressBound)));
	}

	private void applyGroupedUpdate(State state, byte slot, int keyPrefix, int keyHash, int x, int y, long firstValue,
			long[] overflowValues, int valueCount) {
		if (valueCount == 0) {
			return;
		}
		byte recType = (byte) keyPrefix;
		boolean isDelete = ((keyPrefix >>> 8) & 1) != 0;
		byte axisA = (byte) (keyPrefix >>> 16);
		byte axisB = (byte) (keyPrefix >>> 24);
		int storedKeyPrefix = keyPrefix & ~DELETE_KEY_PREFIX_MASK;
		int storedKeyHash = mixAddressHash(storedKeyPrefix, x, y);
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(storedKeyPrefix, storedKeyHash, x, y);
		}
		ArrayOfDoublesUpdatableSketch sketch = getSketchForWrite(state, recType, false, axisA, axisB, x, y, entryId);
		tupleUpdateRaw(sketch, firstValue, signedDelta(isDelete));
		for (int i = 1; i < valueCount; i++) {
			tupleUpdateRaw(sketch, overflowValues[i - 1], signedDelta(isDelete));
		}
		markDirtyAndTouchResidentSketch(slot, entryId, sketch,
				initialSingletonSketchBytesHint(state, sketch, valueCount));
	}

	private void accumulateIngestEvent(BatchUpdateAccumulator updates, IngestEvent event, IngestPartition partition) {
		if (partition == null) {
			accumulateSingleUpdates(updates, event);
			accumulatePair(updates, Pair.SP, event.isDelete, event.spKey, event.thetaSig, event.thetaHo,
					event.thetaHc);
			accumulatePair(updates, Pair.SO, event.isDelete, event.soKey, event.thetaSig, event.thetaHp,
					event.thetaHc);
			accumulatePair(updates, Pair.SC, event.isDelete, event.scKey, event.thetaSig, event.thetaHp,
					event.thetaHo);
			accumulatePair(updates, Pair.PO, event.isDelete, event.poKey, event.thetaSig, event.thetaHs,
					event.thetaHc);
			accumulatePair(updates, Pair.PC, event.isDelete, event.pcKey, event.thetaSig, event.thetaHs,
					event.thetaHo);
			accumulatePair(updates, Pair.OC, event.isDelete, event.ocKey, event.thetaSig, event.thetaHs,
					event.thetaHp);
			return;
		}
		switch (partition) {
		case SINGLES:
			accumulateSingleUpdates(updates, event);
			break;
		case SP:
			accumulatePair(updates, Pair.SP, event.isDelete, event.spKey, event.thetaSig, event.thetaHo,
					event.thetaHc);
			break;
		case SO:
			accumulatePair(updates, Pair.SO, event.isDelete, event.soKey, event.thetaSig, event.thetaHp,
					event.thetaHc);
			break;
		case SC:
			accumulatePair(updates, Pair.SC, event.isDelete, event.scKey, event.thetaSig, event.thetaHp,
					event.thetaHo);
			break;
		case PO:
			accumulatePair(updates, Pair.PO, event.isDelete, event.poKey, event.thetaSig, event.thetaHs,
					event.thetaHc);
			break;
		case PC:
			accumulatePair(updates, Pair.PC, event.isDelete, event.pcKey, event.thetaSig, event.thetaHs,
					event.thetaHo);
			break;
		case OC:
			accumulatePair(updates, Pair.OC, event.isDelete, event.ocKey, event.thetaSig, event.thetaHs,
					event.thetaHp);
			break;
		}
	}

	private void accumulateSingleUpdates(BatchUpdateAccumulator updates, IngestEvent event) {
		int deleteMask = event.isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		int si = event.si;
		int pi = event.pi;
		int oi = event.oi;
		int ci = event.ci;
		long thetaHs = event.thetaHs;
		long thetaHp = event.thetaHp;
		long thetaHo = event.thetaHo;
		long thetaHc = event.thetaHc;
		long thetaSig = event.thetaSig;

		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_S_INDEX] | deleteMask, si, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_P_INDEX] | deleteMask, pi, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_O_INDEX] | deleteMask, oi, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_C_INDEX] | deleteMask, ci, 0, thetaSig);

		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_S_INDEX] | deleteMask, 0, 0, thetaHs);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_P_INDEX] | deleteMask, 0, 0, thetaHp);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_O_INDEX] | deleteMask, 0, 0, thetaHo);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_C_INDEX] | deleteMask, 0, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_P_INDEX] | deleteMask, si, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_O_INDEX] | deleteMask, si, 0, thetaHo);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_C_INDEX] | deleteMask, si, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_S_INDEX] | deleteMask, pi, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_O_INDEX] | deleteMask, pi, 0, thetaHo);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_C_INDEX] | deleteMask, pi, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_S_INDEX] | deleteMask, oi, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_P_INDEX] | deleteMask, oi, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_C_INDEX] | deleteMask, oi, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_S_INDEX] | deleteMask, ci, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_P_INDEX] | deleteMask, ci, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_O_INDEX] | deleteMask, ci, 0, thetaHo);
	}

	private static void accumulatePair(BatchUpdateAccumulator updates, Pair pair, boolean isDelete, long key,
			long triple,
			long comp1, long comp2) {
		int x = (int) (key >>> 32);
		int y = (int) key;
		int pairIndex = pair.ordinal();
		int deleteMask = isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		updates.add(PAIR_TRIPLE_KEY_PREFIXES[pairIndex] | deleteMask, x, y, triple);
		updates.add(PAIR_COMP1_KEY_PREFIXES[pairIndex] | deleteMask, x, y, comp1);
		updates.add(PAIR_COMP2_KEY_PREFIXES[pairIndex] | deleteMask, x, y, comp2);
	}

	/* ------------------------------------------------------------------ */

	private void ingest(State t, IngestEvent event) {
		try {
			boolean isDelete = event.isDelete;
			int si = event.si;
			int pi = event.pi;
			int oi = event.oi;
			int ci = event.ci;
			long thetaHs = event.thetaHs;
			long thetaHp = event.thetaHp;
			long thetaHo = event.thetaHo;
			long thetaHc = event.thetaHc;
			long thetaSig = event.thetaSig;
			long spKey = event.spKey;
			long soKey = event.soKey;
			long scKey = event.scKey;
			long poKey = event.poKey;
			long pcKey = event.pcKey;
			long ocKey = event.ocKey;

			/* single‑component cardinalities */
			updateSingleSketchRaw(t, isDelete, Component.S, si, thetaSig);
			updateSingleSketchRaw(t, isDelete, Component.P, pi, thetaSig);
			updateSingleSketchRaw(t, isDelete, Component.O, oi, thetaSig);
			updateSingleSketchRaw(t, isDelete, Component.C, ci, thetaSig);

			updateGlobalComponentSketchRaw(t, isDelete, Component.S, thetaHs);
			updateGlobalComponentSketchRaw(t, isDelete, Component.P, thetaHp);
			updateGlobalComponentSketchRaw(t, isDelete, Component.O, thetaHo);
			updateGlobalComponentSketchRaw(t, isDelete, Component.C, thetaHc);

			/* complement sets for singles */
			updateComplementSketchRaw(t, isDelete, Component.S, Component.P, si, thetaHp);
			updateComplementSketchRaw(t, isDelete, Component.S, Component.O, si, thetaHo);
			updateComplementSketchRaw(t, isDelete, Component.S, Component.C, si, thetaHc);

			updateComplementSketchRaw(t, isDelete, Component.P, Component.S, pi, thetaHs);
			updateComplementSketchRaw(t, isDelete, Component.P, Component.O, pi, thetaHo);
			updateComplementSketchRaw(t, isDelete, Component.P, Component.C, pi, thetaHc);

			updateComplementSketchRaw(t, isDelete, Component.O, Component.S, oi, thetaHs);
			updateComplementSketchRaw(t, isDelete, Component.O, Component.P, oi, thetaHp);
			updateComplementSketchRaw(t, isDelete, Component.O, Component.C, oi, thetaHc);

			updateComplementSketchRaw(t, isDelete, Component.C, Component.S, ci, thetaHs);
			updateComplementSketchRaw(t, isDelete, Component.C, Component.P, ci, thetaHp);
			updateComplementSketchRaw(t, isDelete, Component.C, Component.O, ci, thetaHo);

			/* pairs (triples + complements) */
			updatePairSketchRaw(t, isDelete, Pair.SP, REC_PAIR_TRIPLE, spKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.SP, REC_PAIR_COMP1, spKey, thetaHo);
			updatePairSketchRaw(t, isDelete, Pair.SP, REC_PAIR_COMP2, spKey, thetaHc);

			updatePairSketchRaw(t, isDelete, Pair.SO, REC_PAIR_TRIPLE, soKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.SO, REC_PAIR_COMP1, soKey, thetaHp);
			updatePairSketchRaw(t, isDelete, Pair.SO, REC_PAIR_COMP2, soKey, thetaHc);

			updatePairSketchRaw(t, isDelete, Pair.SC, REC_PAIR_TRIPLE, scKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.SC, REC_PAIR_COMP1, scKey, thetaHp);
			updatePairSketchRaw(t, isDelete, Pair.SC, REC_PAIR_COMP2, scKey, thetaHo);

			updatePairSketchRaw(t, isDelete, Pair.PO, REC_PAIR_TRIPLE, poKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.PO, REC_PAIR_COMP1, poKey, thetaHs);
			updatePairSketchRaw(t, isDelete, Pair.PO, REC_PAIR_COMP2, poKey, thetaHc);

			updatePairSketchRaw(t, isDelete, Pair.PC, REC_PAIR_TRIPLE, pcKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.PC, REC_PAIR_COMP1, pcKey, thetaHs);
			updatePairSketchRaw(t, isDelete, Pair.PC, REC_PAIR_COMP2, pcKey, thetaHo);

			updatePairSketchRaw(t, isDelete, Pair.OC, REC_PAIR_TRIPLE, ocKey, thetaSig);
			updatePairSketchRaw(t, isDelete, Pair.OC, REC_PAIR_COMP1, ocKey, thetaHs);
			updatePairSketchRaw(t, isDelete, Pair.OC, REC_PAIR_COMP2, ocKey, thetaHp);
		} catch (NullPointerException npe) {
			// ignore NPEs from null values (e.g. missing context)
		} finally {
			enforceSketchBudget();
		}
	}

