	/* ────────────────────────────────────────────────────────────── */
	/* ✦ Fluent BGP builder ✦ */
	/* ────────────────────────────────────────────────────────────── */

	public JoinEstimate estimate(Component joinVar, String s, String p, String o, String c) {
		flushPendingIncremental();
		State snap = current;
		if (estimateCacheTtlNanos <= 0L) {
			synchronized (snap) {
				PatternStats st = statsOf(snap, joinVar, s, p, o, c);
				ArrayOfDoublesSketch bindings = st.sketch == null ? EMPTY : st.sketch;
				return new JoinEstimate(snap, joinVar, bindings, TupleSketchOps.estimatePositiveDistinct(bindings),
						st.card);
			}
		}
		PatternStats st = patternStats(snap, joinVar, s, p, o, c);
		ArrayOfDoublesSketch bindings = st.sketch == null ? EMPTY : st.sketch;
		return new JoinEstimate(snap, joinVar, bindings, TupleSketchOps.estimatePositiveDistinct(bindings), st.card);
	}

	public double estimateCount(Component joinVar, String s, String p, String o, String c) {
		return estimate(joinVar, s, p, o, c).estimate();
	}

	public final class JoinEstimate {
		private final State snap;
		private Component joinVar;
		private ArrayOfDoublesSketch bindings;
		private double distinct;
		private double resultSize;

		private JoinEstimate(State snap, Component joinVar, ArrayOfDoublesSketch bindings,
				double distinct, double size) {
			this.snap = snap;
			this.joinVar = joinVar;
			this.bindings = bindings;
			this.distinct = distinct;
			this.resultSize = size;
		}

		public JoinEstimate join(Component newJoinVar, String s, String p, String o, String c) {
			if (estimateCacheTtlNanos <= 0L) {
				synchronized (snap) {
					return joinWithPatternStats(newJoinVar, statsOf(snap, newJoinVar, s, p, o, c));
				}
			}
			return joinWithPatternStats(newJoinVar, patternStats(snap, newJoinVar, s, p, o, c));
		}

		private JoinEstimate joinWithPatternStats(Component newJoinVar, PatternStats rhs) {
			TupleSketchOps.IntersectionStats intersectionStats = TupleSketchOps.intersectProductStats(this.bindings,
					rhs.sketch, snap.k);
			ArrayOfDoublesSketch inter = intersectionStats.sketch();
			double interDistinct = intersectionStats.positiveDistinct();

			if (interDistinct == 0.0) { // early out
				this.bindings = inter;
				this.distinct = 0.0;
				this.resultSize = 0.0;
				this.joinVar = newJoinVar;
				return this;
			}

			/* round to nearest whole solution count if enabled */
			this.resultSize = roundJoinEstimate(intersectionStats.positiveSum());

			/* carry forward */
			this.bindings = inter;
			this.distinct = interDistinct;
			this.joinVar = newJoinVar;
			return this;
		}

		/** Estimated number of solutions produced so far. */
		public double estimate() {
			return resultSize;
		}

		public double size() {
			return resultSize;
		}

		public double count() {
			return resultSize;
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pattern statistics */
	/* ────────────────────────────────────────────────────────────── */

	private static final class PatternStats {
		final ArrayOfDoublesSketch sketch;
		final double distinct;
		final double card; // relation size |R|

		PatternStats(ArrayOfDoublesSketch s, double card) {
			this.sketch = s;
			this.distinct = TupleSketchOps.estimatePositiveDistinct(s);
			this.card = card;
		}
	}

	private static final class EstimateCacheKey {
		private final Component joinVar;
		private final String s;
		private final String p;
		private final String o;
		private final String c;

		private EstimateCacheKey(Component joinVar, String s, String p, String o, String c) {
			this.joinVar = Objects.requireNonNull(joinVar, "joinVar");
			this.s = s;
			this.p = p;
			this.o = o;
			this.c = c;
		}

		@Override
		public boolean equals(Object other) {
			if (this == other) {
				return true;
			}
			if (!(other instanceof EstimateCacheKey)) {
				return false;
			}
			EstimateCacheKey that = (EstimateCacheKey) other;
			return joinVar == that.joinVar
					&& Objects.equals(s, that.s)
					&& Objects.equals(p, that.p)
					&& Objects.equals(o, that.o)
					&& Objects.equals(c, that.c);
		}

		@Override
		public int hashCode() {
			return Objects.hash(joinVar, s, p, o, c);
		}
	}

	private static final class EstimateCacheEntry {
		private final PatternStats patternStats;
		private final long expiresAtNanos;

		private EstimateCacheEntry(PatternStats patternStats, long expiresAtNanos) {
			this.patternStats = Objects.requireNonNull(patternStats, "patternStats");
			this.expiresAtNanos = expiresAtNanos;
		}

		private boolean isAlive(long nowNanos) {
			return nowNanos - expiresAtNanos < 0L;
		}
	}

	private static final class BindingSketchResult {
		final ArrayOfDoublesSketch sketch;
		final EnumSet<Pair> usedPairs;

		private BindingSketchResult(ArrayOfDoublesSketch sketch, EnumSet<Pair> usedPairs) {
			this.sketch = sketch;
			this.usedPairs = usedPairs;
		}

		static BindingSketchResult of(ArrayOfDoublesSketch sketch) {
			return new BindingSketchResult(sketch, EnumSet.noneOf(Pair.class));
		}

		static BindingSketchResult of(ArrayOfDoublesSketch sketch, Pair pair) {
			return new BindingSketchResult(sketch, EnumSet.of(pair));
		}

		static BindingSketchResult of(ArrayOfDoublesSketch sketch, Pair first, Pair second) {
			return new BindingSketchResult(sketch, EnumSet.of(first, second));
		}
	}

	private static final class PairSketchCandidate {
		final Pair pair;
		final ArrayOfDoublesSketch sketch;

		PairSketchCandidate(Pair pair, ArrayOfDoublesSketch sketch) {
			this.pair = pair;
			this.sketch = sketch;
		}
	}

	private static EnumMap<Component, String> fixedComponents(String s, String p, String o, String c) {
		EnumMap<Component, String> fixed = new EnumMap<>(Component.class);
		if (s != null) {
			fixed.put(Component.S, s);
		}
		if (p != null) {
			fixed.put(Component.P, p);
		}
		if (o != null) {
			fixed.put(Component.O, o);
		}
		if (c != null) {
			fixed.put(Component.C, c);
		}
		return fixed;
	}

	/** Build both |R| and a tuple sketch for one triple pattern. */
	private PatternStats statsOf(State st, Component j,
			String s, String p, String o, String c) {

		EnumMap<Component, String> fixed = fixedComponents(s, p, o, c);
		BindingSketchResult bindingSketch = bindingsSketch(st, j, fixed);
		ArrayOfDoublesSketch sk = bindingSketch.sketch;

		double pairDrivenCardinality = usedPairCardinality(st, fixed, bindingSketch.usedPairs);
		if (Double.isFinite(pairDrivenCardinality)) {
			return new PatternStats(sk, enforceCardinalityLowerBound(sk, pairDrivenCardinality));
		}

		double card;

		switch (fixed.size()) {
		case 0:
			card = approxTotalRows();
			break;

		case 1: {
			Map.Entry<Component, String> e = fixed.entrySet().iterator().next();
			card = cardSingle(st, e.getKey(), e.getValue());
			break;
		}

		case 2: {
			Component[] cmp = fixed.keySet().toArray(new Component[0]);
			Pair pr = findPair(cmp[0], cmp[1]);
			if (pr != null) {
				card = cardPair(st, pr, fixed.get(pr.x), fixed.get(pr.y));
			} else { // components not a known pair – conservative min
				double a = cardSingle(st, cmp[0], fixed.get(cmp[0]));
				double b = cardSingle(st, cmp[1], fixed.get(cmp[1]));
				card = Math.min(a, b);
			}
			break;
		}

		default: { // 3 or 4 bound – use smallest single cardinality
			card = Double.POSITIVE_INFINITY;
			for (Map.Entry<Component, String> e : fixed.entrySet()) {
				card = Math.min(card, cardSingle(st, e.getKey(), e.getValue()));
			}
			break;
		}
		}
		return new PatternStats(sk, enforceCardinalityLowerBound(sk, card));
	}

	private PatternStats patternStats(State snap, Component joinVar, String s, String p, String o, String c) {
		if (estimateCacheTtlNanos <= 0L) {
			synchronized (snap) {
				return statsOf(snap, joinVar, s, p, o, c);
			}
		}

		long nowNanos = System.nanoTime();
		EstimateCacheKey key = new EstimateCacheKey(joinVar, s, p, o, c);
		EstimateCacheEntry cached = estimateCache.get(key);
		if (cached != null && cached.isAlive(nowNanos)) {
			return cached.patternStats;
		}

		PatternStats frozenStats;
		synchronized (snap) {
			frozenStats = freezePatternStats(statsOf(snap, joinVar, s, p, o, c));
		}
		estimateCache.put(key, new EstimateCacheEntry(frozenStats, saturatingAdd(nowNanos, estimateCacheTtlNanos)));
		trimEstimateCache(nowNanos);
		return frozenStats;
	}

	private PatternStats freezePatternStats(PatternStats patternStats) {
		if (patternStats.sketch == null) {
			return patternStats;
		}
		return new PatternStats(patternStats.sketch.compact(), patternStats.card);
	}

	private void trimEstimateCache(long nowNanos) {
		if (estimateCache.size() <= MAX_ESTIMATE_CACHE_ENTRIES) {
			return;
		}
		for (Map.Entry<EstimateCacheKey, EstimateCacheEntry> entry : estimateCache.entrySet()) {
			if (!entry.getValue().isAlive(nowNanos)) {
				estimateCache.remove(entry.getKey(), entry.getValue());
			}
		}
		if (estimateCache.size() > MAX_ESTIMATE_CACHE_ENTRIES) {
			estimateCache.clear();
		}
	}

	private void clearEstimateCache() {
		estimateCache.clear();
	}

	private void clearEstimateCacheIfPopulated() {
		if (!estimateCache.isEmpty()) {
			clearEstimateCache();
		}
	}

	private double approxTotalRows() {
		return Math.max(0.0d, (double) Math.max(seenTriples, approxStoreSize.get()));
	}

	private double usedPairCardinality(State st, EnumMap<Component, String> fixed, EnumSet<Pair> usedPairs) {
		if (usedPairs.isEmpty()) {
			return Double.NaN;
		}
		double card = Double.POSITIVE_INFINITY;
		for (Pair pair : usedPairs) {
			String xValue = fixed.get(pair.x);
			String yValue = fixed.get(pair.y);
			if (xValue == null || yValue == null) {
				continue;
			}
			card = Math.min(card, cardPair(st, pair, xValue, yValue));
		}
		return Double.isFinite(card) ? card : Double.NaN;
	}

	private static double enforceCardinalityLowerBound(ArrayOfDoublesSketch sketch, double cardinality) {
		if (sketch == null || !Double.isFinite(cardinality)) {
			return cardinality;
		}
//		if(cardinality < sketch.getEstimate()){
//			System.out.println("Cardinality " + cardinality + " is lower than sketch estimate " + sketch.getEstimate());
//		}else if(cardinality > sketch.getEstimate()) {
//			System.out.println("Cardinality " + cardinality + " is higher than sketch estimate " + sketch.getEstimate());
//		}

		// Cardinality cannot be lower than the estimated number of distinct join bindings.
//		return Math.max(cardinality, sketch.getEstimate());
		return cardinality;
	}

