	/* ────────────────────────────────────────────────────────────── */
	/* Snapshot‑level cardinalities */
	/* ────────────────────────────────────────────────────────────── */

	private double cardSingle(State st, Component c, String val) {
		int idx = hash(val);
		return estimateSignedRows(getSketchForRead(st, singleTripleAddress(false, c, idx)));
	}

	private double cardPair(State st, Pair p, String x, String y) {
		long key = pairKey(hash(x), hash(y));
		int row = (int) (key >>> 32);
		int col = (int) key;
		return estimateSignedRows(getSketchForRead(st, pairAddress(REC_PAIR_TRIPLE, false, p, row, col)));
	}

	/* ────────────────────────────────────────────────────────────── */
	/* ArrayOfDoublesSketch helpers */
	/* ────────────────────────────────────────────────────────────── */

	private BindingSketchResult bindingsSketch(State st, Component j, EnumMap<Component, String> f) {

		if (f.isEmpty()) {
			return BindingSketchResult.of(null); // no constant – unsupported
		}

		/* 1 constant → single complement */
		if (f.size() == 1) {
			Map.Entry<Component, String> e = f.entrySet().iterator().next();
			return BindingSketchResult.of(singleWrapper(st, e.getKey()).getComplementSketch(j, hash(e.getValue())));
		}

		/* 2 constants: pair fast path */
		Component[] cs = f.keySet().toArray(new Component[0]);
		if (f.size() == 2) {
			Pair pr = findPair(cs[0], cs[1]);
			if (pr != null && (j == pr.comp1 || j == pr.comp2)) {
				int idxX = hash(f.get(pr.x));
				int idxY = hash(f.get(pr.y));
				ArrayOfDoublesSketch pairSketch = pairWrapper(st, pr).getComplementSketch(j, pairKey(idxX, idxY));
				return BindingSketchResult.of(pairSketch, pr);
			}
		} else if (f.size() == 3) {
			List<PairSketchCandidate> pairCandidates = new ArrayList<>(3);
			var best = Double.POSITIVE_INFINITY;
			BindingSketchResult candidateForBest = null;
			for (int i = 0; i < cs.length; i++) {
				for (int k = i + 1; k < cs.length; k++) {
					Pair pr = findPair(cs[i], cs[k]);
					if (pr == null || (j != pr.comp1 && j != pr.comp2)) {
						continue;
					}
					int idxX = hash(f.get(pr.x));
					int idxY = hash(f.get(pr.y));
					ArrayOfDoublesSketch candidate = pairWrapper(st, pr).getComplementSketch(j, pairKey(idxX, idxY));
					if (candidate == null) {
						continue;
					}
					double candidateDistinct = TupleSketchOps.estimatePositiveDistinct(candidate);
					if (candidateDistinct < best) {
						best = candidateDistinct;
						candidateForBest = BindingSketchResult.of(candidate, pr);
					}
					pairCandidates.add(new PairSketchCandidate(pr, candidate));
				}
			}

			if (candidateForBest != null) {
				return candidateForBest;
			}

//			ArrayOfDoublesSketch best = null;
//			Pair bestFirst = null;
//			Pair bestSecond = null;
//			double bestEstimate = Double.POSITIVE_INFINITY;
//			for (int i = 0; i < pairCandidates.size(); i++) {
//				for (int k = i + 1; k < pairCandidates.size(); k++) {
//					Intersection ix = SetOperation.builder().buildIntersection();
//					ix.intersect(pairCandidates.get(i).sketch);
//					ix.intersect(pairCandidates.get(k).sketch);
//					ArrayOfDoublesSketch intersection = ix.getResult();
//					double estimate = intersection.getEstimate();
//					if (best == null || estimate < bestEstimate) {
//						best = intersection;
//						bestFirst = pairCandidates.get(i).pair;
//						bestSecond = pairCandidates.get(k).pair;
//						bestEstimate = estimate;
//					}
//				}
//			}

//			if (best != null) {
//				return BindingSketchResult.of(best, bestFirst, bestSecond);
//			}
			if (!pairCandidates.isEmpty()) {
				PairSketchCandidate first = pairCandidates.get(0);
				return BindingSketchResult.of(first.sketch, first.pair);
			}
		}

		/* generic fall‑back */
		ArrayOfDoublesSketch acc = null;
		for (Map.Entry<Component, String> e : f.entrySet()) {
			ArrayOfDoublesSketch sk = singleWrapper(st, e.getKey())
					.getComplementSketch(j, hash(e.getValue()));
			if (sk == null) {
				continue;
			}
			if (acc == null) {
				acc = sk;
			} else {
				acc = TupleSketchOps.intersectMin(acc, sk, st.k);
			}
		}
		return BindingSketchResult.of(acc);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pair & single wrappers (read‑only) */
	/* ────────────────────────────────────────────────────────────── */

	private StateSingleWrapper singleWrapper(State st, Component fixed) {
		return new StateSingleWrapper(st, fixed);
	}

	private StatePairWrapper pairWrapper(State st, Pair p) {
		return new StatePairWrapper(st, p);
	}

	private final class StateSingleWrapper {
		final State state;
		final Component fixed;

		StateSingleWrapper(State state, Component f) {
			this.state = state;
			this.fixed = f;
		}

		ArrayOfDoublesSketch getComplementSketch(Component c, int fi) {
			if (c == fixed) {
				return null;
			}
			return getSketchForRead(state, singleComplementAddress(false, fixed, c, fi));
		}
	}

	private final class StatePairWrapper {
		final State state;
		final Pair p;

		StatePairWrapper(State state, Pair p) {
			this.state = state;
			this.p = p;
		}

		ArrayOfDoublesSketch getComplementSketch(Component c, long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			if (c == p.comp1) {
				return getSketchForRead(state, pairAddress(REC_PAIR_COMP1, false, p, x, y));
			} else if (c == p.comp2) {
				return getSketchForRead(state, pairAddress(REC_PAIR_COMP2, false, p, x, y));
			} else {
				return null;
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Join primitives */
	/* ────────────────────────────────────────────────────────────── */

	private double joinPairs(State st, Component j,
			Pair a, String ax, String ay,
			Pair b, String bx, String by) {

		long keyA = pairKey(hash(ax), hash(ay));
		long keyB = pairKey(hash(bx), hash(by));

		ArrayOfDoublesSketch sa = pairWrapper(st, a).getComplementSketch(j, keyA);
		ArrayOfDoublesSketch sb = pairWrapper(st, b).getComplementSketch(j, keyB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		return roundJoinEstimate(TupleSketchOps.estimateIntersectionProductSum(sa, sb, st.k));
	}

	private double joinSingles(State st, Component j,
			Component a, String av,
			Component b, String bv) {

		int idxA = hash(av), idxB = hash(bv);

		ArrayOfDoublesSketch sa = singleWrapper(st, a).getComplementSketch(j, idxA);
		ArrayOfDoublesSketch sb = singleWrapper(st, b).getComplementSketch(j, idxB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		return roundJoinEstimate(TupleSketchOps.estimateIntersectionProductSum(sa, sb, st.k));
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Unified mutable state (add + delete) */
	/* ────────────────────────────────────────────────────────────── */

	private static final class StateComponents<T> {
		public final T S;
		public final T P;
		public final T O;
		public final T C;

		StateComponents(T s, T p, T o, T c) {
			S = s;
			P = p;
			O = o;
			C = c;
		}

		T get(Component component) {
			switch (component) {
			case S:
				return S;
			case P:
				return P;
			case O:
				return O;
			case C:
				return C;
			default:
				throw new IllegalStateException("Unsupported component: " + component);
			}
		}

		void forEach(Consumer<? super T> consumer) {
			consumer.accept(S);
			consumer.accept(P);
			consumer.accept(O);
			consumer.accept(C);
		}
	}

	private static final class State {
		final int k; // sketch nominal entries
		final int buckets; // array bucket count (outer.nominalEntries)

		/* live (add) sketches */
		final StateComponents<AtomicReferenceArray<ArrayOfDoublesUpdatableSketch>> globalComponents;
		final StateComponents<AtomicReferenceArray<ArrayOfDoublesUpdatableSketch>> singleTriples;
		final StateComponents<SingleBuild> singles;
		final EnumMap<Pair, PairBuild> pairs = new EnumMap<>(Pair.class);
		final long initialSketchBytes;
		final int maxSketchBytes;

		/* tomb‑stone (delete) sketches */
		final StateComponents<AtomicReferenceArray<ArrayOfDoublesUpdatableSketch>> delSingleTriples;
		final StateComponents<SingleBuild> delSingles;
		final EnumMap<Pair, PairBuild> delPairs = new EnumMap<>(Pair.class);

		State(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;
			ArrayOfDoublesUpdatableSketch emptySketch = newSk(k);
			this.initialSketchBytes = estimatedSketchBytes(emptySketch);
			this.maxSketchBytes = emptySketch.getMaxBytes();

			globalComponents = new StateComponents<>(
					new AtomicReferenceArray<>(1),
					new AtomicReferenceArray<>(1),
					new AtomicReferenceArray<>(1),
					new AtomicReferenceArray<>(1));

			singleTriples = new StateComponents<>(
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets));

			delSingleTriples = new StateComponents<>(
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets),
					new AtomicReferenceArray<>(buckets));

			singles = new StateComponents<>(
					new SingleBuild(k, Component.S, buckets),
					new SingleBuild(k, Component.P, buckets),
					new SingleBuild(k, Component.O, buckets),
					new SingleBuild(k, Component.C, buckets));

			delSingles = new StateComponents<>(
					new SingleBuild(k, Component.S, buckets),
					new SingleBuild(k, Component.P, buckets),
					new SingleBuild(k, Component.O, buckets),
					new SingleBuild(k, Component.C, buckets));

			for (Pair p : PAIR_VALUES) {
				pairs.put(p, new PairBuild(k, buckets));
				delPairs.put(p, new PairBuild(k, buckets));
			}
		}

		void clear() {
			globalComponents.forEach(SketchBasedJoinEstimator::clearArray);
			singleTriples.forEach(SketchBasedJoinEstimator::clearArray);
			delSingleTriples.forEach(SketchBasedJoinEstimator::clearArray);

			singles.forEach(SingleBuild::clear);
			delSingles.forEach(SingleBuild::clear);

			pairs.values().forEach(PairBuild::clear);
			delPairs.values().forEach(PairBuild::clear);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Build‑time structures */
	/* ────────────────────────────────────────────────────────────── */

	private static final class SingleBuild {
		final int k;
		final int buckets;
		final EnumMap<Component, AtomicReferenceArray<ArrayOfDoublesUpdatableSketch>> cmpl = new EnumMap<>(
				Component.class);

		SingleBuild(int k, Component fixed, int buckets) {
			this.k = k;
			this.buckets = buckets;
			for (Component c : COMPONENT_VALUES) {
				if (c != fixed) {
					cmpl.put(c, new AtomicReferenceArray<>(buckets));
				}
			}
		}

		void clear() {
			for (AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr : cmpl.values()) {
				SketchBasedJoinEstimator.clearArray(arr);
			}
		}

		void upd(Component c, int idx, long v) {
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = cmpl.get(c);
			if (arr == null) {
				return;
			}
			ArrayOfDoublesUpdatableSketch sk = arr.get(idx);
			if (sk == null) {
				sk = newSk(k);
				arr.set(idx, sk);
			}
			tupleUpdateRaw(sk, v, 1.0d);
		}
	}

	private static final class PairBuild {
		final int k;
		final int buckets;

		/** Sparse rows indexed by X; each row stores only touched Y-cells. */
		final Map<Integer, Row> rows;

		PairBuild(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;
			this.rows = new HashMap<>();
		}

		void clear() {
			rows.clear();
		}

		void upT(long key, long sig) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.triples, y, sig, k);
		}

		void up1(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.comp1, y, v, k);
		}

		void up2(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			updateSketchMap(r.comp2, y, v, k);
		}

		ArrayOfDoublesUpdatableSketch getTriple(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.triples.get(y);
		}

		ArrayOfDoublesUpdatableSketch getComp1(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp1.get(y);
		}

		ArrayOfDoublesUpdatableSketch getComp2(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp2.get(y);
		}

		private Row getOrCreateRow(int x) {
			Row r = rows.get(x);
			if (r == null) {
				r = new Row();
				rows.put(x, r);
			}
			return r;
		}

		static final class Row {
			final Map<Integer, ArrayOfDoublesUpdatableSketch> triples = new HashMap<>();
			final Map<Integer, ArrayOfDoublesUpdatableSketch> comp1 = new HashMap<>();
			final Map<Integer, ArrayOfDoublesUpdatableSketch> comp2 = new HashMap<>();
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Utility */
	/* ────────────────────────────────────────────────────────────── */

	private static double estimateSignedRows(ArrayOfDoublesSketch sketch) {
		return TupleSketchOps.estimatePositiveSum(sketch);
	}

	private static double signedDelta(boolean isDelete) {
		return isDelete ? -1.0d : 1.0d;
	}

	private static ArrayOfDoublesUpdatableSketch newSk(int k) {
		return TupleSketchOps.newSketch(k);
	}

	private static ArrayOfDoublesUpdatableSketch newSk(int k, MemorySegment payload) {
		return TupleSketchOps.newSketch(k, payload);
	}

	private static void tupleUpdateRaw(ArrayOfDoublesUpdatableSketch sketch, long hash, double delta) {
		TupleSketchOps.update(sketch, hash, delta);
	}

	private static long align(long bytes) {
		return (bytes + 7L) & ~7L;
	}

	private int hash(String v) {
		// Ensure non-negative index in [0, nominalEntries)
		int h = Objects.hashCode(v);
		return (h & 0x7fffffff) % nominalEntries;
	}

	private static long valueFingerprint(String value) {
		long h = FNV64_OFFSET_BASIS;
		if (value != null) {
			for (int i = 0; i < value.length(); i++) {
				h ^= value.charAt(i);
				h *= FNV64_PRIME;
			}
			h ^= value.length();
		}
		return mix64(h);
	}

	private static long quadFingerprint(long s, long p, long o, long c) {
		long h = QUAD_SEED;
		h = mix64(h ^ s);
		h = mix64(h ^ p);
		h = mix64(h ^ o);
		return mix64(h ^ c);
	}

	private static long thetaHash(long value) {
		return MurmurHash3.hash(value, TUPLE_UPDATE_SEED)[0] >>> 1;
	}

	private static long mix64(long value) {
		long z = value;
		z = (z ^ (z >>> 30)) * MIX64_C1;
		z = (z ^ (z >>> 27)) * MIX64_C2;
		return z ^ (z >>> 31);
	}

	private static long pairKey(int a, int b) {
		return (((long) a) << 32) ^ (b & 0xffffffffL);
	}

	private static Pair findPair(Component a, Component b) {
		for (Pair p : PAIR_VALUES) {
			if ((p.x == a && p.y == b) || (p.x == b && p.y == a)) {
				return p;
			}
		}
		return null;
	}

	private String str(Resource r) {
		return r == null ? defaultContextString : r.stringValue();
	}

	private String str(Value v) {
		return v == null ? defaultContextString : v.stringValue();
	}

	private static String sig(String s, String p, String o, String c) {
		return s + ' ' + p + ' ' + o + ' ' + c;
	}

