	static final class JoinStepEstimate {
		private final double outputRows;
		private final double workRows;
		private final Map<String, VarPlanStats> varStats;

		private JoinStepEstimate(double outputRows, double workRows, Map<String, VarPlanStats> varStats) {
			this.outputRows = outputRows;
			this.workRows = workRows;
			this.varStats = freezeVarStats(varStats);
		}

		double outputRows() {
			return outputRows;
		}

		double workRows() {
			return workRows;
		}

		String summary() {
			return "outputRows=" + outputRows + ", workRows=" + workRows + ", joinVars="
					+ summarizeVarStats(varStats);
		}
	}

	private static Map<String, VarPlanStats> freezeVarStats(Map<String, VarPlanStats> varStats) {
		if (varStats.isEmpty()) {
			return Collections.emptyMap();
		}
		if (varStats instanceof SmallVarStatsMap) {
			SmallVarStatsMap smallMap = (SmallVarStatsMap) varStats;
			smallMap.freeze();
			return smallMap;
		}
		return Collections.unmodifiableMap(varStats);
	}

	private static String summarizeVarStats(Map<String, VarPlanStats> varStats) {
		TreeMap<String, Double> summarized = new TreeMap<>();
		for (Map.Entry<String, VarPlanStats> entry : varStats.entrySet()) {
			summarized.put(entry.getKey(), entry.getValue().distinct);
		}
		return summarized.toString();
	}

	private enum EvictionResult {
		EVICTED,
		FAILED,
		NEEDS_UNLOAD
	}

	public double cardinality(Join node) {
		if (!isReady()) {
			recordRobustCardinalityPath(SketchPlannerPath.ROBUST_NOT_READY);
			return -1;
		}

		List<TupleExpr> orderedArgs = new ArrayList<>();
		flattenJoinTreeToOrderedArgs(node, orderedArgs);
		return cardinality(orderedArgs);
	}

	public double cardinality(List<TupleExpr> tupleExprs) {
		return cardinalityWithInitiallyBoundVars(tupleExprs, Collections.emptySet());
	}

	private double cardinalityWithInitiallyBoundVars(List<TupleExpr> tupleExprs, Set<String> initiallyBoundVars) {
		if (!isReady() || tupleExprs == null || tupleExprs.isEmpty()) {
			recordRobustCardinalityPath(
					isReady() ? SketchPlannerPath.UNSUPPORTED_SHAPE : SketchPlannerPath.ROBUST_NOT_READY);
			return -1;
		}

		Set<String> bound = initiallyBoundVars == null || initiallyBoundVars.isEmpty() ? Collections.emptySet()
				: Set.copyOf(initiallyBoundVars);
		if (tupleExprs.size() == 2) {
			TuplePlanEstimate simulated = estimateBindingSetAssignmentJoinPlan(tupleExprs.get(0), tupleExprs.get(1),
					false, bound);
			if (simulated != null) {
				recordRobustCardinalityPath(SketchPlannerPath.ROBUST_USED);
				return normalizeRows(simulated.outputRows);
			}
		}
		JoinOrderPlanner.Algorithm algorithm = tupleExprs
				.size() <= SketchJoinOrderPlanner.MAX_DYNAMIC_PROGRAMMING_JOIN_ARGS
						? JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING
						: JoinOrderPlanner.Algorithm.GREEDY;
		SketchJoinOrderPlanner.PlanOutcome outcome = new SketchJoinOrderPlanner(this, JoinOrderWorkAdjuster.NO_OP,
				tupleExprs, bound)
						.plan(algorithm);
		recordRobustCardinalityPath(outcome.path());
		return outcome.plan()
				.map(JoinOrderPlanner.JoinOrderPlan::getEstimatedFinalRows)
				.orElse(-1.0d);
	}

	public double cardinality(LeftJoin node) {
		if (!isReady() || node.hasCondition()) {
			return -1;
		}

		TupleExpr leftArg = node.getLeftArg();
		TupleExpr rightArg = node.getRightArg();

		return estimateJoinCardinality(leftArg, rightArg, true);
	}

	public double cardinality(Filter node) {
		if (!isReady()) {
			return -1;
		}

		TuplePlanEstimate estimate = estimateTupleExprPlan(node);
		return estimate == null ? -1.0d : normalizeRows(estimate.outputRows);
	}

	private double estimateJoinCardinality(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin) {
		PatternEstimateInput leftInput = asSketchCompatibleInput(leftArg);
		PatternEstimateInput rightInput = asSketchCompatibleInput(rightArg);
		if (leftInput != null && rightInput != null) {
			StatementPattern l = leftInput.pattern;
			StatementPattern r = rightInput.pattern;
			if (!hasBoundComponent(l) || !hasBoundComponent(r)) {
				return estimateJoinCardinalityFromTuplePlans(leftArg, rightArg, leftJoin);
			}

			/* find first common unbound variable */
			Var common = null;
			List<Var> lVars = l.getVarList();
			for (Var v : r.getVarList()) {
				if (!v.hasValue() && lVars.contains(v)) {
					common = v;
					break;
				}
			}
			if (common == null) {
				double leftRows = applyFilterMultiplier(estimatePatternRows(l), leftInput.filterMultiplier);
				double rightRows = applyFilterMultiplier(estimatePatternRows(r), rightInput.filterMultiplier);
				double crossRows = estimateDisconnectedJoinRows(leftRows, rightRows);
				return leftJoin ? Math.max(leftRows, crossRows) : crossRows;
			}

			Component lc = getComponent(l, common);
			Component rc = getComponent(r, common);

			JoinEstimate leftEstimate = this
					.estimate(lc,
							getValueOrNull(l.getSubjectVar()),
							getValueOrNull(l.getPredicateVar()),
							getValueOrNull(l.getObjectVar()),
							getValueOrNull(l.getContextVar()));
			JoinEstimate rightEstimate = this
					.estimate(rc,
							getValueOrNull(r.getSubjectVar()),
							getValueOrNull(r.getPredicateVar()),
							getValueOrNull(r.getObjectVar()),
							getValueOrNull(r.getContextVar()));
			double leftDistinct = leftEstimate.distinct;
			double rightDistinct = rightEstimate.distinct;
			double leftRows = applyFilterMultiplier(leftEstimate.estimate(), leftInput.filterMultiplier);
			double rightRows = applyFilterMultiplier(rightEstimate.estimate(), rightInput.filterMultiplier);
			double joinRows = applyFilterMultiplier(leftEstimate
					.join(rc,
							getValueOrNull(r.getSubjectVar()),
							getValueOrNull(r.getPredicateVar()),
							getValueOrNull(r.getObjectVar()),
							getValueOrNull(r.getContextVar()))
					.estimate(), leftInput.filterMultiplier * rightInput.filterMultiplier);
			if (joinRows == 0.0d && leftInput.filterMultiplier == 1.0d && rightInput.filterMultiplier == 1.0d) {
				Double exactJoinRows = zeroIntersectionFallbackJoinRows(l, r, common.getName(), leftDistinct,
						rightDistinct, leftRows, rightRows, estimateDisconnectedJoinRows(leftRows, rightRows));
				if (exactJoinRows != null && exactJoinRows > 0.0d) {
					joinRows = exactJoinRows;
				}
			}
			return leftJoin ? Math.max(leftRows, joinRows) : joinRows;
		}
		double nestedEstimate = estimateJoinCardinalityWithNestedSide(leftArg, rightArg, leftJoin);
		if (nestedEstimate >= 0.0d) {
			return nestedEstimate;
		}
		return estimateJoinCardinalityFromTuplePlans(leftArg, rightArg, leftJoin);
	}

	private double estimateJoinCardinalityFromTuplePlans(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin) {
		TuplePlanEstimate joinedEstimate = estimateJoinedTupleExprPlan(leftArg, rightArg, leftJoin,
				Collections.emptySet());
		if (joinedEstimate == null) {
			return -1.0d;
		}
		return normalizeRows(joinedEstimate.outputRows);
	}

	private void flattenJoinTreeToOrderedArgs(TupleExpr tupleExpr, List<TupleExpr> orderedArgs) {
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			flattenJoinTreeToOrderedArgs(join.getLeftArg(), orderedArgs);
			flattenJoinTreeToOrderedArgs(join.getRightArg(), orderedArgs);
			return;
		}
		orderedArgs.add(tupleExpr);
	}

	private TuplePlanEstimate estimateTupleExprPlan(TupleExpr tupleExpr) {
		return estimateTupleExprPlan(tupleExpr, Collections.emptySet());
	}

	private TuplePlanEstimate estimateTupleExprPlan(TupleExpr tupleExpr, Set<String> initiallyBoundVars) {
		if (tupleExpr == null) {
			return null;
		}
		OptimizationScopeState scope = optimizationScope.get();
		if (scope == null) {
			return computeTupleExprPlan(tupleExpr, initiallyBoundVars);
		}
		long boundVarMask = scope.variableDictionary.maskOf(initiallyBoundVars);
		if (boundVarMask == BOUND_VAR_MASK_OVERFLOW) {
			return computeTupleExprPlan(tupleExpr, initiallyBoundVars);
		}
		return estimateTupleExprPlan(tupleExpr, scope, boundVarMask);
	}

	private TuplePlanEstimate estimateTupleExprPlan(TupleExpr tupleExpr, long initiallyBoundVarMask) {
		if (tupleExpr == null) {
			return null;
		}
		OptimizationScopeState scope = optimizationScope.get();
		if (scope == null || initiallyBoundVarMask == BOUND_VAR_MASK_OVERFLOW) {
			return computeTupleExprPlan(tupleExpr, Collections.emptySet());
		}
		return estimateTupleExprPlan(tupleExpr, scope, initiallyBoundVarMask);
	}

	private TuplePlanEstimate estimateTupleExprPlan(TupleExpr tupleExpr, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		TuplePlanEstimateCacheKey key = new TuplePlanEstimateCacheKey(tupleExpr, initiallyBoundVarMask);
		Optional<TuplePlanEstimate> cached = scope.tupleEstimateCache.get(key);
		if (cached != null) {
			return cached.orElse(null);
		}
		TuplePlanEstimate estimate = computeTupleExprPlan(tupleExpr, scope, initiallyBoundVarMask);
		scope.tupleEstimateCache.put(key, Optional.ofNullable(estimate));
		return estimate;
	}

	private TuplePlanEstimate computeTupleExprPlan(TupleExpr tupleExpr, Set<String> initiallyBoundVars) {
		if (tupleExpr == null) {
			return null;
		}

		TuplePlanEstimate plannerEstimate = toPlannerTupleEstimate(tupleExpr, initiallyBoundVars);
		if (plannerEstimate != null) {
			return plannerEstimate;
		}

		if (tupleExpr instanceof Filter) {
			return estimateFilteredTupleExprPlan((Filter) tupleExpr, initiallyBoundVars);
		}
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			return estimateJoinedTupleExprPlan(join.getLeftArg(), join.getRightArg(), false, initiallyBoundVars);
		}
		if (tupleExpr instanceof LeftJoin) {
			LeftJoin join = (LeftJoin) tupleExpr;
			if (join.hasCondition()) {
				return null;
			}
			return estimateJoinedTupleExprPlan(join.getLeftArg(), join.getRightArg(), true, initiallyBoundVars);
		}
		if (tupleExpr instanceof EmptySet) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}
		if (tupleExpr instanceof SingletonSet) {
			return new TuplePlanEstimate(1.0d, 1.0d, 1.0d, Collections.emptyMap());
		}
		if (tupleExpr instanceof Slice) {
			return estimateSliceTupleExprPlan((Slice) tupleExpr, initiallyBoundVars);
		}
		if (tupleExpr instanceof Distinct || tupleExpr instanceof Reduced) {
			return estimateDistinctTupleExprPlan((UnaryTupleOperator) tupleExpr, initiallyBoundVars);
		}
		if (tupleExpr instanceof UnaryTupleOperator) {
			return estimateTupleExprPlan(((UnaryTupleOperator) tupleExpr).getArg(), initiallyBoundVars);
		}
		return null;
	}

	private TuplePlanEstimate computeTupleExprPlan(TupleExpr tupleExpr, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		if (tupleExpr == null) {
			return null;
		}

		TuplePlanEstimate plannerEstimate = toPlannerTupleEstimate(tupleExpr, scope, initiallyBoundVarMask);
		if (plannerEstimate != null) {
			return plannerEstimate;
		}

		if (tupleExpr instanceof Filter) {
			return estimateFilteredTupleExprPlan((Filter) tupleExpr, scope, initiallyBoundVarMask);
		}
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			return estimateJoinedTupleExprPlan(join.getLeftArg(), join.getRightArg(), false, scope,
					initiallyBoundVarMask);
		}
		if (tupleExpr instanceof LeftJoin) {
			LeftJoin join = (LeftJoin) tupleExpr;
			if (join.hasCondition()) {
				return null;
			}
			return estimateJoinedTupleExprPlan(join.getLeftArg(), join.getRightArg(), true, scope,
					initiallyBoundVarMask);
		}
		if (tupleExpr instanceof EmptySet) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}
		if (tupleExpr instanceof SingletonSet) {
			return new TuplePlanEstimate(1.0d, 1.0d, 1.0d, Collections.emptyMap());
		}
		if (tupleExpr instanceof Slice) {
			return estimateSliceTupleExprPlan((Slice) tupleExpr, scope, initiallyBoundVarMask);
		}
		if (tupleExpr instanceof Distinct || tupleExpr instanceof Reduced) {
			return estimateDistinctTupleExprPlan((UnaryTupleOperator) tupleExpr, scope, initiallyBoundVarMask);
		}
		if (tupleExpr instanceof UnaryTupleOperator) {
			return estimateTupleExprPlan(((UnaryTupleOperator) tupleExpr).getArg(), scope, initiallyBoundVarMask);
		}
		return null;
	}

	private TuplePlanEstimate estimateFilteredTupleExprPlan(Filter filter, Set<String> initiallyBoundVars) {
		TuplePlanEstimate exactFiniteEstimate = exactFiniteBindingSetFilterPlan(filter);
		if (exactFiniteEstimate != null) {
			return exactFiniteEstimate;
		}
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(filter.getArg(), initiallyBoundVars);
		if (argEstimate == null) {
			return null;
		}
		double filterMultiplier = resolveFilterMultiplier(filter, argEstimate);
		if (filterMultiplier >= 1.0d) {
			StatementPattern patternLocalBase = basePatternForFilter(filter);
			if (patternLocalBase != null) {
				LookupAnalysis lookupAnalysis = analyzeLookupBindings(patternLocalBase, filter.getCondition(),
						initiallyBoundVars);
				if (lookupAnalysis.multiplier() > 0.0d) {
					filterMultiplier = lookupAnalysis.multiplier();
				}
			}
		}
		return applySubtreeFilterMultiplier(argEstimate, filterMultiplier);
	}

	private TuplePlanEstimate estimateFilteredTupleExprPlan(Filter filter, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		TuplePlanEstimate exactFiniteEstimate = exactFiniteBindingSetFilterPlan(filter);
		if (exactFiniteEstimate != null) {
			return exactFiniteEstimate;
		}
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(filter.getArg(), scope, initiallyBoundVarMask);
		if (argEstimate == null) {
			return null;
		}
		double filterMultiplier = resolveFilterMultiplier(filter, argEstimate);
		if (filterMultiplier >= 1.0d) {
			StatementPattern patternLocalBase = basePatternForFilter(filter);
			if (patternLocalBase != null) {
				LookupAnalysis lookupAnalysis = analyzeLookupBindings(patternLocalBase, filter.getCondition(),
						scope, initiallyBoundVarMask);
				if (lookupAnalysis.multiplier() > 0.0d) {
					filterMultiplier = lookupAnalysis.multiplier();
				}
			}
		}
		return applySubtreeFilterMultiplier(argEstimate, filterMultiplier);
	}

	private TuplePlanEstimate estimateJoinedTupleExprPlan(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin,
			Set<String> initiallyBoundVars) {
		TuplePlanEstimate simulated = estimateBindingSetAssignmentJoinPlan(leftArg, rightArg, leftJoin,
				initiallyBoundVars);
		if (simulated != null) {
			return simulated;
		}
		TuplePlanEstimate leftEstimate = estimateTupleExprPlan(leftArg, initiallyBoundVars);
		TuplePlanEstimate rightEstimate = estimateTupleExprPlan(rightArg, initiallyBoundVars);
		if (leftEstimate == null || rightEstimate == null) {
			return null;
		}
		JoinStepEstimate step = estimateJoinStep(leftEstimate, rightEstimate);
		double outputRows = leftJoin ? Math.max(leftEstimate.outputRows, step.outputRows) : step.outputRows;
		return new TuplePlanEstimate(outputRows, outputRows, 1.0d, step.varStats);
	}

	private TuplePlanEstimate estimateJoinedTupleExprPlan(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin,
			OptimizationScopeState scope, long initiallyBoundVarMask) {
		TuplePlanEstimate simulated = estimateBindingSetAssignmentJoinPlan(leftArg, rightArg, leftJoin, scope,
				initiallyBoundVarMask);
		if (simulated != null) {
			return simulated;
		}
		TuplePlanEstimate leftEstimate = estimateTupleExprPlan(leftArg, scope, initiallyBoundVarMask);
		TuplePlanEstimate rightEstimate = estimateTupleExprPlan(rightArg, scope, initiallyBoundVarMask);
		if (leftEstimate == null || rightEstimate == null) {
			return null;
		}
		JoinStepEstimate step = estimateJoinStep(leftEstimate, rightEstimate);
		double outputRows = leftJoin ? Math.max(leftEstimate.outputRows, step.outputRows) : step.outputRows;
		return new TuplePlanEstimate(outputRows, outputRows, 1.0d, step.varStats);
	}

	private TuplePlanEstimate estimateBindingSetAssignmentJoinPlan(TupleExpr leftArg, TupleExpr rightArg,
			boolean leftJoin, Set<String> initiallyBoundVars) {
		boolean leftAssignment = leftArg instanceof BindingSetAssignment;
		boolean rightAssignment = rightArg instanceof BindingSetAssignment;
		if (leftAssignment == rightAssignment) {
			return null;
		}
		if (leftJoin && !leftAssignment) {
			return null;
		}

		BindingSetAssignment assignment = (BindingSetAssignment) (leftAssignment ? leftArg : rightArg);
		TupleExpr otherArg = leftAssignment ? rightArg : leftArg;
		Set<String> sharedNames = new HashSet<>(assignment.getBindingNames());
		sharedNames.retainAll(otherArg.getBindingNames());
		if (sharedNames.isEmpty() || !isSmallBindingSetAssignment(assignment)) {
			return null;
		}

		Iterable<BindingSet> bindingSets = assignment.getBindingSets();
		if (bindingSets == null) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}

		double totalRows = 0.0d;
		Map<String, Set<Value>> survivingAssignmentValues = new HashMap<>();
		Map<String, ArrayOfDoublesUpdatableSketch> survivingAssignmentSketches = new HashMap<>();
		Map<String, Double> carriedDistinct = new HashMap<>();

		for (BindingSet bindingSet : bindingSets) {
			TupleExpr boundOther = bindTupleExpr(otherArg, bindingSet);
			TuplePlanEstimate rowEstimate = estimateBoundTupleExprPlan(boundOther, initiallyBoundVars);
			if (rowEstimate == null) {
				return null;
			}

			double matchedRows = rowEstimate.outputRows;
			double rowRows = leftJoin ? Math.max(1.0d, matchedRows) : matchedRows;
			if (rowRows <= 0.0d) {
				continue;
			}

			totalRows += rowRows;
			if (!Double.isFinite(totalRows)) {
				totalRows = Double.MAX_VALUE;
			}

			for (String bindingName : assignment.getBindingNames()) {
				Value value = bindingSet.getValue(bindingName);
				if (value == null) {
					continue;
				}
				survivingAssignmentValues.computeIfAbsent(bindingName, key -> new HashSet<>()).add(value);
				tupleUpdateRaw(survivingAssignmentSketches.computeIfAbsent(bindingName, key -> newSk(bufA.k)),
						thetaHash(valueFingerprint(str(value))), 1.0d);
			}

			if (matchedRows <= 0.0d) {
				continue;
			}
			for (Map.Entry<String, VarPlanStats> entry : rowEstimate.varStats.entrySet()) {
				if (bindingSet.hasBinding(entry.getKey())) {
					continue;
				}
				carriedDistinct.merge(entry.getKey(), entry.getValue().distinct, Double::sum);
			}
		}

		totalRows = normalizeRows(totalRows);
		Map<String, VarPlanStats> varStats = newVarStatsMap();
		for (Map.Entry<String, Set<Value>> entry : survivingAssignmentValues.entrySet()) {
			double distinct = clampDistinct(entry.getValue().size(), totalRows);
			ArrayOfDoublesSketch sketch = survivingAssignmentSketches.get(entry.getKey());
			varStats.put(entry.getKey(), new VarPlanStats(distinct, sketch == null ? null : sketch.compact()));
		}
		for (Map.Entry<String, Double> entry : carriedDistinct.entrySet()) {
			varStats.putIfAbsent(entry.getKey(), new VarPlanStats(clampDistinct(entry.getValue(), totalRows), null));
		}
		return new TuplePlanEstimate(totalRows, totalRows, 1.0d, varStats);
	}

	private TuplePlanEstimate estimateBindingSetAssignmentJoinPlan(TupleExpr leftArg, TupleExpr rightArg,
			boolean leftJoin, OptimizationScopeState scope, long initiallyBoundVarMask) {
		boolean leftAssignment = leftArg instanceof BindingSetAssignment;
		boolean rightAssignment = rightArg instanceof BindingSetAssignment;
		if (leftAssignment == rightAssignment) {
			return null;
		}
		if (leftJoin && !leftAssignment) {
			return null;
		}

		BindingSetAssignment assignment = (BindingSetAssignment) (leftAssignment ? leftArg : rightArg);
		TupleExpr otherArg = leftAssignment ? rightArg : leftArg;
		Set<String> sharedNames = new HashSet<>(assignment.getBindingNames());
		sharedNames.retainAll(otherArg.getBindingNames());
		if (sharedNames.isEmpty() || !isSmallBindingSetAssignment(assignment)) {
			return null;
		}

		Iterable<BindingSet> bindingSets = assignment.getBindingSets();
		if (bindingSets == null) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}

		double totalRows = 0.0d;
		Map<String, Set<Value>> survivingAssignmentValues = new HashMap<>();
		Map<String, ArrayOfDoublesUpdatableSketch> survivingAssignmentSketches = new HashMap<>();
		Map<String, Double> carriedDistinct = new HashMap<>();

		for (BindingSet bindingSet : bindingSets) {
			TupleExpr boundOther = bindTupleExpr(otherArg, bindingSet);
			TuplePlanEstimate rowEstimate = estimateBoundTupleExprPlan(boundOther, scope, initiallyBoundVarMask);
			if (rowEstimate == null) {
				return null;
			}

			double matchedRows = rowEstimate.outputRows;
			double rowRows = leftJoin ? Math.max(1.0d, matchedRows) : matchedRows;
			if (rowRows <= 0.0d) {
				continue;
			}

			totalRows += rowRows;
			if (!Double.isFinite(totalRows)) {
				totalRows = Double.MAX_VALUE;
			}

			for (String bindingName : assignment.getBindingNames()) {
				Value value = bindingSet.getValue(bindingName);
				if (value == null) {
					continue;
				}
				survivingAssignmentValues.computeIfAbsent(bindingName, key -> new HashSet<>()).add(value);
				tupleUpdateRaw(survivingAssignmentSketches.computeIfAbsent(bindingName, key -> newSk(bufA.k)),
						thetaHash(valueFingerprint(str(value))), 1.0d);
			}

			if (matchedRows <= 0.0d) {
				continue;
			}
			for (Map.Entry<String, VarPlanStats> entry : rowEstimate.varStats.entrySet()) {
				if (bindingSet.hasBinding(entry.getKey())) {
					continue;
				}
				carriedDistinct.merge(entry.getKey(), entry.getValue().distinct, Double::sum);
			}
		}

		totalRows = normalizeRows(totalRows);
		Map<String, VarPlanStats> varStats = newVarStatsMap();
		for (Map.Entry<String, Set<Value>> entry : survivingAssignmentValues.entrySet()) {
			double distinct = clampDistinct(entry.getValue().size(), totalRows);
			ArrayOfDoublesSketch sketch = survivingAssignmentSketches.get(entry.getKey());
			varStats.put(entry.getKey(), new VarPlanStats(distinct, sketch == null ? null : sketch.compact()));
		}
		for (Map.Entry<String, Double> entry : carriedDistinct.entrySet()) {
			varStats.putIfAbsent(entry.getKey(), new VarPlanStats(clampDistinct(entry.getValue(), totalRows), null));
		}
		return new TuplePlanEstimate(totalRows, totalRows, 1.0d, varStats);
	}

	private TupleExpr bindTupleExpr(TupleExpr tupleExpr, BindingSet bindingSet) {
		TupleExpr bound = tupleExpr.clone();
		bound.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>(true) {
			@Override
			public void meet(Var var) {
				if (var.hasValue() || var.getName() == null || !bindingSet.hasBinding(var.getName())) {
					return;
				}
				Value value = bindingSet.getValue(var.getName());
				if (value != null) {
					var.replaceWith(Var.of(var.getName(), value, var.isAnonymous(), var.isConstant()));
				}
			}
		});
		return bound;
	}

	private TuplePlanEstimate estimateBoundTupleExprPlan(TupleExpr tupleExpr, Set<String> initiallyBoundVars) {
		if (tupleExpr instanceof StatementPattern) {
			TuplePlanEstimate exactPlan = exactBoundStatementPatternPlan((StatementPattern) tupleExpr);
			if (exactPlan != null) {
				return exactPlan;
			}
		} else if (tupleExpr instanceof Filter) {
			TuplePlanEstimate exactPlan = exactBoundLocalFilterPlan((Filter) tupleExpr);
			if (exactPlan != null) {
				return exactPlan;
			}
		}
		return estimateTupleExprPlan(tupleExpr, initiallyBoundVars);
	}

	private TuplePlanEstimate estimateBoundTupleExprPlan(TupleExpr tupleExpr, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		if (tupleExpr instanceof StatementPattern) {
			TuplePlanEstimate exactPlan = exactBoundStatementPatternPlan((StatementPattern) tupleExpr);
			if (exactPlan != null) {
				return exactPlan;
			}
		} else if (tupleExpr instanceof Filter) {
			TuplePlanEstimate exactPlan = exactBoundLocalFilterPlan((Filter) tupleExpr);
			if (exactPlan != null) {
				return exactPlan;
			}
		}
		return estimateTupleExprPlan(tupleExpr, scope, initiallyBoundVarMask);
	}

	private TuplePlanEstimate exactBoundLocalFilterPlan(Filter filter) {
		if (!(filter.getArg() instanceof StatementPattern)) {
			return null;
		}
		StatementPattern pattern = ((StatementPattern) filter.getArg()).clone();
		if (!bindSimpleFilterCondition(pattern, filter.getCondition())) {
			return null;
		}
		return exactBoundStatementPatternPlan(pattern);
	}

	private TuplePlanEstimate exactBoundStatementPatternPlan(StatementPattern pattern) {
		if (boundComponentCount(pattern) < 2) {
			return null;
		}
		if (hasIncompatibleBoundResource(pattern.getSubjectVar())
				|| hasIncompatibleBoundPredicate(pattern.getPredicateVar())
				|| hasIncompatibleBoundResource(pattern.getContextVar())) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}

		Resource subject = exactBoundResource(pattern.getSubjectVar());
		IRI predicate = exactBoundIri(pattern.getPredicateVar());
		Value object = exactBoundValue(pattern.getObjectVar());
		Resource[] contexts = exactBoundContexts(pattern.getContextVar());
		if (contexts == null) {
			return new TuplePlanEstimate(0.0d, 0.0d, 1.0d, Collections.emptyMap());
		}

		double rows = 0.0d;
		Map<String, Set<Value>> distinctValues = new HashMap<>();
		try (SailDataset dataset = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
				CloseableIteration<? extends Statement> statements = dataset.getStatements(subject, predicate, object,
						contexts)) {
			while (statements.hasNext()) {
				Statement statement = statements.next();
				if (!statementMatchesPatternVariableEqualities(pattern, statement)) {
					continue;
				}
				rows++;
				if (rows > zeroIntersectionRowBudget) {
					return null;
				}
				collectExactPatternVarValues(pattern, statement, distinctValues);
			}
		} catch (SailException e) {
			logger.debug("Falling back from exact bound pattern lookup for {}", pattern, e);
			return null;
		}

		rows = normalizeRows(rows);
		Map<String, VarPlanStats> varStats = newVarStatsMap();
		for (Map.Entry<String, Set<Value>> entry : distinctValues.entrySet()) {
			varStats.put(entry.getKey(), new VarPlanStats(clampDistinct(entry.getValue().size(), rows), null,
					pattern));
		}
		return new TuplePlanEstimate(rows, rows, 1.0d, varStats);
	}

	private int boundComponentCount(StatementPattern pattern) {
		int count = 0;
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (hasBoundValue(var)) {
				count++;
			}
		}
		return count;
	}

	private void collectExactPatternVarValues(StatementPattern pattern, Statement statement,
			Map<String, Set<Value>> distinctValues) {
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var == null || var.hasValue() || var.getName() == null) {
				continue;
			}
			Value value = statementValue(statement, component);
			if (value != null) {
				distinctValues.computeIfAbsent(var.getName(), ignored -> new HashSet<>()).add(value);
			}
		}
	}

	private Double exactBoundStatementPatternRows(StatementPattern pattern) {
		Var subjectVar = pattern.getSubjectVar();
		Var predicateVar = pattern.getPredicateVar();
		Var objectVar = pattern.getObjectVar();
		if (subjectVar == null || predicateVar == null || objectVar == null
				|| !subjectVar.hasValue() || !predicateVar.hasValue() || !objectVar.hasValue()) {
			return null;
		}
		if (!(subjectVar.getValue() instanceof Resource) || !(predicateVar.getValue() instanceof IRI)) {
			return 0.0d;
		}

		Var contextVar = pattern.getContextVar();
		if (contextVar != null && !contextVar.hasValue()) {
			return null;
		}
		if (contextVar != null && contextVar.getValue() != null && !(contextVar.getValue() instanceof Resource)) {
			return 0.0d;
		}

		Resource[] contexts = contextVar == null
				? new Resource[0]
				: new Resource[] { (Resource) contextVar.getValue() };
		double rows = 0.0d;
		try (SailDataset dataset = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
				CloseableIteration<? extends Statement> statements = dataset.getStatements(
						(Resource) subjectVar.getValue(),
						(IRI) predicateVar.getValue(),
						objectVar.getValue(),
						contexts)) {
			while (statements.hasNext()) {
				statements.next();
				rows++;
			}
		} catch (SailException e) {
			logger.debug("Falling back from exact bound pattern lookup for {}", pattern, e);
			return null;
		}
		return normalizeRows(rows);
	}

	private Double zeroIntersectionFallbackJoinRows(StatementPattern left, StatementPattern right, String sharedVarName,
			double leftDistinctEstimate, double rightDistinctEstimate, double leftRowsEstimate,
			double rightRowsEstimate, double disconnectedRows) {
		if (!hasBoundComponent(left) || !hasBoundComponent(right) || zeroIntersectionRowBudget <= 0L) {
			return null;
		}

		double smallerRowsEstimate = Math.min(leftRowsEstimate, rightRowsEstimate);
		double smallerDistinctEstimate = Math.min(leftDistinctEstimate, rightDistinctEstimate);
		double largerDistinctEstimate = Math.max(leftDistinctEstimate, rightDistinctEstimate);
		if (!Double.isFinite(smallerRowsEstimate) || smallerRowsEstimate <= 0.0d
				|| smallerRowsEstimate > zeroIntersectionRowBudget
				|| !Double.isFinite(smallerDistinctEstimate) || smallerDistinctEstimate <= 0.0d
				|| !Double.isFinite(largerDistinctEstimate) || largerDistinctEstimate <= 0.0d) {
			return null;
		}
		boolean exactEligible = smallerDistinctEstimate <= zeroIntersectionExactDistinctLimit;
		double skewRatio = largerDistinctEstimate / Math.max(1.0d, smallerDistinctEstimate);
		boolean skewEligible = zeroIntersectionSkewRatio > 0.0d && skewRatio >= zeroIntersectionSkewRatio;
		if (!exactEligible && !skewEligible) {
			return null;
		}

		Component leftSharedComponent = findPatternComponentByVarName(left, sharedVarName);
		Component rightSharedComponent = findPatternComponentByVarName(right, sharedVarName);
		if (leftSharedComponent == null || rightSharedComponent == null) {
			return null;
		}

		boolean scanLeft = exactEligible
				? leftDistinctEstimate <= rightDistinctEstimate
				: leftRowsEstimate <= rightRowsEstimate;
		StatementPattern scanPattern = scanLeft ? left : right;
		StatementPattern probePattern = scanLeft ? right : left;
		Component scanSharedComponent = scanLeft ? leftSharedComponent : rightSharedComponent;
		double scanRowsEstimate = scanLeft ? leftRowsEstimate : rightRowsEstimate;
		if (!Double.isFinite(scanRowsEstimate) || scanRowsEstimate <= 0.0d
				|| scanRowsEstimate > zeroIntersectionRowBudget) {
			return null;
		}

		SharedVarScan smallerScan = scanSharedVarRows(scanPattern, scanSharedComponent, sharedVarName);
		if (smallerScan == null || smallerScan.scannedRows == 0L) {
			return smallerScan == null ? null : 0.0d;
		}

		Map<Value, Long> probeCache = new HashMap<>();
		if (smallerScan.exactCounts != null) {
			long joinRows = 0L;
			for (Map.Entry<Value, Long> entry : smallerScan.exactCounts.entrySet()) {
				Long largerRows = probeCache.computeIfAbsent(entry.getKey(),
						value -> exactBoundPatternRows(probePattern, sharedVarName, value));
				if (largerRows == null) {
					return null;
				}
				joinRows += entry.getValue() * largerRows;
			}
			return normalizeRows(Math.min(disconnectedRows, joinRows));
		}

		if (smallerScan.sampledRows.isEmpty()) {
			return 0.0d;
		}
		double sampledJoinRows = 0.0d;
		for (Value sampledValue : smallerScan.sampledRows) {
			Long largerRows = probeCache.computeIfAbsent(sampledValue,
					value -> exactBoundPatternRows(probePattern, sharedVarName, value));
			if (largerRows == null) {
				return null;
			}
			sampledJoinRows += largerRows;
		}
		double averageRows = sampledJoinRows / smallerScan.sampledRows.size();
		return normalizeRows(Math.min(disconnectedRows, smallerScan.scannedRows * averageRows));
	}

	private SharedVarScan scanSharedVarRows(StatementPattern pattern, Component sharedComponent, String sharedVarName) {
		Resource subject = exactBoundResource(pattern.getSubjectVar());
		IRI predicate = exactBoundIri(pattern.getPredicateVar());
		Value object = exactBoundValue(pattern.getObjectVar());
		Resource[] contexts = exactBoundContexts(pattern.getContextVar());
		if (contexts == null) {
			return null;
		}

		Map<Value, Long> exactCounts = zeroIntersectionExactDistinctLimit > 0 ? new LinkedHashMap<>() : null;
		boolean samplingEnabled = zeroIntersectionSampleSize > 0;
		List<Value> sampledRows = samplingEnabled ? new ArrayList<>(zeroIntersectionSampleSize)
				: Collections.emptyList();
		java.util.Random sampleRandom = new java.util.Random(mix64(valueFingerprint(sharedVarName)
				^ Double.doubleToLongBits(Math.max(1.0d, zeroIntersectionSkewRatio))
				^ zeroIntersectionRowBudget));
		long scannedRows = 0L;
		try (SailDataset dataset = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
				CloseableIteration<? extends Statement> statements = dataset.getStatements(subject, predicate, object,
						contexts)) {
			while (statements.hasNext()) {
				Statement statement = statements.next();
				if (!statementMatchesPatternVariableEqualities(pattern, statement)) {
					continue;
				}
				scannedRows++;
				if (scannedRows > zeroIntersectionRowBudget) {
					return null;
				}
				Value sharedValue = statementValue(statement, sharedComponent);
				if (sharedValue != null) {
					if (samplingEnabled) {
						if (sampledRows.size() < zeroIntersectionSampleSize) {
							sampledRows.add(sharedValue);
						} else {
							long replacementIndex = sampleRandom.nextLong(scannedRows);
							if (replacementIndex < zeroIntersectionSampleSize) {
								sampledRows.set((int) replacementIndex, sharedValue);
							}
						}
					}
					if (exactCounts != null) {
						exactCounts.merge(sharedValue, 1L, Long::sum);
						if (exactCounts.size() > zeroIntersectionExactDistinctLimit) {
							exactCounts = null;
						}
					}
				}
			}
		} catch (SailException e) {
			logger.debug("Falling back from exact shared-var scan for {}", pattern, e);
			return null;
		}
		return new SharedVarScan(exactCounts, sampledRows, scannedRows);
	}

	private Long exactBoundPatternRows(StatementPattern pattern, String sharedVarName, Value sharedValue) {
		StatementPattern boundPattern = bindPatternVar(pattern, sharedVarName, sharedValue);
		if (hasIncompatibleBoundResource(boundPattern.getSubjectVar())
				|| hasIncompatibleBoundPredicate(boundPattern.getPredicateVar())
				|| hasIncompatibleBoundResource(boundPattern.getContextVar())) {
			return 0L;
		}

		Resource subject = exactBoundResource(boundPattern.getSubjectVar());
		IRI predicate = exactBoundIri(boundPattern.getPredicateVar());
		Value object = exactBoundValue(boundPattern.getObjectVar());
		Resource[] contexts = exactBoundContexts(boundPattern.getContextVar());
		if (contexts == null) {
			return 0L;
		}

		long rows = 0L;
		try (SailDataset dataset = sailStore.getExplicitSailSource().dataset(IsolationLevels.READ_COMMITTED);
				CloseableIteration<? extends Statement> statements = dataset.getStatements(subject, predicate, object,
						contexts)) {
			while (statements.hasNext()) {
				Statement statement = statements.next();
				if (statementMatchesPatternVariableEqualities(boundPattern, statement)) {
					rows++;
				}
			}
		} catch (SailException e) {
			logger.debug("Falling back from exact bound probe for {} with {}={}", pattern, sharedVarName, sharedValue,
					e);
			return null;
		}
		return rows;
	}

	private StatementPattern bindPatternVar(StatementPattern pattern, String sharedVarName, Value sharedValue) {
		StatementPattern boundPattern = pattern.clone();
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(boundPattern, component);
			if (var == null || var.hasValue() || var.getName() == null || !sharedVarName.equals(var.getName())) {
				continue;
			}
			var.replaceWith(Var.of(var.getName(), sharedValue, var.isAnonymous(), var.isConstant()));
		}
		return boundPattern;
	}

	private boolean hasIncompatibleBoundResource(Var var) {
		return var != null && var.hasValue() && var.getValue() != null && !(var.getValue() instanceof Resource);
	}

	private boolean hasIncompatibleBoundPredicate(Var var) {
		return var != null && var.hasValue() && var.getValue() != null && !(var.getValue() instanceof IRI);
	}

	private Resource exactBoundResource(Var var) {
		if (var == null || !var.hasValue() || var.getValue() == null) {
			return null;
		}
		return var.getValue()instanceof Resource resource ? resource : null;
	}

	private IRI exactBoundIri(Var var) {
		if (var == null || !var.hasValue() || var.getValue() == null) {
			return null;
		}
		return var.getValue()instanceof IRI iri ? iri : null;
	}

	private Value exactBoundValue(Var var) {
		if (var == null || !var.hasValue()) {
			return null;
		}
		return var.getValue();
	}

	private Resource[] exactBoundContexts(Var contextVar) {
		if (contextVar == null || !contextVar.hasValue()) {
			return new Resource[0];
		}
		if (contextVar.getValue() == null) {
			return new Resource[] { null };
		}
		if (!(contextVar.getValue()instanceof Resource resource)) {
			return null;
		}
		return new Resource[] { resource };
	}

	private boolean statementMatchesPatternVariableEqualities(StatementPattern pattern, Statement statement) {
		Map<String, Value> seen = new HashMap<>();
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var == null || var.hasValue() || var.getName() == null) {
				continue;
			}
			Value value = statementValue(statement, component);
			if (seen.containsKey(var.getName())) {
				if (!Objects.equals(seen.get(var.getName()), value)) {
					return false;
				}
			} else {
				seen.put(var.getName(), value);
			}
		}
		return true;
	}

	private Value statementValue(Statement statement, Component component) {
		return switch (component) {
		case S -> statement.getSubject();
		case P -> statement.getPredicate();
		case O -> statement.getObject();
		case C -> statement.getContext();
		};
	}

	private static final class SharedVarScan {
		private final Map<Value, Long> exactCounts;
		private final List<Value> sampledRows;
		private final long scannedRows;

		private SharedVarScan(Map<Value, Long> exactCounts, List<Value> sampledRows, long scannedRows) {
			this.exactCounts = exactCounts;
			this.sampledRows = sampledRows;
			this.scannedRows = scannedRows;
		}
	}

	private TuplePlanEstimate estimateSliceTupleExprPlan(Slice slice, Set<String> initiallyBoundVars) {
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(slice.getArg(), initiallyBoundVars);
		if (argEstimate == null) {
			return null;
		}
		double rows = argEstimate.outputRows;
		if (slice.hasOffset()) {
			rows = Math.max(0.0d, rows - slice.getOffset());
		}
		if (slice.hasLimit()) {
			rows = Math.min(rows, slice.getLimit());
		}
		rows = normalizeRows(rows);
		return new TuplePlanEstimate(rows, rows, 1.0d, clampVarStatsToRows(argEstimate.varStats, rows, false));
	}

	private TuplePlanEstimate estimateSliceTupleExprPlan(Slice slice, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(slice.getArg(), scope, initiallyBoundVarMask);
		if (argEstimate == null) {
			return null;
		}
		double rows = argEstimate.outputRows;
		if (slice.hasOffset()) {
			rows = Math.max(0.0d, rows - slice.getOffset());
		}
		if (slice.hasLimit()) {
			rows = Math.min(rows, slice.getLimit());
		}
		rows = normalizeRows(rows);
		return new TuplePlanEstimate(rows, rows, 1.0d, clampVarStatsToRows(argEstimate.varStats, rows, false));
	}

	private TuplePlanEstimate estimateDistinctTupleExprPlan(UnaryTupleOperator tupleExpr,
			Set<String> initiallyBoundVars) {
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(tupleExpr.getArg(), initiallyBoundVars);
		if (argEstimate == null) {
			return null;
		}
		double rows = normalizeRows(argEstimate.outputRows);
		return new TuplePlanEstimate(rows, rows, 1.0d, argEstimate.varStats);
	}

	private TuplePlanEstimate estimateDistinctTupleExprPlan(UnaryTupleOperator tupleExpr, OptimizationScopeState scope,
			long initiallyBoundVarMask) {
		TuplePlanEstimate argEstimate = estimateTupleExprPlan(tupleExpr.getArg(), scope, initiallyBoundVarMask);
		if (argEstimate == null) {
			return null;
		}
		double rows = normalizeRows(argEstimate.outputRows);
		return new TuplePlanEstimate(rows, rows, 1.0d, argEstimate.varStats);
	}

	private double estimatePatternRows(StatementPattern pattern) {
		PatternCardinalityProvider provider = patternCardinalityProvider;
		if (provider != null) {
			double rows = provider.estimate(pattern);
			if (Double.isFinite(rows) && rows >= 0.0d) {
				return rows;
			}
		}
		return estimate(resolveJoinComponent(pattern),
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()))
						.estimate();
	}

	private Component resolveJoinComponent(StatementPattern pattern) {
		if (!hasBoundValue(pattern.getSubjectVar())) {
			return Component.S;
		}
		if (!hasBoundValue(pattern.getPredicateVar())) {
			return Component.P;
		}
		if (!hasBoundValue(pattern.getObjectVar())) {
			return Component.O;
		}
		if (!hasBoundValue(pattern.getContextVar())) {
			return Component.C;
		}
		return Component.S;
	}

	private double estimateDisconnectedJoinRows(double leftRows, double rightRows) {
		double estimate = leftRows * rightRows;
		if (!Double.isFinite(estimate)) {
			return Double.MAX_VALUE;
		}
		return roundJoinEstimate(estimate);
	}

	private double estimateDisconnectedJoinWorkRows(double leftRows, double rightRows) {
		double estimate = estimateDisconnectedJoinRows(leftRows, rightRows);
		if (!Double.isFinite(estimate)) {
			return Double.MAX_VALUE;
		}
		estimate = estimate * DISCONNECTED_JOIN_WORK_PENALTY;
		if (!Double.isFinite(estimate)) {
			return Double.MAX_VALUE;
		}
		return roundJoinEstimate(estimate);
	}

	private double roundJoinEstimate(double value) {
		if (!roundJoinEstimates || !Double.isFinite(value) || value >= Long.MAX_VALUE) {
			return value;
		}
		return Math.round(value);
	}

	private double estimateJoinCardinalityWithNestedSide(TupleExpr leftArg, TupleExpr rightArg, boolean leftJoin) {
		boolean leftNested = leftArg instanceof Join;
		boolean rightNested = rightArg instanceof Join;
		if (leftNested == rightNested) {
			return -1;
		}

		Join nested = (Join) (leftNested ? leftArg : rightArg);
		PatternEstimateInput flatInput = asSketchCompatibleInput(leftNested ? rightArg : leftArg);
		if (flatInput == null || !hasBoundComponent(flatInput.pattern)) {
			return -1;
		}
		StatementPattern flat = flatInput.pattern;

		java.util.Set<String> nestedBindingNames = nested.getBindingNames();
		for (Var var : flat.getVarList()) {
			if (var == null || var.hasValue() || var.getName() == null || !nestedBindingNames.contains(var.getName())) {
				continue;
			}

			TupleSketchStats nestedStats = estimateTupleExprForJoinVar(nested, var.getName());
			if (nestedStats == null) {
				continue;
			}

			TupleSketchStats flatStats = estimatePatternForJoinVar(flat, var.getName(), flatInput.filterMultiplier);
			if (flatStats == null) {
				continue;
			}

			double leftRows = leftNested ? nestedStats.rows : flatStats.rows;
			double joinRows = mergeTupleSketchStats(leftNested ? nestedStats : flatStats,
					leftNested ? flatStats : nestedStats).rows;
			return leftJoin ? Math.max(leftRows, joinRows) : joinRows;
		}

		double nestedRows = estimateTupleExprRows(nested);
		if (nestedRows < 0.0) {
			return -1;
		}
		double flatRows = applyFilterMultiplier(estimatePatternRows(flat), flatInput.filterMultiplier);
		double crossRows = estimateDisconnectedJoinRows(leftNested ? nestedRows : flatRows,
				leftNested ? flatRows : nestedRows);
		if (leftJoin) {
			double leftRows = leftNested ? nestedRows : flatRows;
			return Math.max(leftRows, crossRows);
		}
		return crossRows;
	}

	private double estimateTupleExprRows(TupleExpr tupleExpr) {
		PatternEstimateInput patternInput = asSketchCompatibleInput(tupleExpr);
		if (patternInput != null) {
			return hasBoundComponent(patternInput.pattern)
					? applyFilterMultiplier(estimatePatternRows(patternInput.pattern), patternInput.filterMultiplier)
					: -1;
		}

		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			return estimateJoinCardinality(join.getLeftArg(), join.getRightArg(), false);
		}

		if (tupleExpr instanceof LeftJoin) {
			LeftJoin join = (LeftJoin) tupleExpr;
			if (join.hasCondition()) {
				return -1;
			}
			return estimateJoinCardinality(join.getLeftArg(), join.getRightArg(), true);
		}

		return -1;
	}

	private TupleSketchStats estimateTupleExprForJoinVar(TupleExpr tupleExpr, String joinVarName) {
		PatternEstimateInput patternInput = asSketchCompatibleInput(tupleExpr);
		if (patternInput != null) {
			return estimatePatternForJoinVar(patternInput.pattern, joinVarName, patternInput.filterMultiplier);
		}

		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			TupleSketchStats leftStats = estimateTupleExprForJoinVar(join.getLeftArg(), joinVarName);
			TupleSketchStats rightStats = estimateTupleExprForJoinVar(join.getRightArg(), joinVarName);
			if (leftStats == null || rightStats == null) {
				return null;
			}
			return mergeTupleSketchStats(leftStats, rightStats);
		}

		return null;
	}

	private TupleSketchStats estimatePatternForJoinVar(StatementPattern pattern, String joinVarName,
			double filterMultiplier) {
		if (!hasBoundComponent(pattern)) {
			return null;
		}

		Var joinVar = findUnboundVarByName(pattern, joinVarName);
		if (joinVar == null) {
			return null;
		}

		JoinEstimate estimate = estimate(getComponent(pattern, joinVar),
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()));
		return new TupleSketchStats(estimate.bindings, estimate.distinct,
				applyFilterMultiplier(estimate.resultSize, filterMultiplier));
	}

	private TupleSketchStats mergeTupleSketchStats(TupleSketchStats leftStats, TupleSketchStats rightStats) {
		TupleSketchOps.IntersectionStats intersectionStats = TupleSketchOps.intersectProductStats(leftStats.bindings,
				rightStats.bindings, DEFAULT_SKETCH_NOMINAL_ENTRIES);
		ArrayOfDoublesSketch inter = intersectionStats.sketch();
		double interDistinct = intersectionStats.positiveDistinct();

		if (interDistinct == 0.0) {
			return new TupleSketchStats(inter, 0.0, 0.0);
		}

		double joinRows = roundJoinEstimate(intersectionStats.positiveSum());
		return new TupleSketchStats(inter, interDistinct, joinRows);
	}

	private Var findUnboundVarByName(StatementPattern pattern, String varName) {
		for (Var var : pattern.getVarList()) {
			if (var != null && !var.hasValue() && varName.equals(var.getName())) {
				return var;
			}
		}
		return null;
	}

	private static final class TupleSketchStats {
		private final ArrayOfDoublesSketch bindings;
		private final double distinct;
		private final double rows;

		private TupleSketchStats(ArrayOfDoublesSketch bindings, double distinct, double rows) {
			this.bindings = bindings;
			this.distinct = distinct;
			this.rows = rows;
		}
	}

	private static final class PatternEstimateInput {
		private final StatementPattern pattern;
		private final double filterMultiplier;

		private PatternEstimateInput(StatementPattern pattern, double filterMultiplier) {
			this.pattern = pattern;
			this.filterMultiplier = filterMultiplier;
		}
	}

	private PatternEstimateInput asSketchCompatibleInput(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern) {
			return new PatternEstimateInput((StatementPattern) tupleExpr, 1.0d);
		}
		if (tupleExpr instanceof Filter) {
			return asSketchCompatibleInput((Filter) tupleExpr);
		}
		return null;
	}

	private PatternEstimateInput asSketchCompatibleInput(Filter filter) {
		PatternEstimateInput input = asSketchCompatibleInput(filter.getArg());
		if (input == null) {
			return null;
		}
		double filterMultiplier = resolveFilterMultiplier(filter, input.pattern);
		double combinedMultiplier = normalizeExactFilterMultiplier(input.filterMultiplier * filterMultiplier);
		return new PatternEstimateInput(input.pattern, combinedMultiplier);
	}

	public AccessShape accessShapeForJoinOrdering(TupleExpr tupleExpr, Set<String> currentlyBoundVars) {
		if (tupleExpr == null) {
			return null;
		}
		OptimizationScopeState scope = optimizationScope.get();
		if (scope == null) {
			return computeAccessShapeForJoinOrdering(tupleExpr,
					currentlyBoundVars == null ? Collections.emptySet() : currentlyBoundVars);
		}
		long boundVarMask = scope.variableDictionary.maskOf(currentlyBoundVars);
		if (boundVarMask == BOUND_VAR_MASK_OVERFLOW) {
			return computeAccessShapeForJoinOrdering(tupleExpr,
					currentlyBoundVars == null ? Collections.emptySet() : currentlyBoundVars);
		}
		AccessShapeCacheKey key = new AccessShapeCacheKey(tupleExpr, boundVarMask);
		return scope.accessShapeCache.computeIfAbsent(key,
				ignored -> computeAccessShapeForJoinOrdering(tupleExpr, scope, boundVarMask));
	}

	public double factorOutputRowsForJoinOrdering(TupleExpr tupleExpr, Set<String> currentlyBoundVars) {
		TuplePlanEstimate estimate = estimateTupleExprPlan(tupleExpr,
				currentlyBoundVars == null ? Collections.emptySet() : currentlyBoundVars);
		return estimate == null ? -1.0d : estimate.outputRows();
	}

	AccessShape accessShapeForJoinOrdering(TupleExpr tupleExpr, String[] sourceVariableNames,
			long sourceBoundVarMask) {
		if (tupleExpr == null) {
			return null;
		}
		OptimizationScopeState scope = optimizationScope.get();
		if (scope == null) {
			return computeAccessShapeForJoinOrdering(tupleExpr,
					externalVariableMaskSet(sourceVariableNames, sourceBoundVarMask));
		}
		long boundVarMask = scope.variableDictionary.maskOf(sourceVariableNames, sourceBoundVarMask);
		if (boundVarMask == BOUND_VAR_MASK_OVERFLOW) {
			return computeAccessShapeForJoinOrdering(tupleExpr,
					externalVariableMaskSet(sourceVariableNames, sourceBoundVarMask));
		}
		AccessShapeCacheKey key = new AccessShapeCacheKey(tupleExpr, boundVarMask);
		return scope.accessShapeCache.computeIfAbsent(key,
				ignored -> computeAccessShapeForJoinOrdering(tupleExpr, scope, boundVarMask));
	}

	private Set<String> externalVariableMaskSet(String[] sourceVariableNames, long sourceBoundVarMask) {
		if (sourceVariableNames == null || sourceBoundVarMask == 0L) {
			return Set.of();
		}
		return new ExternalVariableMaskSet(sourceVariableNames, sourceBoundVarMask);
	}

	private AccessShape computeAccessShapeForJoinOrdering(TupleExpr tupleExpr, Set<String> currentlyBoundVars) {
		if (tupleExpr instanceof StatementPattern) {
			return buildAccessShape((StatementPattern) tupleExpr, currentlyBoundVars, 1.0d, 0);
		}
		if (tupleExpr instanceof Filter) {
			return computeAccessShapeForJoinOrdering((Filter) tupleExpr, currentlyBoundVars);
		}
		return null;
	}

	private AccessShape computeAccessShapeForJoinOrdering(TupleExpr tupleExpr, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		if (tupleExpr instanceof StatementPattern) {
			return buildAccessShape((StatementPattern) tupleExpr, scope, currentlyBoundVarMask, 1.0d, 0);
		}
		if (tupleExpr instanceof Filter) {
			return computeAccessShapeForJoinOrdering((Filter) tupleExpr, scope, currentlyBoundVarMask);
		}
		return null;
	}

	private AccessShape computeAccessShapeForJoinOrdering(Filter filter, Set<String> currentlyBoundVars) {
		AccessShape accessShape = computeAccessShapeForJoinOrdering(filter.getArg(), currentlyBoundVars);
		if (accessShape == null) {
			return null;
		}
		LookupAnalysis lookupAnalysis = analyzeLookupBindings(accessShape.pattern(), filter.getCondition(),
				currentlyBoundVars);
		double filterMultiplier = resolveFilterMultiplier(filter, accessShape.pattern(), currentlyBoundVars);
		if (filterMultiplier >= 1.0d && lookupAnalysis.multiplier() > 0.0d) {
			filterMultiplier = lookupAnalysis.multiplier();
		}
		double combinedMultiplier = normalizeFilterMultiplier(accessShape.filterMultiplier() * filterMultiplier);
		int combinedLookupComponentMask = accessShape.filterLookupComponentMask()
				| lookupAnalysis.componentMask();
		return buildAccessShape(accessShape.pattern(), currentlyBoundVars, combinedMultiplier,
				combinedLookupComponentMask);
	}

	private AccessShape computeAccessShapeForJoinOrdering(Filter filter, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		AccessShape accessShape = computeAccessShapeForJoinOrdering(filter.getArg(), scope, currentlyBoundVarMask);
		if (accessShape == null) {
			return null;
		}
		LookupAnalysis lookupAnalysis = analyzeLookupBindings(accessShape.pattern(), filter.getCondition(),
				scope, currentlyBoundVarMask);
		double filterMultiplier = resolveFilterMultiplier(filter, accessShape.pattern(), scope, currentlyBoundVarMask);
		if (filterMultiplier >= 1.0d && lookupAnalysis.multiplier() > 0.0d) {
			filterMultiplier = lookupAnalysis.multiplier();
		}
		double combinedMultiplier = normalizeFilterMultiplier(accessShape.filterMultiplier() * filterMultiplier);
		int combinedLookupComponentMask = accessShape.filterLookupComponentMask() | lookupAnalysis.componentMask();
		return buildAccessShape(accessShape.pattern(), scope, currentlyBoundVarMask, combinedMultiplier,
				combinedLookupComponentMask);
	}

	private AccessShape buildAccessShape(StatementPattern pattern, Set<String> currentlyBoundVars,
			double filterMultiplier, int filterLookupComponentMask) {
		StatementPattern patternClone = pattern.clone();
		int patternConstantComponentMask = collectPatternConstantComponentMask(patternClone);
		String[] joinBoundVarNamesByComponent = collectJoinBoundVarNames(patternClone,
				currentlyBoundVars);
		return new AccessShape(patternClone, filterMultiplier, patternConstantComponentMask,
				joinBoundVarNamesByComponent,
				filterLookupComponentMask,
				prefixMask -> estimateAccessRows(patternClone, joinBoundVarNamesByComponent, prefixMask));
	}

	private AccessShape buildAccessShape(StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask, double filterMultiplier, int filterLookupComponentMask) {
		StatementPattern patternClone = pattern.clone();
		int patternConstantComponentMask = collectPatternConstantComponentMask(patternClone);
		String[] joinBoundVarNamesByComponent = collectJoinBoundVarNames(patternClone, scope, currentlyBoundVarMask);
		return new AccessShape(patternClone, filterMultiplier, patternConstantComponentMask,
				joinBoundVarNamesByComponent,
				filterLookupComponentMask,
				prefixMask -> estimateAccessRows(patternClone, joinBoundVarNamesByComponent, prefixMask));
	}

	private int collectPatternConstantComponentMask(StatementPattern pattern) {
		int componentMask = 0;
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var != null && var.hasValue()) {
				componentMask |= 1 << component.ordinal();
			}
		}
		return componentMask;
	}

	private String[] collectJoinBoundVarNames(StatementPattern pattern,
			Set<String> currentlyBoundVars) {
		String[] components = new String[COMPONENT_VALUES.length];
		if (currentlyBoundVars == null || currentlyBoundVars.isEmpty()) {
			return components;
		}
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var == null || var.hasValue() || var.getName() == null || !currentlyBoundVars.contains(var.getName())) {
				continue;
			}
			components[component.ordinal()] = var.getName();
		}
		return components;
	}

	private String[] collectJoinBoundVarNames(StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		String[] components = new String[COMPONENT_VALUES.length];
		if (scope == null || currentlyBoundVarMask == 0L) {
			return components;
		}
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var == null || var.hasValue() || var.getName() == null) {
				continue;
			}
			int id = scope.variableDictionary.idIfKnown(var.getName());
			if (id != VariableDictionary.NO_ID && (currentlyBoundVarMask & scope.variableDictionary.bit(id)) != 0L) {
				components[component.ordinal()] = var.getName();
			}
		}
		return components;
	}

	private double estimateAccessRows(StatementPattern pattern, String[] joinBoundVarNamesByComponent,
			int prefixComponentMask) {
		StatementPattern accessPattern = patternForAccessPrefix(pattern, prefixComponentMask);
		OptimizationScopeState scope = optimizationScope.get();
		TuplePlanEstimate estimate;
		if (scope == null) {
			estimate = estimateTupleExprPlan(accessPattern,
					boundVarNamesForAccessPrefix(joinBoundVarNamesByComponent, prefixComponentMask));
		} else {
			long boundVarMask = boundVarMaskForAccessPrefix(scope, joinBoundVarNamesByComponent, prefixComponentMask);
			estimate = boundVarMask == BOUND_VAR_MASK_OVERFLOW
					? estimateTupleExprPlan(accessPattern,
							boundVarNamesForAccessPrefix(joinBoundVarNamesByComponent, prefixComponentMask))
					: estimateTupleExprPlan(accessPattern, boundVarMask);
		}
		if (estimate == null) {
			return 0.0d;
		}
		return estimate.outputRows();
	}

	private long boundVarMaskForAccessPrefix(OptimizationScopeState scope,
			String[] joinBoundVarNamesByComponent,
			int prefixComponentMask) {
		if (scope == null || prefixComponentMask == 0) {
			return 0L;
		}
		long mask = 0L;
		for (Component component : COMPONENT_VALUES) {
			if ((prefixComponentMask & (1 << component.ordinal())) == 0) {
				continue;
			}
			String varName = joinBoundVarNamesByComponent[component.ordinal()];
			if (varName == null) {
				continue;
			}
			int id = scope.variableDictionary.id(varName);
			long bit = scope.variableDictionary.bit(id);
			if (bit == 0L) {
				return BOUND_VAR_MASK_OVERFLOW;
			}
			mask |= bit;
		}
		return mask;
	}

	private Set<String> boundVarNamesForAccessPrefix(String[] joinBoundVarNamesByComponent,
			int prefixComponentMask) {
		if (prefixComponentMask == 0) {
			return Set.of();
		}
		String[] names = new String[COMPONENT_VALUES.length];
		int count = 0;
		for (Component component : COMPONENT_VALUES) {
			if ((prefixComponentMask & (1 << component.ordinal())) == 0) {
				continue;
			}
			String varName = joinBoundVarNamesByComponent[component.ordinal()];
			if (varName == null || containsName(names, count, varName)) {
				continue;
			}
			names[count++] = varName;
		}
		switch (count) {
		case 0:
			return Set.of();
		case 1:
			return Set.of(names[0]);
		case 2:
			return Set.of(names[0], names[1]);
		case 3:
			return Set.of(names[0], names[1], names[2]);
		default:
			return Set.of(names[0], names[1], names[2], names[3]);
		}
	}

	private static boolean containsName(String[] names, int count, String name) {
		for (int i = 0; i < count; i++) {
			if (name.equals(names[i])) {
				return true;
			}
		}
		return false;
	}

	private StatementPattern patternForAccessPrefix(StatementPattern pattern, int prefixComponentMask) {
		StatementPattern accessPattern = pattern.clone();
		for (Component component : COMPONENT_VALUES) {
			if ((prefixComponentMask & (1 << component.ordinal())) != 0) {
				continue;
			}
			Var var = varForComponent(accessPattern, component);
			if (var != null && var.hasValue()) {
				accessPattern.replaceChildNode(var, unboundCopy(var));
			}
		}
		return accessPattern;
	}

	private Var unboundCopy(Var var) {
		return Var.of(var.getName(), null, var.isAnonymous(), false);
	}

	private LookupAnalysis analyzeLookupBindings(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars) {
		if (condition == null) {
			return LookupAnalysis.none();
		}
		if (condition instanceof And) {
			And and = (And) condition;
			return combineLookupAnalyses(analyzeLookupBindings(pattern, and.getLeftArg(), currentlyBoundVars),
					analyzeLookupBindings(pattern, and.getRightArg(), currentlyBoundVars));
		}
		LookupAnalysis listMember = analyzeListMemberLookup(pattern, condition, currentlyBoundVars);
		if (!listMember.isNone()) {
			return listMember;
		}
		LookupAnalysis disjunction = analyzeDisjunctiveEqualityLookup(pattern, condition, currentlyBoundVars);
		if (!disjunction.isNone()) {
			return disjunction;
		}
		return analyzeEqualityLookup(pattern, condition, currentlyBoundVars);
	}

	private LookupAnalysis analyzeLookupBindings(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask) {
		if (condition == null) {
			return LookupAnalysis.none();
		}
		if (condition instanceof And) {
			And and = (And) condition;
			return combineLookupAnalyses(analyzeLookupBindings(pattern, and.getLeftArg(), scope, currentlyBoundVarMask),
					analyzeLookupBindings(pattern, and.getRightArg(), scope, currentlyBoundVarMask));
		}
		LookupAnalysis listMember = analyzeListMemberLookup(pattern, condition, scope, currentlyBoundVarMask);
		if (!listMember.isNone()) {
			return listMember;
		}
		LookupAnalysis disjunction = analyzeDisjunctiveEqualityLookup(pattern, condition, scope,
				currentlyBoundVarMask);
		if (!disjunction.isNone()) {
			return disjunction;
		}
		return analyzeEqualityLookup(pattern, condition, scope, currentlyBoundVarMask);
	}

	private LookupAnalysis combineLookupAnalyses(LookupAnalysis left, LookupAnalysis right) {
		if (left.isNone()) {
			return right;
		}
		if (right.isNone()) {
			return left;
		}
		int componentMask = left.componentMask() | right.componentMask();
		double multiplier = left.multiplier() > 0.0d && right.multiplier() > 0.0d
				? normalizeFilterMultiplier(left.multiplier() * right.multiplier())
				: Math.max(left.multiplier(), right.multiplier());
		return new LookupAnalysis(componentMask, multiplier);
	}

	private LookupAnalysis analyzeListMemberLookup(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars) {
		if (!(condition instanceof ListMemberOperator)) {
			return LookupAnalysis.none();
		}

		List<ValueExpr> arguments = ((ListMemberOperator) condition).getArguments();
		if (arguments == null || arguments.size() < 2 || !(arguments.get(0)instanceof Var listedVar)
				|| listedVar.getName() == null) {
			return LookupAnalysis.none();
		}

		Component component = findPatternComponentByVarName(pattern, listedVar.getName());
		if (component == null) {
			return LookupAnalysis.none();
		}

		Set<String> lookupKeys = new HashSet<>();
		for (int i = 1; i < arguments.size(); i++) {
			String lookupKey = lookupKey(arguments.get(i), currentlyBoundVars);
			if (lookupKey == null) {
				return LookupAnalysis.none();
			}
			lookupKeys.add(lookupKey);
		}
		if (lookupKeys.isEmpty()) {
			return LookupAnalysis.none();
		}
		return lookupAnalysisFor(pattern, component, lookupKeys.size());
	}

	private LookupAnalysis analyzeListMemberLookup(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask) {
		if (!(condition instanceof ListMemberOperator)) {
			return LookupAnalysis.none();
		}

		List<ValueExpr> arguments = ((ListMemberOperator) condition).getArguments();
		if (arguments == null || arguments.size() < 2 || !(arguments.get(0)instanceof Var listedVar)
				|| listedVar.getName() == null) {
			return LookupAnalysis.none();
		}

		Component component = findPatternComponentByVarName(pattern, listedVar.getName());
		if (component == null) {
			return LookupAnalysis.none();
		}

		Set<String> lookupKeys = new HashSet<>();
		for (int i = 1; i < arguments.size(); i++) {
			String lookupKey = lookupKey(arguments.get(i), scope, currentlyBoundVarMask);
			if (lookupKey == null) {
				return LookupAnalysis.none();
			}
			lookupKeys.add(lookupKey);
		}
		if (lookupKeys.isEmpty()) {
			return LookupAnalysis.none();
		}
		return lookupAnalysisFor(pattern, component, lookupKeys.size());
	}

	private LookupAnalysis analyzeDisjunctiveEqualityLookup(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars) {
		List<LookupValueCount> alternatives = new ArrayList<>();
		if (!collectDisjunctiveEqualityAlternatives(pattern, condition, currentlyBoundVars, alternatives)
				|| alternatives.isEmpty()) {
			return LookupAnalysis.none();
		}
		Component component = alternatives.get(0).component();
		int valueCount = 0;
		for (LookupValueCount alternative : alternatives) {
			if (alternative.component() != component) {
				return LookupAnalysis.none();
			}
			valueCount += alternative.valueCount();
		}
		return lookupAnalysisFor(pattern, component, valueCount);
	}

	private LookupAnalysis analyzeDisjunctiveEqualityLookup(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask) {
		List<LookupValueCount> alternatives = new ArrayList<>();
		if (!collectDisjunctiveEqualityAlternatives(pattern, condition, scope, currentlyBoundVarMask, alternatives)
				|| alternatives.isEmpty()) {
			return LookupAnalysis.none();
		}
		Component component = alternatives.get(0).component();
		int valueCount = 0;
		for (LookupValueCount alternative : alternatives) {
			if (alternative.component() != component) {
				return LookupAnalysis.none();
			}
			valueCount += alternative.valueCount();
		}
		return lookupAnalysisFor(pattern, component, valueCount);
	}

	private boolean collectDisjunctiveEqualityAlternatives(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars, List<LookupValueCount> alternatives) {
		if (condition instanceof Or) {
			Or or = (Or) condition;
			return collectDisjunctiveEqualityAlternatives(pattern, or.getLeftArg(), currentlyBoundVars, alternatives)
					&& collectDisjunctiveEqualityAlternatives(pattern, or.getRightArg(), currentlyBoundVars,
							alternatives);
		}
		LookupValueCount alternative = lookupValueCountForEquality(pattern, condition, currentlyBoundVars);
		if (alternative == null) {
			return false;
		}
		alternatives.add(alternative);
		return true;
	}

	private boolean collectDisjunctiveEqualityAlternatives(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask, List<LookupValueCount> alternatives) {
		if (condition instanceof Or) {
			Or or = (Or) condition;
			return collectDisjunctiveEqualityAlternatives(pattern, or.getLeftArg(), scope, currentlyBoundVarMask,
					alternatives)
					&& collectDisjunctiveEqualityAlternatives(pattern, or.getRightArg(), scope, currentlyBoundVarMask,
							alternatives);
		}
		LookupValueCount alternative = lookupValueCountForEquality(pattern, condition, scope, currentlyBoundVarMask);
		if (alternative == null) {
			return false;
		}
		alternatives.add(alternative);
		return true;
	}

	private LookupAnalysis analyzeEqualityLookup(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars) {
		LookupValueCount lookupValue = lookupValueCountForEquality(pattern, condition, currentlyBoundVars);
		if (lookupValue == null) {
			return LookupAnalysis.none();
		}
		return lookupAnalysisFor(pattern, lookupValue.component(), lookupValue.valueCount());
	}

	private LookupAnalysis analyzeEqualityLookup(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask) {
		LookupValueCount lookupValue = lookupValueCountForEquality(pattern, condition, scope, currentlyBoundVarMask);
		if (lookupValue == null) {
			return LookupAnalysis.none();
		}
		return lookupAnalysisFor(pattern, lookupValue.component(), lookupValue.valueCount());
	}

	private LookupValueCount lookupValueCountForEquality(StatementPattern pattern, ValueExpr condition,
			Set<String> currentlyBoundVars) {
		if (condition instanceof Compare compare) {
			if (compare.getOperator() != Compare.CompareOp.EQ) {
				return null;
			}
			return lookupValueCountForEquality(pattern, compare.getLeftArg(), compare.getRightArg(), currentlyBoundVars,
					compare.getRightArg(), compare.getLeftArg());
		}
		if (condition instanceof SameTerm sameTerm) {
			return lookupValueCountForEquality(pattern, sameTerm.getLeftArg(), sameTerm.getRightArg(),
					currentlyBoundVars,
					sameTerm.getRightArg(), sameTerm.getLeftArg());
		}
		return null;
	}

	private LookupValueCount lookupValueCountForEquality(StatementPattern pattern, ValueExpr condition,
			OptimizationScopeState scope, long currentlyBoundVarMask) {
		if (condition instanceof Compare compare) {
			if (compare.getOperator() != Compare.CompareOp.EQ) {
				return null;
			}
			return lookupValueCountForEquality(pattern, compare.getLeftArg(), compare.getRightArg(), scope,
					currentlyBoundVarMask, compare.getRightArg(), compare.getLeftArg());
		}
		if (condition instanceof SameTerm sameTerm) {
			return lookupValueCountForEquality(pattern, sameTerm.getLeftArg(), sameTerm.getRightArg(), scope,
					currentlyBoundVarMask,
					sameTerm.getRightArg(), sameTerm.getLeftArg());
		}
		return null;
	}

	private LookupValueCount lookupValueCountForEquality(StatementPattern pattern, ValueExpr leftVarCandidate,
			ValueExpr rightValueCandidate, Set<String> currentlyBoundVars, ValueExpr rightVarCandidate,
			ValueExpr leftValueCandidate) {
		LookupValueCount left = lookupValueCountForVarBinding(pattern, leftVarCandidate, rightValueCandidate,
				currentlyBoundVars);
		if (left != null) {
			return left;
		}
		return lookupValueCountForVarBinding(pattern, rightVarCandidate, leftValueCandidate, currentlyBoundVars);
	}

	private LookupValueCount lookupValueCountForEquality(StatementPattern pattern, ValueExpr leftVarCandidate,
			ValueExpr rightValueCandidate, OptimizationScopeState scope, long currentlyBoundVarMask,
			ValueExpr rightVarCandidate,
			ValueExpr leftValueCandidate) {
		LookupValueCount left = lookupValueCountForVarBinding(pattern, leftVarCandidate, rightValueCandidate,
				scope, currentlyBoundVarMask);
		if (left != null) {
			return left;
		}
		return lookupValueCountForVarBinding(pattern, rightVarCandidate, leftValueCandidate, scope,
				currentlyBoundVarMask);
	}

	private LookupValueCount lookupValueCountForVarBinding(StatementPattern pattern, ValueExpr maybePatternVarExpr,
			ValueExpr maybeLookupExpr, Set<String> currentlyBoundVars) {
		if (!(maybePatternVarExpr instanceof Var patternVar) || patternVar.getName() == null) {
			return null;
		}
		Component component = findPatternComponentByVarName(pattern, patternVar.getName());
		if (component == null || lookupKey(maybeLookupExpr, currentlyBoundVars) == null) {
			return null;
		}
		return new LookupValueCount(component, 1);
	}

	private LookupValueCount lookupValueCountForVarBinding(StatementPattern pattern, ValueExpr maybePatternVarExpr,
			ValueExpr maybeLookupExpr, OptimizationScopeState scope, long currentlyBoundVarMask) {
		if (!(maybePatternVarExpr instanceof Var patternVar) || patternVar.getName() == null) {
			return null;
		}
		Component component = findPatternComponentByVarName(pattern, patternVar.getName());
		if (component == null || lookupKey(maybeLookupExpr, scope, currentlyBoundVarMask) == null) {
			return null;
		}
		return new LookupValueCount(component, 1);
	}

	private LookupAnalysis lookupAnalysisFor(StatementPattern pattern, Component component, int valueCount) {
		if (component == null || valueCount <= 0) {
			return LookupAnalysis.none();
		}
		double multiplier = estimateLookupFilterMultiplier(pattern, component, valueCount);
		return new LookupAnalysis(1 << component.ordinal(), multiplier);
	}

	private double estimateLookupFilterMultiplier(StatementPattern pattern, Component component, int valueCount) {
		JoinEstimate estimate = estimate(component,
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()));
		double distinct = estimate.distinct;
		if (!Double.isFinite(distinct) || distinct <= 0.0d) {
			return -1.0d;
		}
		double ratio = valueCount / Math.max(1.0d, distinct);
		if (!Double.isFinite(ratio) || ratio <= 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(Math.min(1.0d, ratio));
	}

	private String lookupKey(ValueExpr valueExpr, Set<String> currentlyBoundVars) {
		if (valueExpr instanceof ValueConstant constant && constant.getValue() != null) {
			return "value:" + constant.getValue().stringValue();
		}
		if (valueExpr instanceof Var var && var.getName() != null && currentlyBoundVars.contains(var.getName())) {
			return "var:" + var.getName();
		}
		return null;
	}

	private String lookupKey(ValueExpr valueExpr, OptimizationScopeState scope, long currentlyBoundVarMask) {
		if (valueExpr instanceof ValueConstant constant && constant.getValue() != null) {
			return "value:" + constant.getValue().stringValue();
		}
		if (valueExpr instanceof Var var && var.getName() != null && scope != null) {
			int id = scope.variableDictionary.idIfKnown(var.getName());
			if (id != VariableDictionary.NO_ID && (currentlyBoundVarMask & scope.variableDictionary.bit(id)) != 0L) {
				return "var:" + var.getName();
			}
		}
		return null;
	}

	private double resolveFilterMultiplier(Filter filter, StatementPattern pattern) {
		double knownMultiplier = estimateKnownFilterMultiplier(filter, pattern);
		return knownMultiplier >= 0.0d ? knownMultiplier : 1.0d;
	}

	private double resolveFilterMultiplier(Filter filter, StatementPattern pattern, Set<String> currentlyBoundVars) {
		double knownMultiplier = estimateKnownFilterMultiplier(filter, pattern, currentlyBoundVars);
		return knownMultiplier >= 0.0d ? knownMultiplier : 1.0d;
	}

	private double resolveFilterMultiplier(Filter filter, StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		double knownMultiplier = estimateKnownFilterMultiplier(filter, pattern, scope, currentlyBoundVarMask);
		return knownMultiplier >= 0.0d ? knownMultiplier : 1.0d;
	}

	private double resolveFilterMultiplier(Filter filter, TuplePlanEstimate estimate) {
		if (filter.getCondition() == null || estimate == null) {
			return 1.0d;
		}
		StatementPattern patternLocalBase = basePatternForFilter(filter);
		if (patternLocalBase != null) {
			double knownMultiplier = estimateKnownFilterMultiplier(filter, patternLocalBase);
			if (knownMultiplier >= 0.0d) {
				return knownMultiplier;
			}
		}
		Set<String> conditionVars = VarNameCollector.process(filter.getCondition());
		if (conditionVars.isEmpty()) {
			return 1.0d;
		}
		Set<String> bindingNames = filter.getArg().getBindingNames();
		for (String conditionVar : conditionVars) {
			if (bindingNames.contains(conditionVar)) {
				double heuristicMultiplier = estimateHeuristicFilterMultiplier(estimate, filter.getCondition());
				return heuristicMultiplier > 0.0d ? heuristicMultiplier : 1.0d;
			}
		}
		return 1.0d;
	}

	private double resolveLearnedFilterMultiplier(Filter filter, StatementPattern pattern) {
		return resolveLearnedFilterMultiplier(filter, pattern, 0);
	}

	private double resolveLearnedFilterMultiplier(Filter filter, StatementPattern pattern,
			Set<String> currentlyBoundVars) {
		return resolveLearnedFilterMultiplier(filter, pattern, localBoundComponentMask(pattern, currentlyBoundVars));
	}

	private double resolveLearnedFilterMultiplier(Filter filter, StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		return resolveLearnedFilterMultiplier(filter, pattern,
				localBoundComponentMask(pattern, scope, currentlyBoundVarMask));
	}

	private double resolveLearnedFilterMultiplier(Filter filter, StatementPattern pattern,
			int localBoundComponentMask) {
		JoinStatsProvider statsProvider = learnedStatsProvider;
		if (statsProvider == null || filter.getCondition() == null) {
			return -1.0d;
		}
		PatternKey patternKey = FilterSelectivityKeys.patternKeyFor(pattern);
		if (patternKey == null) {
			return -1.0d;
		}
		String filterKey = qualifiedFilterKey(filter, localBoundComponentMask);
		double ratio = statsProvider.getFilterPassRatio(patternKey, filterKey);
		if (isValidFilterMultiplier(ratio)) {
			return normalizeExactFilterMultiplier(ratio);
		}
		ratio = statsProvider.getFilterPassRatio(patternKey, FilterSelectivityKeys.filterKeyFor(filter.getCondition()));
		if (isValidFilterMultiplier(ratio)) {
			return normalizeExactFilterMultiplier(ratio);
		}
		String templateKey = qualifiedFilterTemplateKey(filter, pattern, localBoundComponentMask);
		if (templateKey != null) {
			ratio = statsProvider.getFilterTemplatePassRatio(patternKey, templateKey);
			if (isValidFilterMultiplier(ratio)) {
				return normalizeExactFilterMultiplier(ratio);
			}
		}
		String unconditionalTemplateKey = FilterSelectivityKeys.filterTemplateKeyFor(filter.getCondition(), pattern);
		if (unconditionalTemplateKey != null) {
			ratio = statsProvider.getFilterTemplatePassRatio(patternKey, unconditionalTemplateKey);
			if (isValidFilterMultiplier(ratio)) {
				return normalizeExactFilterMultiplier(ratio);
			}
		}
		ratio = statsProvider.getPatternPassRatio(patternKey);
		if (isValidFilterMultiplier(ratio)) {
			return normalizeExactFilterMultiplier(ratio);
		}
		return -1.0d;
	}

	private double resolveSampledFilterMultiplier(Filter filter, StatementPattern pattern) {
		PatternFilterSampleEstimate estimate = resolveSampledFilterEstimate(filter, pattern);
		return estimate == null || !isValidFilterMultiplier(estimate.getPassRatio())
				? -1.0d
				: normalizeExactFilterMultiplier(estimate.getPassRatio());
	}

	private PatternFilterSampleEstimate resolveSampledFilterEstimate(Filter filter, StatementPattern pattern) {
		PatternFilterSamplingEstimator samplingEstimator = patternFilterSamplingEstimator;
		if (samplingEstimator == null || filter == null || filter.getCondition() == null || pattern == null) {
			return null;
		}
		return samplingEstimator.estimateFilterPass(filter, pattern);
	}

	private double estimateKnownFilterMultiplier(Filter filter, StatementPattern pattern) {
		if (filter == null || filter.getCondition() == null || pattern == null
				|| !FilterSelectivityKeys.conditionIntersectsPattern(filter.getCondition(), pattern)) {
			return -1.0d;
		}
		double learnedMultiplier = resolveLearnedFilterMultiplier(filter, pattern);
		if (learnedMultiplier >= 0.0d) {
			return learnedMultiplier;
		}
		double sampledMultiplier = resolveSampledFilterMultiplier(filter, pattern);
		if (sampledMultiplier >= 0.0d) {
			return sampledMultiplier;
		}
		double heuristicMultiplier = estimateHeuristicFilterMultiplier(filter, pattern);
		if (heuristicMultiplier > 0.0d) {
			return heuristicMultiplier;
		}
		return -1.0d;
	}

	private double estimateKnownFilterMultiplier(Filter filter, StatementPattern pattern,
			Set<String> currentlyBoundVars) {
		if (filter == null || filter.getCondition() == null || pattern == null
				|| !FilterSelectivityKeys.conditionIntersectsPattern(filter.getCondition(), pattern)) {
			return -1.0d;
		}
		double learnedMultiplier = resolveLearnedFilterMultiplier(filter, pattern, currentlyBoundVars);
		if (learnedMultiplier >= 0.0d) {
			return learnedMultiplier;
		}
		double sampledMultiplier = resolveSampledFilterMultiplier(filter, pattern);
		if (sampledMultiplier >= 0.0d) {
			return sampledMultiplier;
		}
		double heuristicMultiplier = estimateHeuristicFilterMultiplier(filter, pattern);
		if (heuristicMultiplier > 0.0d) {
			return heuristicMultiplier;
		}
		return -1.0d;
	}

	private double estimateKnownFilterMultiplier(Filter filter, StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		if (filter == null || filter.getCondition() == null || pattern == null
				|| !FilterSelectivityKeys.conditionIntersectsPattern(filter.getCondition(), pattern)) {
			return -1.0d;
		}
		double learnedMultiplier = resolveLearnedFilterMultiplier(filter, pattern, scope, currentlyBoundVarMask);
		if (learnedMultiplier >= 0.0d) {
			return learnedMultiplier;
		}
		double sampledMultiplier = resolveSampledFilterMultiplier(filter, pattern);
		if (sampledMultiplier >= 0.0d) {
			return sampledMultiplier;
		}
		double heuristicMultiplier = estimateHeuristicFilterMultiplier(filter, pattern);
		if (heuristicMultiplier > 0.0d) {
			return heuristicMultiplier;
		}
		return -1.0d;
	}

	private String qualifiedFilterKey(Filter filter, int localBoundComponentMask) {
		return FilterSelectivityKeys.qualifyFilterKey(FilterSelectivityKeys.filterKeyFor(filter.getCondition()),
				localBoundComponentMask);
	}

	private String qualifiedFilterTemplateKey(Filter filter, StatementPattern pattern, int localBoundComponentMask) {
		return FilterSelectivityKeys.qualifyFilterKey(
				FilterSelectivityKeys.filterTemplateKeyFor(filter.getCondition(), pattern),
				localBoundComponentMask);
	}

	private int localBoundComponentMask(StatementPattern pattern, Set<String> currentlyBoundVars) {
		if (pattern == null || currentlyBoundVars == null || currentlyBoundVars.isEmpty()) {
			return 0;
		}
		int componentMask = 0;
		componentMask |= localBoundComponentMask(pattern.getSubjectVar(), currentlyBoundVars, Component.S);
		componentMask |= localBoundComponentMask(pattern.getPredicateVar(), currentlyBoundVars, Component.P);
		componentMask |= localBoundComponentMask(pattern.getObjectVar(), currentlyBoundVars, Component.O);
		componentMask |= localBoundComponentMask(pattern.getContextVar(), currentlyBoundVars, Component.C);
		return componentMask;
	}

	private int localBoundComponentMask(StatementPattern pattern, OptimizationScopeState scope,
			long currentlyBoundVarMask) {
		if (pattern == null || scope == null || currentlyBoundVarMask == 0L) {
			return 0;
		}
		int componentMask = 0;
		componentMask |= localBoundComponentMask(pattern.getSubjectVar(), scope, currentlyBoundVarMask, Component.S);
		componentMask |= localBoundComponentMask(pattern.getPredicateVar(), scope, currentlyBoundVarMask, Component.P);
		componentMask |= localBoundComponentMask(pattern.getObjectVar(), scope, currentlyBoundVarMask, Component.O);
		componentMask |= localBoundComponentMask(pattern.getContextVar(), scope, currentlyBoundVarMask, Component.C);
		return componentMask;
	}

	private int localBoundComponentMask(Var var, Set<String> currentlyBoundVars, Component component) {
		if (var == null || var.hasValue() || var.getName() == null || !currentlyBoundVars.contains(var.getName())) {
			return 0;
		}
		return 1 << component.ordinal();
	}

	private int localBoundComponentMask(Var var, OptimizationScopeState scope, long currentlyBoundVarMask,
			Component component) {
		if (var == null || var.hasValue() || var.getName() == null || scope == null) {
			return 0;
		}
		int id = scope.variableDictionary.idIfKnown(var.getName());
		if (id == VariableDictionary.NO_ID || (currentlyBoundVarMask & scope.variableDictionary.bit(id)) == 0L) {
			return 0;
		}
		return 1 << component.ordinal();
	}

	private StatementPattern basePatternForFilter(Filter filter) {
		return FilterSelectivityKeys.patternLocalBaseForFilter(filter);
	}

	private double estimateHeuristicFilterMultiplier(Filter filter, StatementPattern pattern) {
		if (filter.getCondition() == null) {
			return -1.0d;
		}
		double listMemberMultiplier = estimateListMemberFilterMultiplier(pattern, filter.getCondition());
		if (listMemberMultiplier > 0.0d) {
			return listMemberMultiplier;
		}
		double baseRows = estimatePatternRows(pattern);
		if (!(baseRows > 0.0d) || !Double.isFinite(baseRows)) {
			return -1.0d;
		}
		StatementPattern narrowedPattern = pattern.clone();
		if (!bindSimpleFilterCondition(narrowedPattern, filter.getCondition())) {
			return -1.0d;
		}
		double narrowedRows = estimatePatternRows(narrowedPattern);
		if (narrowedRows < 0.0d || !Double.isFinite(narrowedRows)) {
			return -1.0d;
		}
		double ratio = narrowedRows / baseRows;
		if (!Double.isFinite(ratio) || ratio < 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(ratio);
	}

	private double estimateHeuristicFilterMultiplier(TuplePlanEstimate estimate, ValueExpr condition) {
		if (condition == null || estimate == null) {
			return -1.0d;
		}
		if (condition instanceof And) {
			And and = (And) condition;
			double left = estimateHeuristicFilterMultiplier(estimate, and.getLeftArg());
			double right = estimateHeuristicFilterMultiplier(estimate, and.getRightArg());
			if (left > 0.0d && right > 0.0d) {
				return normalizeFilterMultiplier(left * right);
			}
			return left > 0.0d ? left : right;
		}

		double listMemberMultiplier = estimateListMemberFilterMultiplier(estimate, condition);
		if (listMemberMultiplier > 0.0d) {
			return listMemberMultiplier;
		}

		double equalityMultiplier = estimateEqualityFilterMultiplier(estimate, condition);
		if (equalityMultiplier > 0.0d) {
			return equalityMultiplier;
		}
		return -1.0d;
	}

	private double estimateListMemberFilterMultiplier(StatementPattern pattern, ValueExpr condition) {
		if (condition instanceof And) {
			And and = (And) condition;
			double left = estimateListMemberFilterMultiplier(pattern, and.getLeftArg());
			double right = estimateListMemberFilterMultiplier(pattern, and.getRightArg());
			if (left > 0.0d && right > 0.0d) {
				return normalizeFilterMultiplier(left * right);
			}
			return left > 0.0d ? left : right;
		}
		if (!(condition instanceof ListMemberOperator)) {
			return -1.0d;
		}

		List<ValueExpr> arguments = ((ListMemberOperator) condition).getArguments();
		if (arguments == null || arguments.size() < 2 || !(arguments.get(0) instanceof Var)) {
			return -1.0d;
		}
		Var listedVar = (Var) arguments.get(0);
		if (listedVar.getName() == null) {
			return -1.0d;
		}

		Set<Value> constants = new HashSet<>();
		for (int i = 1; i < arguments.size(); i++) {
			ValueExpr argument = arguments.get(i);
			if (!(argument instanceof ValueConstant)) {
				return -1.0d;
			}
			Value value = ((ValueConstant) argument).getValue();
			if (value == null) {
				return -1.0d;
			}
			constants.add(value);
		}
		if (constants.isEmpty()) {
			return -1.0d;
		}

		Var patternVar = findUnboundVarByName(pattern, listedVar.getName());
		if (patternVar == null) {
			return -1.0d;
		}

		JoinEstimate estimate = estimate(getComponent(pattern, patternVar),
				getValueOrNull(pattern.getSubjectVar()),
				getValueOrNull(pattern.getPredicateVar()),
				getValueOrNull(pattern.getObjectVar()),
				getValueOrNull(pattern.getContextVar()));
		double distinct = estimate.distinct;
		if (!Double.isFinite(distinct) || distinct <= 0.0d) {
			return -1.0d;
		}

		double ratio = constants.size() / Math.max(1.0d, distinct);
		if (!Double.isFinite(ratio) || ratio <= 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(Math.min(1.0d, ratio));
	}

	private double estimateListMemberFilterMultiplier(TuplePlanEstimate estimate, ValueExpr condition) {
		if (!(condition instanceof ListMemberOperator)) {
			return -1.0d;
		}

		List<ValueExpr> arguments = ((ListMemberOperator) condition).getArguments();
		if (arguments == null || arguments.size() < 2 || !(arguments.get(0) instanceof Var)) {
			return -1.0d;
		}
		Var listedVar = (Var) arguments.get(0);
		if (listedVar.getName() == null) {
			return -1.0d;
		}

		Set<Value> constants = new HashSet<>();
		for (int i = 1; i < arguments.size(); i++) {
			ValueExpr argument = arguments.get(i);
			if (!(argument instanceof ValueConstant)) {
				return -1.0d;
			}
			Value value = ((ValueConstant) argument).getValue();
			if (value == null) {
				return -1.0d;
			}
			constants.add(value);
		}
		if (constants.isEmpty()) {
			return -1.0d;
		}

		VarPlanStats stats = estimate.varStats.get(listedVar.getName());
		if (stats == null || !Double.isFinite(stats.distinct) || stats.distinct <= 0.0d) {
			return -1.0d;
		}

		double ratio = constants.size() / Math.max(1.0d, stats.distinct);
		if (!Double.isFinite(ratio) || ratio <= 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(Math.min(1.0d, ratio));
	}

	private double estimateEqualityFilterMultiplier(TuplePlanEstimate estimate, ValueExpr condition) {
		if (condition instanceof Compare) {
			Compare compare = (Compare) condition;
			if (compare.getOperator() != Compare.CompareOp.EQ) {
				return -1.0d;
			}
			double varEqualityMultiplier = estimateVarToVarFilterMultiplier(estimate, compare.getLeftArg(),
					compare.getRightArg());
			if (varEqualityMultiplier > 0.0d) {
				return varEqualityMultiplier;
			}
			return estimateVarToConstantFilterMultiplier(estimate, compare.getLeftArg(), compare.getRightArg(),
					compare.getRightArg(), compare.getLeftArg());
		}
		if (condition instanceof SameTerm) {
			SameTerm sameTerm = (SameTerm) condition;
			double varEqualityMultiplier = estimateVarToVarFilterMultiplier(estimate, sameTerm.getLeftArg(),
					sameTerm.getRightArg());
			if (varEqualityMultiplier > 0.0d) {
				return varEqualityMultiplier;
			}
			return estimateVarToConstantFilterMultiplier(estimate, sameTerm.getLeftArg(), sameTerm.getRightArg(),
					sameTerm.getRightArg(), sameTerm.getLeftArg());
		}
		return -1.0d;
	}

	private double estimateVarToVarFilterMultiplier(TuplePlanEstimate estimate, ValueExpr leftExpr,
			ValueExpr rightExpr) {
		if (!(leftExpr instanceof Var leftVar) || !(rightExpr instanceof Var rightVar)
				|| leftVar.getName() == null || rightVar.getName() == null) {
			return -1.0d;
		}
		if (leftVar.getName().equals(rightVar.getName())) {
			return 1.0d;
		}
		VarPlanStats leftStats = estimate.varStats.get(leftVar.getName());
		VarPlanStats rightStats = estimate.varStats.get(rightVar.getName());
		if (leftStats == null || rightStats == null
				|| !Double.isFinite(leftStats.distinct) || !Double.isFinite(rightStats.distinct)
				|| leftStats.distinct <= 0.0d || rightStats.distinct <= 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(1.0d / Math.max(1.0d,
				Math.max(leftStats.distinct, rightStats.distinct)));
	}

	private double estimateVarToConstantFilterMultiplier(TuplePlanEstimate estimate, ValueExpr leftVarCandidate,
			ValueExpr rightValueCandidate, ValueExpr rightVarCandidate, ValueExpr leftValueCandidate) {
		double left = estimateVarToConstantFilterMultiplier(estimate, leftVarCandidate, rightValueCandidate);
		if (left > 0.0d) {
			return left;
		}
		return estimateVarToConstantFilterMultiplier(estimate, rightVarCandidate, leftValueCandidate);
	}

	private double estimateVarToConstantFilterMultiplier(TuplePlanEstimate estimate, ValueExpr maybeVarExpr,
			ValueExpr maybeValueExpr) {
		if (!(maybeVarExpr instanceof Var) || !(maybeValueExpr instanceof ValueConstant)) {
			return -1.0d;
		}
		Var filterVar = (Var) maybeVarExpr;
		ValueConstant constant = (ValueConstant) maybeValueExpr;
		if (filterVar.getName() == null || constant.getValue() == null) {
			return -1.0d;
		}
		VarPlanStats stats = estimate.varStats.get(filterVar.getName());
		if (stats == null || !Double.isFinite(stats.distinct) || stats.distinct <= 0.0d) {
			return -1.0d;
		}
		return normalizeFilterMultiplier(1.0d / Math.max(1.0d, stats.distinct));
	}

	private boolean isValidFilterMultiplier(double value) {
		return Double.isFinite(value) && value >= 0.0d && value <= 1.0d;
	}

	private double normalizeFilterMultiplier(double value) {
		if (!Double.isFinite(value) || value < 0.0d) {
			return 1.0d;
		}
		if (value == 0.0d) {
			return 0.0d;
		}
		return Math.max(MIN_FILTER_MULTIPLIER, Math.min(1.0d, value));
	}

	private double normalizeExactFilterMultiplier(double value) {
		if (!Double.isFinite(value) || value < 0.0d) {
			return 1.0d;
		}
		return Math.min(1.0d, value);
	}

	private double applyFilterMultiplier(double rows, double multiplier) {
		if (!Double.isFinite(rows)) {
			return rows;
		}
		if (!Double.isFinite(multiplier) || multiplier < 0.0d || multiplier >= 1.0d) {
			return rows;
		}
		return rows * normalizeExactFilterMultiplier(multiplier);
	}

	private TuplePlanEstimate applySubtreeFilterMultiplier(TuplePlanEstimate estimate, double multiplier) {
		if (estimate == null || !Double.isFinite(multiplier) || multiplier < 0.0d || multiplier >= 1.0d) {
			return estimate;
		}
		double filteredRows = normalizeRows(applyFilterMultiplier(estimate.outputRows, multiplier));
		Map<String, VarPlanStats> filteredStats = newVarStatsMap();
		for (Map.Entry<String, VarPlanStats> entry : estimate.varStats.entrySet()) {
			filteredStats.put(entry.getKey(),
					new VarPlanStats(clampDistinct(entry.getValue().distinct, filteredRows), null));
		}
		return new TuplePlanEstimate(filteredRows, filteredRows, 1.0d, filteredStats);
	}

	private boolean bindSimpleFilterCondition(StatementPattern pattern, ValueExpr condition) {
		if (condition instanceof And) {
			And and = (And) condition;
			return bindSimpleFilterCondition(pattern, and.getLeftArg())
					&& bindSimpleFilterCondition(pattern, and.getRightArg());
		}

		if (condition instanceof Compare) {
			Compare compare = (Compare) condition;
			if (compare.getOperator() != Compare.CompareOp.EQ) {
				return false;
			}

			return bindVarToConstant(pattern, compare.getLeftArg(), compare.getRightArg())
					|| bindVarToConstant(pattern, compare.getRightArg(), compare.getLeftArg());
		}

		if (condition instanceof SameTerm) {
			SameTerm sameTerm = (SameTerm) condition;
			return bindVarToConstant(pattern, sameTerm.getLeftArg(), sameTerm.getRightArg())
					|| bindVarToConstant(pattern, sameTerm.getRightArg(), sameTerm.getLeftArg());
		}

		return false;
	}

	private boolean bindVarToConstant(StatementPattern pattern, ValueExpr maybeVarExpr, ValueExpr maybeValueExpr) {
		if (!(maybeVarExpr instanceof Var) || !(maybeValueExpr instanceof ValueConstant)) {
			return false;
		}

		Var filterVar = (Var) maybeVarExpr;
		ValueConstant constant = (ValueConstant) maybeValueExpr;
		if (filterVar.getName() == null || constant.getValue() == null) {
			return false;
		}

		return bindPatternVars(pattern, filterVar.getName(), constant.getValue());
	}

	private boolean bindPatternVars(StatementPattern pattern, String varName, Value value) {
		boolean found = false;
		for (Var patternVar : new Var[] {
				pattern.getSubjectVar(),
				pattern.getPredicateVar(),
				pattern.getObjectVar(),
				pattern.getContextVar() }) {
			if (patternVar == null || !varName.equals(patternVar.getName())) {
				continue;
			}

			found = true;
			if (patternVar.hasValue() && !Objects.equals(patternVar.getValue(), value)) {
				return false;
			}
			if (!patternVar.hasValue()) {
				pattern.replaceChildNode(patternVar,
						Var.of(patternVar.getName(), value, patternVar.isAnonymous(), patternVar.isConstant()));
			}
		}
		return found;
	}

	private String getValueOrNull(Var v) {
		return (v == null || v.getValue() == null)
				? null
				: v.getValue().stringValue();
	}

	private boolean hasBoundComponent(StatementPattern sp) {
		return hasBoundValue(sp.getSubjectVar())
				|| hasBoundValue(sp.getPredicateVar())
				|| hasBoundValue(sp.getObjectVar())
				|| hasBoundValue(sp.getContextVar());
	}

	private boolean hasBoundValue(Var var) {
		return var != null && var.hasValue();
	}

	private Component findPatternComponentByVarName(StatementPattern pattern, String varName) {
		for (Component component : COMPONENT_VALUES) {
			Var var = varForComponent(pattern, component);
			if (var != null && varName.equals(var.getName())) {
				return component;
			}
		}
		return null;
	}

	private Component getComponent(StatementPattern sp, Var var) {
		if (var.equals(sp.getSubjectVar())) {
			return Component.S;
		}
		if (var.equals(sp.getPredicateVar())) {
			return Component.P;
		}
		if (var.equals(sp.getObjectVar())) {
			return Component.O;
		}
		if (var.equals(sp.getContextVar())) {
			return Component.C;
		}
		throw new IllegalStateException("Unexpected variable " + var + " in pattern " + sp);
	}

	private Var varForComponent(StatementPattern pattern, Component component) {
		return switch (component) {
		case S -> pattern.getSubjectVar();
		case P -> pattern.getPredicateVar();
		case O -> pattern.getObjectVar();
		case C -> pattern.getContextVar();
		};
	}

	private record LookupAnalysis(int componentMask, double multiplier) {
		private static LookupAnalysis none() {
			return new LookupAnalysis(0, -1.0d);
		}

		private boolean isNone() {
			return componentMask == 0;
		}
	}

	private record LookupValueCount(Component component, int valueCount) {
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Staleness API */
	/* ────────────────────────────────────────────────────────────── */

	private static final class ChurnSnapshot {
		final int sampled;
		final int removed;
		final int readded;

		ChurnSnapshot(int sampled, int removed, int readded) {
			this.sampled = sampled;
			this.removed = removed;
			this.readded = readded;
		}

		double removalRatio() {
			return sampled == 0 ? 0.0 : (double) removed / (double) sampled;
		}

		double readdRatio() {
			return sampled == 0 ? 0.0 : (double) readded / (double) sampled;
		}
	}

	private static final class ChurnSampler {
		private enum State {
			ADDED,
			DELETED_AFTER_ADD,
			READDED_AFTER_DELETE
		}

		private final ConcurrentHashMap<String, State> samples = new ConcurrentHashMap<>();
		private long eventsSinceLastSample = 0L;

		void reset() {
			samples.clear();
			eventsSinceLastSample = 0L;
		}

		void recordAdd(String s, String p, String o, String c, long sampleEvery) {
			record(s, p, o, c, sampleEvery, true);
		}

		void recordDelete(String s, String p, String o, String c, long sampleEvery) {
			record(s, p, o, c, sampleEvery, false);
		}

		private void record(String s, String p, String o, String c, long sampleEvery, boolean isAdd) {
			if (sampleEvery <= 0) {
				return;
			}
			eventsSinceLastSample++;
			if (eventsSinceLastSample < sampleEvery) {
				return;
			}
			eventsSinceLastSample = 0L;
			String signature = sig(s, p, o, c);

			samples.compute(signature, (sig, state) -> {
				if (state == null) {
					return isAdd ? State.ADDED : null;
				}
				if (isAdd && state == State.DELETED_AFTER_ADD) {
					return State.READDED_AFTER_DELETE;
				}
				if (!isAdd && state == State.ADDED) {
					return State.DELETED_AFTER_ADD;
				}
				return state;
			});
		}

		ChurnSnapshot snapshot() {
			int sampled = 0;
			int removed = 0;
			int readded = 0;
			for (State state : samples.values()) {
				sampled++;
				if (state == State.DELETED_AFTER_ADD || state == State.READDED_AFTER_DELETE) {
					removed++;
				}
				if (state == State.READDED_AFTER_DELETE) {
					readded++;
				}
			}
			return new ChurnSnapshot(sampled, removed, readded);
		}
	}

	/**
	 * Immutable staleness snapshot. All values are approximate by design.
	 */
	public static final class Staleness {
		public final long ageMillis; // AoI: time since last publish
		public final long lastRebuildPublishMs;

		// churn-specific
		public final int sampledAdds;
		public final int sampledRemoved;
		public final int sampledReadded;
		public final double sampledRemovalRatio;
		public final double sampledReaddRatio;

		public final double stalenessScore; // combined 0..1+

		private Staleness(
				long ageMillis,
				long lastRebuildPublishMs,
				int sampledAdds,
				int sampledRemoved,
				int sampledReadded,
				double sampledRemovalRatio,
				double sampledReaddRatio,
				double stalenessScore) {
			this.ageMillis = ageMillis;
			this.lastRebuildPublishMs = lastRebuildPublishMs;
			this.sampledAdds = sampledAdds;
			this.sampledRemoved = sampledRemoved;
			this.sampledReadded = sampledReadded;
			this.sampledRemovalRatio = sampledRemovalRatio;
			this.sampledReaddRatio = sampledReaddRatio;
			this.stalenessScore = stalenessScore;
		}

		@Override
		public String toString() {
			return "Staleness{" +
					"ageMillis=" + ageMillis +
					", lastRebuildPublishMs=" + lastRebuildPublishMs +
					", sampledAdds=" + sampledAdds +
					", sampledRemoved=" + sampledRemoved +
					", sampledReadded=" + sampledReadded +
					", sampledRemovalRatio=" + sampledRemovalRatio +
					", sampledReaddRatio=" + sampledReaddRatio +
					", stalenessScore=" + stalenessScore +
					'}';
		}
	}

	/**
	 * Compute a staleness snapshot using the *current* published State. No locks taken.
	 *
	 * This is O(total number of populated sketch keys) and intended for occasional diagnostics or adaptive scheduling.
	 * All numbers are approximate by design of the tuple sketches.
	 */
	public Staleness staleness() {
		final long now = System.currentTimeMillis();
		final long age = lastRebuildPublishMs == 0L ? Long.MAX_VALUE : (now - lastRebuildPublishMs);

		final int decisionMin = 1;

		ChurnSnapshot churnSnapshot = churnSampler.snapshot();
		double churnRatio = churnSnapshot.sampled < decisionMin
				? 0.0
				: Math.max(churnSnapshot.readdRatio(), churnSnapshot.removalRatio());

		double score = clamp(churnRatio, 0.0, 1.0);

		return new Staleness(
				age,
				lastRebuildPublishMs,
				churnSnapshot.sampled,
				churnSnapshot.removed,
				churnSnapshot.readded,
				churnSnapshot.removalRatio(),
				churnSnapshot.readdRatio(),
				score);
	}

	/** Convenience: true if combined staleness score exceeds a given threshold. */
	public boolean isStale(double threshold) {
		Staleness staleness = staleness();
		int decisionMin = 1;
		boolean removalBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledRemovalRatio >= churnRemovalRatioThreshold;
		boolean readdBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledReaddRatio >= churnReaddThreshold;
		return removalBreach || readdBreach || staleness.stalenessScore > threshold;
	}

	// ──────────────────────────────────────────────────────────────
	// Staleness helpers (private)
	// ──────────────────────────────────────────────────────────────

	private static double clamp(double v, double lo, double hi) {
		return Math.max(lo, Math.min(hi, v));
	}

	/**
	 * Determine how frequently churn events should be sampled, expressed as "every N statements".
	 * <p>
	 * Rules:
	 * <ul>
	 * <li>When both {@code churnSamplePercent} and {@code churnSampleMin} are zero or negative, sampling is
	 * disabled.</li>
	 * <li>Base interval is derived from {@code churnSamplePercent * approxStoreSize} (rounded to ≥ 1) when percent &gt;
	 * 0.</li>
	 * <li>The interval is never smaller (more frequent) than {@code churnSampleMin} when
	 * {@code churnSampleMin &gt; 0}.</li>
	 * <li>If {@code churnSampleMax &gt; 0} and the calculated interval is below it, the interval is raised to
	 * {@code churnSampleMax} to avoid oversampling.</li>
	 * </ul>
	 */
	private long samplingInterval() {
		if (churnSamplePercent <= 0.0 && churnSampleMin <= 0) {
			return 0L; // sampling disabled
		}

		long interval = 0L;

		if (churnSamplePercent > 0.0) {
			double raw = approxStoreSize.get() * churnSamplePercent;
			long pctInterval = Math.max(1L, Math.round(raw));
			interval = Math.max(interval, pctInterval);
		}

		if (churnSampleMin > 0) {
			interval = Math.max(interval, churnSampleMin);
		}

		if (churnSampleMax > 0 && interval > 0 && interval < churnSampleMax) {
			interval = churnSampleMax;
		}

		return interval;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Persistence public API */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Best-effort sketch persistence intended for scheduled store-level sync/commit paths.
	 *
	 * @return true if persisted state was updated.
	 */
	public boolean persistIfDirty() {
		flushPendingIncremental();
		SketchEstimatorPersistenceStore store = persistenceStore;
		if (!persistenceEnabled || persistenceFile == null || store == null) {
			return false;
		}
		if ((rebuildEpoch.get() & 1L) != 0L) {
			return false;
		}
		if (!dirty.get() && !indexDirty.get()) {
			return false;
		}
		try {
			flushDirtySketches();
		} catch (Throwable t) {
			logger.warn("Failed to persist join estimator state to {}", persistenceFile, t);
			return false;
		}
		synchronized (persistLock) {
			if (!dirty.get() && !indexDirty.get()) {
				return false;
			}
			try {
				store.flush();
				writeDirectoryIndexes(store);
				store.writeMetadata(newDirectoryMetadata(store));
				indexDirty.set(false);
				refreshDirtyFlagFromCacheDirectory();
				return true;
			} catch (Throwable t) {
				logger.warn("Failed to persist join estimator state to {}", persistenceFile, t);
				return false;
			}
		}
	}

	/**
	 * Release in-memory sketches. Query planning falls back until sketches are lazy-loaded or rebuilt.
	 */
	public void unload() {
		unloadInternal(false);
	}

	/**
	 * Discard any in-memory estimator state and force a rebuild from store data on the next refresh cycle.
	 */
	public void discardAndMarkForRebuild() {
		unloadInternal(true);
		clearSlotPersistence((byte) 0);
		clearSlotPersistence((byte) 1);
		dirty.set(false);
		indexDirty.set(false);
	}

	private void unloadInternal(boolean markRebuildRequired) {
		clearEstimateCache();
		if (persistenceEnabled && persistenceStore != null) {
			if ((dirty.get() || indexDirty.get()) && !persistIfDirty()) {
				return;
			}
		} else {
			discardPendingIncremental();
		}
		synchronized (bufA) {
			bufA.clear();
		}
		synchronized (bufB) {
			bufB.clear();
		}
		synchronized (sketchCacheLock) {
			residentLru.clear();
			cacheDirectory.clearAllResidentNodes();
			residentSketchBytes = 0L;
		}
		memoryRegistry.clearCategory(MemoryCategory.RESIDENT_SKETCHES);
		memoryRegistry.clearTransientCategories();
		refreshCacheMetadataAccounting();
		if (!persistenceEnabled || persistenceStore == null) {
			seenTriples = 0L;
		}
		sketchesLoaded = false;
		if (markRebuildRequired) {
			rebuildRequired.set(true);
		}
	}

	private void discardPendingIncremental() {
		synchronized (incrementalBufferLock) {
			Arrays.fill(incrementalBuffer, 0, incrementalBufferCount, null);
			incrementalBufferCount = 0;
		}
		int discardedQueuedBatches = 0;
		while (asyncIncrementalBatches.poll() != null) {
			discardedQueuedBatches++;
		}
		if (discardedQueuedBatches > 0) {
			synchronized (asyncIncrementalDrainLock) {
				asyncIncrementalBatchCount = Math.max(0, asyncIncrementalBatchCount - discardedQueuedBatches);
				asyncIncrementalDrainLock.notifyAll();
			}
		}
		waitForAsyncIncrementalBatchesIgnoringFailures();
		asyncIncrementalFailure.set(null);
	}

	private void waitForAsyncIncrementalBatchesIgnoringFailures() {
		synchronized (asyncIncrementalDrainLock) {
			while (asyncIncrementalBatchCount > 0) {
				try {
					asyncIncrementalDrainLock.wait();
				} catch (InterruptedException e) {
					Thread.currentThread().interrupt();
					return;
				}
			}
		}
	}

	private boolean tryLoadFromDisk() {
		if (!persistenceEnabled || persistenceFile == null) {
			return false;
		}
		synchronized (loadLock) {
			if (sketchesLoaded) {
				return true;
			}
			if (!hasSnapshotAvailable(persistenceFile)) {
				return false;
			}
			try {
				loadDirectoryStore(true);
				sketchesLoaded = true;
				rebuildRequired.set(false);
				dirty.set(false);
				indexDirty.set(false);
				return true;
			} catch (Throwable t) {
				discardAndMarkForRebuild();
				logger.warn("Failed to load join estimator state from {}", persistenceFile, t);
				return false;
			}
		}
	}

	private static boolean hasSnapshotAvailable(Path file) {
		return file != null && Files.isRegularFile(file.toAbsolutePath().normalize().resolve("metadata.bin"));
	}

	private void loadDirectoryStore(boolean markLoaded) throws IOException {
		SketchEstimatorPersistenceStore store = persistenceStore;
		if (store == null || !store.hasMetadata()) {
			return;
		}
		SketchEstimatorMetadata metadata = store.readMetadata();
		if (metadata.bucketCount != nominalEntries) {
			throw new IOException("Snapshot buckets mismatch: snapshot=" + metadata.bucketCount + " current="
					+ nominalEntries);
		}
		if (metadata.sketchNominalEntries != bufA.k) {
			throw new IOException("Snapshot sketchK mismatch: snapshot=" + metadata.sketchNominalEntries
					+ " current=" + bufA.k);
		}
		if (!Objects.equals(metadata.defaultContext, defaultContextString)) {
			throw new IOException("Snapshot defaultContextString mismatch");
		}
		if (metadata.persistedMaxMemoryBytes > memoryPolicy.maxMemoryBytes) {
			logger.warn("Join estimator store {} was persisted with larger Xmx ({} bytes) than current Xmx ({} bytes)",
					store.directory(), metadata.persistedMaxMemoryBytes, memoryPolicy.maxMemoryBytes);
		}

		List<SketchEstimatorPersistenceStore.IndexEntry> slotAEntries = store.readIndex((byte) 0);
		List<SketchEstimatorPersistenceStore.IndexEntry> slotBEntries = store.readIndex((byte) 1);
		synchronized (bufA) {
			bufA.clear();
		}
		synchronized (bufB) {
			bufB.clear();
		}
		synchronized (sketchCacheLock) {
			cacheDirectory.clear();
			loadDirectoryIndexEntries(slotAEntries);
			loadDirectoryIndexEntries(slotBEntries);
			residentLru.clear();
			cacheDirectory.clearAllResidentNodes();
			residentSketchBytes = 0L;
			indexDirty.set(false);
		}
		memoryRegistry.clearCategory(MemoryCategory.RESIDENT_SKETCHES);
		refreshCacheMetadataAccounting();
		slotGenerations[0] = Math.max(1L, metadata.slotGenerationA);
		slotGenerations[1] = Math.max(1L, metadata.slotGenerationB);
		current = metadata.activeSlot == 0 ? bufA : bufB;
		usingA = metadata.activeSlot == 0;
		seenTriples = metadata.seenCount;
		approxStoreSize.set(metadata.approxStoreSize);
		lastRebuildPublishMs = metadata.lastPublishTime;
		churnSampler.reset();
		sketchesLoaded = markLoaded;
		rebuildRequired.set(false);
		dirty.set(false);
		indexDirty.set(false);
	}

	private void loadDirectoryIndexEntries(List<SketchEstimatorPersistenceStore.IndexEntry> entries) {
		for (SketchEstimatorPersistenceStore.IndexEntry entry : entries) {
			SketchAddress address = new SketchAddress(entry.recType, entry.delete, entry.axisA, entry.axisB, entry.x,
					entry.y);
			int entryId = cacheDirectory.findOrAdd(address);
			cacheDirectory.setPersistedRef(entryId, entry.ref.slot, entry.ref.fileKind, entry.ref.offset,
					entry.ref.length, entry.ref.generation);
		}
	}

	private void writeDirectoryIndexes(SketchEstimatorPersistenceStore store) throws IOException {
		store.writeIndex((byte) 0, directoryIndexEntries((byte) 0));
		store.writeIndex((byte) 1, directoryIndexEntries((byte) 1));
	}

	private List<SketchEstimatorPersistenceStore.IndexEntry> directoryIndexEntries(byte slot) {
		List<SketchEstimatorPersistenceStore.IndexEntry> entries = new ArrayList<>();
		synchronized (sketchCacheLock) {
			for (PersistedSketchEntry entry : cacheDirectory.snapshotPersistedEntries(slot)) {
				SketchAddress address = entry.address;
				PersistedSketchRef ref = entry.persistedSketchRef;
				entries.add(new SketchEstimatorPersistenceStore.IndexEntry(address.recType, address.isDelete,
						address.axisA, address.axisB, address.x, address.y,
						new SketchEstimatorPersistenceStore.Ref(slot, ref.fileKind, ref.offset, ref.length,
								ref.generation)));
			}
		}
		return entries;
	}

	private SketchEstimatorMetadata newDirectoryMetadata(SketchEstimatorPersistenceStore store) throws IOException {
		byte activeSlot = slotByte(slotOf(current));
		long approxSize = store.approximateSize();
		return new SketchEstimatorMetadata(nominalEntries, bufA.k, defaultContextString, activeSlot, seenTriples,
				approxSize, lastRebuildPublishMs, memoryPolicy, slotGenerations[0], slotGenerations[1]);
	}

	private void clearSlotPersistence(byte slot) {
		synchronized (sketchCacheLock) {
			cacheDirectory.clearPersistedRefsForSlot(slot);
			cacheDirectory.clearDirtyForSlot(slot);
		}
	}

	private boolean isRebuildAllowed() {
		BooleanSupplier supplier = rebuildAllowedSupplier;
		if (supplier != null) {
			try {
				return supplier.getAsBoolean();
			} catch (Throwable t) {
				logger.debug("Ignoring rebuild-allowed supplier failure", t);
			}
		}
		return true;
	}

	private void refreshCacheMetadataAccounting() {
		synchronized (sketchCacheLock) {
			refreshCacheMetadataAccountingLocked();
		}
	}

	private void refreshCacheMetadataAccountingLocked() {
		int cacheVersion = cacheDirectory.heapBytesVersion();
		int residentVersion = residentLru.heapBytesVersion();
		if (cacheVersion == cacheDirectoryMetadataVersion && residentVersion == residentLruMetadataVersion) {
			return;
		}
		long actualBytes = cacheDirectory.estimatedHeapBytes() + residentLru.estimatedHeapBytes();
		long trackedBytes = Math.max(0L, actualBytes - baselineCacheMetadataBytes);
		cacheDirectoryMetadataVersion = cacheVersion;
		residentLruMetadataVersion = residentVersion;
		memoryRegistry.replace(MemoryCategory.CACHE_METADATA, MEMORY_OWNER_CACHE_METADATA, trackedBytes);
	}

	DebugMemorySnapshot debugMemorySnapshot() {
		return memoryRegistry.snapshot();
	}

	private void replaceTrackedMemory(MemoryCategory category, long ownerId, long bytes) {
		memoryRegistry.replace(category, ownerId, bytes);
	}

	private void releaseTrackedMemory(MemoryCategory category, long ownerId) {
		memoryRegistry.release(category, ownerId);
	}

	private void reserveTrackedMemory(MemoryCategory category, long ownerId, long bytes) {
		memoryRegistry.reserve(category, ownerId, bytes);
	}

	private long trackedEstimatorBytes() {
		return memoryRegistry.totalBytes();
	}

	private void ensureEstimatorCapacity(long predictedBytes, boolean allowUnload) {
		long additionalBytes = Math.max(0L, predictedBytes);
		if (hasRecoveredHeadroom(additionalBytes)) {
			return;
		}

		while (true) {
			int candidateEntryId;
			byte candidateSlot;
			synchronized (sketchCacheLock) {
				if (residentLru.isEmpty()) {
					break;
				}
				int headNode = residentLru.headNode();
				candidateEntryId = residentLru.entryId(headNode);
				candidateSlot = residentLru.slot(headNode);
			}
			EvictionResult evictionResult = evictResidentSketch(candidateEntryId, candidateSlot);
			if (evictionResult != EvictionResult.EVICTED) {
				break;
			}
			if (hasRecoveredHeadroom(additionalBytes)) {
				return;
			}
		}

		if (hasRecoveredHeadroom(additionalBytes)) {
			return;
		}
		if (allowUnload) {
			unloadInternal(true);
		}
		throw new MemoryPressureAbort("Insufficient estimator memory budget for allocation of " + additionalBytes
				+ " bytes (tracked=" + trackedEstimatorBytes() + ", budget=" + trackedMemorySoftLimitBytes
				+ ")");
	}

	private boolean hasRecoveredHeadroom(long additionalBytes) {
		long trackedBytes = saturatingAdd(trackedEstimatorBytes(), additionalBytes);
		return trackedBytes <= trackedMemorySoftLimitBytes;
	}

	private static long saturatingAdd(long left, long right) {
		if (right <= 0L) {
			return left;
		}
		if (left >= Long.MAX_VALUE - right) {
			return Long.MAX_VALUE;
		}
		return left + right;
	}

	private static long residentOwner(byte slot, int entryId) {
		return (((long) slot) << 32) | (entryId & 0xffffffffL);
	}

	private static String residentOwnerLabel(long ownerId) {
		byte slot = (byte) (ownerId >>> 32);
		int entryId = (int) ownerId;
		return "resident:" + (slot == 0 ? "A" : "B") + ":" + entryId;
	}

	private static long transientOwner(long ownerBase) {
		return transientOwner(ownerBase, 0L);
	}

	private static long transientOwner(long ownerBase, long discriminator) {
		long threadId = Thread.currentThread().getId() & 0xffffL;
		return (threadId << 48) | ((discriminator & 0xffffffffL) << 16) | (ownerBase & 0xffffL);
	}

	private static String transientOwnerLabel(long ownerId) {
		long threadId = (ownerId >>> 48) & 0xffffL;
		long discriminator = (ownerId >>> 16) & 0xffffffffL;
		long ownerBase = (short) ownerId;
		return "transient:" + ownerBase + ":" + discriminator + ":thread-" + threadId;
	}

	private static long estimateByteArrayBytes(int length) {
		return align(ARRAY_HEADER_BYTES + Math.max(0L, length) * BYTE_BYTES);
	}

	private static long estimateBooleanArrayBytes(int length) {
		return align(ARRAY_HEADER_BYTES + Math.max(0L, length) * BOOLEAN_BYTES);
	}

	private static long estimateIntArrayBytes(int length) {
		return align(ARRAY_HEADER_BYTES + Math.max(0L, length) * INT_BYTES);
	}

	private static long estimateLongArrayBytes(int length) {
		return align(ARRAY_HEADER_BYTES + Math.max(0L, length) * LONG_BYTES);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* ArrayOfDoublesSketch cache + IO */
	/* ────────────────────────────────────────────────────────────── */

	private static long estimatedSketchBytes(ArrayOfDoublesUpdatableSketch sketch) {
		// getCurrentBytes() is O(1) and avoids scanning retained entries on every cache touch.
		return sketch.getCurrentBytes();
	}

	private BufferSlot slotOf(State state) {
		return state == bufA ? BufferSlot.A : BufferSlot.B;
	}

	private static byte slotByte(BufferSlot slot) {
		return slot == BufferSlot.A ? (byte) 0 : (byte) 1;
	}

	private State stateOf(BufferSlot slot) {
		return slot == BufferSlot.A ? bufA : bufB;
	}

	private static SketchAddress singleTripleAddress(boolean isDelete, Component component, int idx) {
		return new SketchAddress(REC_SINGLE_TRIPLE, isDelete, (byte) component.ordinal(), (byte) 0, idx, 0);
	}

	private static SketchAddress globalComponentAddress(Component component) {
		return new SketchAddress(REC_GLOBAL_COMPONENT, false, (byte) component.ordinal(), (byte) 0, 0, 0);
	}

	private static SketchAddress singleComplementAddress(boolean isDelete, Component fixed, Component other, int idx) {
		return new SketchAddress(REC_SINGLE_CPL, isDelete, (byte) fixed.ordinal(), (byte) other.ordinal(), idx, 0);
	}

	private static SketchAddress pairAddress(byte recType, boolean isDelete, Pair pair, int x, int y) {
		return new SketchAddress(recType, isDelete, (byte) pair.ordinal(), (byte) 0, x, y);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForRead(State state, SketchAddress address) {
		ArrayOfDoublesUpdatableSketch sketch = getResidentSketch(state, address.recType, address.isDelete,
				address.axisA, address.axisB,
				address.x, address.y);
		if (sketch != null) {
			touchResidentSketch(state, address, sketch, false);
			return sketch;
		}
		return loadPersistedSketch(state, address);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForWrite(State state, SketchAddress address) {
		return getSketchForWrite(state, address.recType, address.isDelete, address.axisA, address.axisB, address.x,
				address.y, -1);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForWrite(State state, SketchAddress address, int entryId) {
		return getSketchForWrite(state, address, entryId, true);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForWrite(State state, SketchAddress address, int entryId,
			boolean enforceLoadBudget) {
		return getSketchForWrite(state, address.recType, address.isDelete, address.axisA, address.axisB, address.x,
				address.y, entryId, enforceLoadBudget);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForWrite(State state, byte recType, boolean isDelete, byte axisA,
			byte axisB, int x,
			int y, int entryId) {
		return getSketchForWrite(state, recType, isDelete, axisA, axisB, x, y, entryId, true);
	}

	private ArrayOfDoublesUpdatableSketch getSketchForWrite(State state, byte recType, boolean isDelete, byte axisA,
			byte axisB, int x,
			int y, int entryId, boolean enforceLoadBudget) {
		ArrayOfDoublesUpdatableSketch sketch = getResidentSketch(state, recType, isDelete, axisA, axisB, x, y);
		if (sketch == null) {
			SketchAddress address = new SketchAddress(recType, isDelete, axisA, axisB, x, y);
			sketch = entryId >= 0 ? loadPersistedSketch(state, address, entryId, enforceLoadBudget)
					: loadPersistedSketch(state, address, enforceLoadBudget);
			if (sketch != null) {
				setResidentSketch(state, recType, isDelete, axisA, axisB, x, y, sketch);
			}
			if (sketch == null) {
				sketch = allocatePersistentSketchForWrite(state, address, entryId);
				if (sketch != null) {
					setResidentSketch(state, recType, isDelete, axisA, axisB, x, y, sketch);
				}
			}
		}
		if (sketch == null) {
			ensureEstimatorCapacity(256L, true);
			sketch = newSk(state.k);
			setResidentSketch(state, recType, isDelete, axisA, axisB, x, y, sketch);
		}
		return sketch;
	}

	private void updateSingleSketchRaw(State state, boolean isDelete, Component component, int idx, long thetaHash) {
		updateSketchRaw(state, REC_SINGLE_TRIPLE, isDelete, (byte) component.ordinal(), (byte) 0, idx, 0, thetaHash);
	}

	private void updateGlobalComponentSketchRaw(State state, boolean isDelete, Component component, long thetaHash) {
		updateSketchRaw(state, REC_GLOBAL_COMPONENT, isDelete, (byte) component.ordinal(), (byte) 0, 0, 0, thetaHash);
	}

	private void updateComplementSketchRaw(State state, boolean isDelete, Component fixed, Component other, int idx,
			long thetaHash) {
		updateSketchRaw(state, REC_SINGLE_CPL, isDelete, (byte) fixed.ordinal(), (byte) other.ordinal(), idx, 0,
				thetaHash);
	}

	private ArrayOfDoublesUpdatableSketch loadPersistedSketch(State state, SketchAddress address) {
		return loadPersistedSketch(state, address, true);
	}

	private ArrayOfDoublesUpdatableSketch loadPersistedSketch(State state, SketchAddress address,
			boolean enforceBudget) {
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.find(address);
		}
		if (entryId < 0) {
			return null;
		}
		return loadPersistedSketch(state, address, entryId, enforceBudget);
	}

	private ArrayOfDoublesUpdatableSketch allocatePersistentSketchForWrite(State state, SketchAddress address,
			int knownEntryId) {
		if (!persistenceEnabled) {
			return null;
		}
		SketchEstimatorPersistenceStore store = persistenceStore;
		if (store == null) {
			return null;
		}
		int entryId = knownEntryId;
		if (entryId < 0) {
			synchronized (sketchCacheLock) {
				entryId = cacheDirectory.findOrAdd(address);
			}
		}
		byte slot = slotByte(slotOf(state));
		synchronized (persistLock) {
			store = persistenceStore;
			if (store == null) {
				return null;
			}
			try {
				SketchEstimatorPersistenceStore.FramedPayloadAllocation allocation = store.allocateFramedPayload(slot,
						fileKindFor(address), SKETCH_PAYLOAD_FORMAT_NATIVE, state.maxSketchBytes,
						slotGenerations[slot]);
				ArrayOfDoublesUpdatableSketch sketch = newSk(state.k, allocation.payload);
				synchronized (sketchCacheLock) {
					cacheDirectory.setPersistedRef(entryId, slot, allocation.ref.fileKind, allocation.ref.offset,
							allocation.ref.length, allocation.ref.generation);
					indexDirty.set(true);
				}
				return sketch;
			} catch (IOException e) {
				logger.warn("Failed to allocate persisted sketch {}; falling back to heap sketch", address, e);
				return null;
			}
		}
	}

	private ArrayOfDoublesUpdatableSketch loadPersistedSketch(State state, SketchAddress address, int entryId) {
		return loadPersistedSketch(state, address, entryId, true);
	}

	private ArrayOfDoublesUpdatableSketch loadPersistedSketch(State state, SketchAddress address, int entryId,
			boolean enforceBudget) {
		try {
			ArrayOfDoublesUpdatableSketch loaded;
			byte slot = slotByte(slotOf(state));
			synchronized (persistLock) {
				PersistedSketchRef persistedSketchRef;
				synchronized (sketchCacheLock) {
					persistedSketchRef = cacheDirectory.persistedRef(entryId, slot);
				}
				if (persistedSketchRef == null) {
					return null;
				}
				SketchEstimatorPersistenceStore store = persistenceStore;
				if (store == null) {
					return null;
				}
				loaded = readSketchFromStore(store, persistedSketchRef, slot);
			}
			putResidentSketch(state, address, loaded, enforceBudget);
			return loaded;
		} catch (IOException e) {
			logger.warn("Failed to load persisted sketch {}", address, e);
			throw new RuntimeException("Failed to load persisted sketch " + address, e);
		}
	}

	private void putResidentSketch(State state, SketchAddress address, ArrayOfDoublesUpdatableSketch sketch) {
		putResidentSketch(state, address, sketch, true);
	}

	private void putResidentSketch(State state, SketchAddress address, ArrayOfDoublesUpdatableSketch sketch,
			boolean enforceBudget) {
		setResidentSketch(state, address, sketch);
		if (sketch == null) {
			removeResidentSketchTracking(state, address);
		} else {
			touchResidentSketch(state, address, sketch, enforceBudget);
		}
	}

	private void touchResidentSketch(State state, SketchAddress address, ArrayOfDoublesUpdatableSketch sketch,
			boolean enforceBudget) {
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(address);
		}
		touchResidentSketch(state, entryId, sketch, enforceBudget);
	}

	private void touchResidentSketch(State state, int entryId, ArrayOfDoublesUpdatableSketch sketch,
			boolean enforceBudget) {
		byte slot = slotByte(slotOf(state));
		long bytes = estimatedSketchBytes(sketch);
		boolean residentBytesChanged = true;
		synchronized (sketchCacheLock) {
			int nodeId = cacheDirectory.residentNode(entryId, slot);
			if (nodeId == -1) {
				int createdNodeId = residentLru.add(entryId, slot, bytes);
				cacheDirectory.setResidentNode(entryId, slot, createdNodeId);
				residentSketchBytes += bytes;
				refreshCacheMetadataAccountingLocked();
			} else {
				long previousBytes = residentLru.bytes(nodeId);
				residentLru.touch(nodeId, bytes);
				residentSketchBytes += (bytes - previousBytes);
				residentBytesChanged = bytes != previousBytes;
			}
		}
		if (residentBytesChanged) {
			replaceTrackedMemory(MemoryCategory.RESIDENT_SKETCHES, residentOwner(slot, entryId), bytes);
		}
		if (enforceBudget) {
			enforceSketchBudget();
		}
	}

	private long initialSingletonSketchBytesHint(State state, ArrayOfDoublesUpdatableSketch sketch, int valueCount) {
		if (valueCount != 1 || sketch.getRetainedEntries() != 1) {
			return -1L;
		}
		return state.initialSketchBytes;
	}

	private void markDirtyAndTouchResidentSketch(byte slot, int entryId, ArrayOfDoublesUpdatableSketch sketch,
			long knownBytes) {
		boolean hasInitialSingletonBytes = knownBytes >= 0L;
		long bytes = hasInitialSingletonBytes ? knownBytes : estimatedSketchBytes(sketch);
		boolean residentBytesChanged = true;
		synchronized (sketchCacheLock) {
			cacheDirectory.markDirty(entryId, slot);
			dirty.set(true);
			int nodeId = cacheDirectory.residentNode(entryId, slot);
			if (nodeId == -1) {
				if (hasInitialSingletonBytes && cacheDirectory.persistedRef(entryId, slot) != null) {
					bytes = estimatedSketchBytes(sketch);
				}
				int createdNodeId = residentLru.add(entryId, slot, bytes);
				cacheDirectory.setResidentNode(entryId, slot, createdNodeId);
				residentSketchBytes += bytes;
				refreshCacheMetadataAccountingLocked();
			} else {
				if (hasInitialSingletonBytes) {
					bytes = estimatedSketchBytes(sketch);
				}
				long previousBytes = residentLru.bytes(nodeId);
				residentLru.touch(nodeId, bytes);
				residentSketchBytes += (bytes - previousBytes);
				residentBytesChanged = bytes != previousBytes;
			}
		}
		if (residentBytesChanged) {
			replaceTrackedMemory(MemoryCategory.RESIDENT_SKETCHES, residentOwner(slot, entryId), bytes);
		}
	}

	private void removeResidentSketchTracking(State state, SketchAddress address) {
		byte slot = slotByte(slotOf(state));
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.find(address);
			if (entryId < 0) {
				return;
			}
			removeResidentSketchTracking(entryId, slot);
		}
		refreshCacheMetadataAccounting();
	}

	private void clearResidentTrackingForSlot(BufferSlot slot) {
		byte targetSlot = slotByte(slot);
		synchronized (sketchCacheLock) {
			for (int node = residentLru.headNode(); node != -1;) {
				int nextNode = residentLru.nextNode(node);
				if (residentLru.slot(node) == targetSlot) {
					int entryId = residentLru.entryId(node);
					residentSketchBytes -= residentLru.remove(node);
					cacheDirectory.setResidentNode(entryId, targetSlot, -1);
					releaseTrackedMemory(MemoryCategory.RESIDENT_SKETCHES, residentOwner(targetSlot, entryId));
				}
				node = nextNode;
			}
			cacheDirectory.clearResidentNodesForSlot(targetSlot);
		}
		refreshCacheMetadataAccounting();
	}

	private void rebuildResidentTrackingForSlot(State state) {
		BufferSlot bufferSlot = slotOf(state);
		byte slot = slotByte(bufferSlot);
		clearResidentTrackingForSlot(bufferSlot);
		synchronized (sketchCacheLock) {
			cacheDirectory.clearDirtyForSlot(slot);
		}

		for (Component component : COMPONENT_VALUES) {
			trackRebuiltArray(slot, GLOBAL_COMPONENT_KEY_PREFIXES[component.ordinal()],
					state.globalComponents.get(component));
			trackRebuiltArray(slot, SINGLE_TRIPLE_KEY_PREFIXES[component.ordinal()],
					state.singleTriples.get(component));
		}
		trackRebuiltSingles(slot, state.singles, false);
		trackRebuiltPairs(slot, state.pairs, false);

		dirty.set(true);
		refreshCacheMetadataAccounting();
	}

	private void trackRebuiltSingles(byte slot, StateComponents<SingleBuild> singles, boolean isDelete) {
		int deleteMask = isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		for (Component fixed : COMPONENT_VALUES) {
			SingleBuild build = singles.get(fixed);
			for (Map.Entry<Component, AtomicReferenceArray<ArrayOfDoublesUpdatableSketch>> entry : build.cmpl
					.entrySet()) {
				int keyPrefix = SINGLE_COMPLEMENT_KEY_PREFIXES[fixed.ordinal()][entry.getKey().ordinal()] | deleteMask;
				trackRebuiltArray(slot, keyPrefix, entry.getValue());
			}
		}
	}

	private void trackRebuiltPairs(byte slot, EnumMap<Pair, PairBuild> pairs, boolean isDelete) {
		int deleteMask = isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		for (Pair pair : PAIR_VALUES) {
			PairBuild build = pairs.get(pair);
			int pairIndex = pair.ordinal();
			int triplePrefix = PAIR_TRIPLE_KEY_PREFIXES[pairIndex] | deleteMask;
			int comp1Prefix = PAIR_COMP1_KEY_PREFIXES[pairIndex] | deleteMask;
			int comp2Prefix = PAIR_COMP2_KEY_PREFIXES[pairIndex] | deleteMask;
			for (Map.Entry<Integer, PairBuild.Row> rowEntry : build.rows.entrySet()) {
				int x = rowEntry.getKey();
				PairBuild.Row row = rowEntry.getValue();
				trackRebuiltMap(slot, triplePrefix, x, row.triples);
				trackRebuiltMap(slot, comp1Prefix, x, row.comp1);
				trackRebuiltMap(slot, comp2Prefix, x, row.comp2);
			}
		}
	}

	private void trackRebuiltArray(byte slot, int keyPrefix,
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> sketches) {
		for (int x = 0; x < sketches.length(); x++) {
			trackRebuiltSketch(slot, keyPrefix, x, 0, sketches.get(x));
		}
	}

	private void trackRebuiltMap(byte slot, int keyPrefix, int x,
			Map<Integer, ArrayOfDoublesUpdatableSketch> sketches) {
		for (Map.Entry<Integer, ArrayOfDoublesUpdatableSketch> entry : sketches.entrySet()) {
			trackRebuiltSketch(slot, keyPrefix, x, entry.getKey(), entry.getValue());
		}
	}

	private void trackRebuiltSketch(byte slot, int keyPrefix, int x, int y, ArrayOfDoublesUpdatableSketch sketch) {
		if (sketch == null) {
			return;
		}
		long bytes = estimatedSketchBytes(sketch);
		int keyHash = mixAddressHash(keyPrefix, x, y);
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(keyPrefix, keyHash, x, y);
			cacheDirectory.markDirty(entryId, slot);
			int nodeId = cacheDirectory.residentNode(entryId, slot);
			if (nodeId == -1) {
				int createdNodeId = residentLru.add(entryId, slot, bytes);
				cacheDirectory.setResidentNode(entryId, slot, createdNodeId);
				residentSketchBytes += bytes;
			} else {
				long previousBytes = residentLru.bytes(nodeId);
				residentLru.touch(nodeId, bytes);
				residentSketchBytes += bytes - previousBytes;
			}
		}
		replaceTrackedMemory(MemoryCategory.RESIDENT_SKETCHES, residentOwner(slot, entryId), bytes);
	}

	private void removeResidentSketchTracking(int entryId, byte slot) {
		int nodeId = cacheDirectory.residentNode(entryId, slot);
		if (nodeId == -1) {
			return;
		}
		residentSketchBytes -= residentLru.remove(nodeId);
		cacheDirectory.setResidentNode(entryId, slot, -1);
		releaseTrackedMemory(MemoryCategory.RESIDENT_SKETCHES, residentOwner(slot, entryId));
	}

	private void markDirty(State state, int entryId) {
		byte slot = slotByte(slotOf(state));
		synchronized (sketchCacheLock) {
			cacheDirectory.markDirty(entryId, slot);
		}
		dirty.set(true);
	}

	private boolean isDirty(int entryId, byte slot) {
		synchronized (sketchCacheLock) {
			return cacheDirectory.isDirty(entryId, slot);
		}
	}

	private boolean refreshDirtyFlagFromCacheDirectory() {
		synchronized (sketchCacheLock) {
			boolean hasDirtyEntries = cacheDirectory.hasDirtyEntries((byte) 0)
					|| cacheDirectory.hasDirtyEntries((byte) 1);
			dirty.set(hasDirtyEntries);
			return hasDirtyEntries;
		}
	}

	private void enforceSketchBudget() {
		long targetBytes;
		synchronized (sketchCacheLock) {
			if (residentSketchBytes <= maxSketchMemoryBytes || residentLru.isEmpty()) {
				return;
			}
			targetBytes = minSketchMemoryBytes;
		}

		while (true) {
			int candidateEntryId;
			byte candidateSlot;
			synchronized (sketchCacheLock) {
				if (residentSketchBytes <= targetBytes || residentLru.isEmpty()) {
					return;
				}
				int headNode = residentLru.headNode();
				candidateEntryId = residentLru.entryId(headNode);
				candidateSlot = residentLru.slot(headNode);
			}

			EvictionResult evictionResult = evictResidentSketch(candidateEntryId, candidateSlot);
			if (evictionResult == EvictionResult.NEEDS_UNLOAD) {
				unloadInternal(true);
				return;
			}
			if (evictionResult == EvictionResult.FAILED) {
				return;
			}
		}

	}

	private int evictResidentSketchBatch(int batchSize) {
		int evicted = 0;
		for (int i = 0; i < batchSize; i++) {
			int candidateEntryId;
			byte candidateSlot;
			synchronized (sketchCacheLock) {
				if (residentLru.isEmpty()) {
					return evicted;
				}
				int headNode = residentLru.headNode();
				candidateEntryId = residentLru.entryId(headNode);
				candidateSlot = residentLru.slot(headNode);
			}
			EvictionResult result = evictResidentSketch(candidateEntryId, candidateSlot);
			if (result == EvictionResult.NEEDS_UNLOAD) {
				unloadInternal(true);
				return evicted;
			}
			if (result == EvictionResult.FAILED) {
				return evicted;
			}
			evicted++;
		}
		return evicted;
	}

	private int activeLoadedBucketCount() {
		return residentLruCount();
	}

	private int residentLruCount() {
		synchronized (sketchCacheLock) {
			int count = 0;
			for (int node = residentLru.headNode(); node != -1; node = residentLru.nextNode(node)) {
				count++;
			}
			return count;
		}
	}

	private EvictionResult evictResidentSketch(int entryId, byte slotByte) {
		BufferSlot slot = slotByte == 0 ? BufferSlot.A : BufferSlot.B;
		State state = stateOf(slot);
		SketchAddress sketchAddress;
		synchronized (sketchCacheLock) {
			if (entryId < 0 || entryId >= cacheDirectory.size()) {
				return EvictionResult.EVICTED;
			}
			sketchAddress = cacheDirectory.toSketchAddress(entryId);
		}
		ArrayOfDoublesUpdatableSketch sketch;
		boolean dirtySketch;
		synchronized (state) {
			sketch = getResidentSketch(state, sketchAddress);
			if (sketch == null) {
				synchronized (sketchCacheLock) {
					removeResidentSketchTracking(entryId, slotByte);
				}
				refreshCacheMetadataAccounting();
				return EvictionResult.EVICTED;
			}
			dirtySketch = isDirty(entryId, slotByte);
			if (dirtySketch && persistenceStore == null) {
				return EvictionResult.NEEDS_UNLOAD;
			}
			setResidentSketch(state, sketchAddress, null);
			synchronized (sketchCacheLock) {
				removeResidentSketchTracking(entryId, slotByte);
			}
		}
		refreshCacheMetadataAccounting();
		boolean mappedSketch = sketch.hasMemorySegment();
		if (!dirtySketch) {
			return EvictionResult.EVICTED;
		}
		if (mappedSketch) {
			clearDirtyMappedSketch(entryId, slotByte);
			return EvictionResult.EVICTED;
		}
		synchronized (persistLock) {
			try {
				appendSketchPayload(state, entryId, sketchAddress, sketch);
				return EvictionResult.EVICTED;
			} catch (IOException e) {
				logger.warn("Failed to persist dirty sketch during eviction", e);
				synchronized (state) {
					if (getResidentSketch(state, sketchAddress) == null) {
						setResidentSketch(state, sketchAddress, sketch);
						touchResidentSketch(state, sketchAddress, sketch, false);
					}
				}
				return EvictionResult.FAILED;
			}
		}
	}

	private ArrayOfDoublesUpdatableSketch getResidentSketch(State state, SketchAddress address) {
		return getResidentSketch(state, address.recType, address.isDelete, address.axisA, address.axisB, address.x,
				address.y);
	}

	private ArrayOfDoublesUpdatableSketch getResidentSketch(State state, byte recType, boolean isDelete, byte axisA,
			byte axisB, int x,
			int y) {
		switch (recType) {
		case REC_GLOBAL_COMPONENT: {
			Component component = COMPONENT_VALUES[axisA];
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = state.globalComponents.get(component);
			return arr.get(0);
		}
		case REC_SINGLE_TRIPLE: {
			Component component = COMPONENT_VALUES[axisA];
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = isDelete ? state.delSingleTriples.get(component)
					: state.singleTriples.get(component);
			return arr.get(x);
		}
		case REC_SINGLE_CPL: {
			Component fixed = COMPONENT_VALUES[axisA];
			Component other = COMPONENT_VALUES[axisB];
			SingleBuild build = isDelete ? state.delSingles.get(fixed) : state.singles.get(fixed);
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = build.cmpl.get(other);
			return arr == null ? null : arr.get(x);
		}
		case REC_PAIR_TRIPLE:
		case REC_PAIR_COMP1:
		case REC_PAIR_COMP2: {
			Pair pair = PAIR_VALUES[axisA];
			PairBuild build = isDelete ? state.delPairs.get(pair) : state.pairs.get(pair);
			PairBuild.Row row = build.rows.get(x);
			if (row == null) {
				return null;
			}
			if (recType == REC_PAIR_TRIPLE) {
				return row.triples.get(y);
			}
			if (recType == REC_PAIR_COMP1) {
				return row.comp1.get(y);
			}
			return row.comp2.get(y);
		}
		default:
			throw new IllegalStateException("Unknown sketch record type: " + recType);
		}
	}

	private void setResidentSketch(State state, SketchAddress address, ArrayOfDoublesUpdatableSketch sketch) {
		setResidentSketch(state, address.recType, address.isDelete, address.axisA, address.axisB, address.x,
				address.y, sketch);
	}

	private void setResidentSketch(State state, byte recType, boolean isDelete, byte axisA, byte axisB, int x, int y,
			ArrayOfDoublesUpdatableSketch sketch) {
		switch (recType) {
		case REC_GLOBAL_COMPONENT: {
			Component component = COMPONENT_VALUES[axisA];
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = state.globalComponents.get(component);
			arr.set(0, sketch);
			return;
		}
		case REC_SINGLE_TRIPLE: {
			Component component = COMPONENT_VALUES[axisA];
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = isDelete ? state.delSingleTriples.get(component)
					: state.singleTriples.get(component);
			arr.set(x, sketch);
			return;
		}
		case REC_SINGLE_CPL: {
			Component fixed = COMPONENT_VALUES[axisA];
			Component other = COMPONENT_VALUES[axisB];
			SingleBuild build = isDelete ? state.delSingles.get(fixed) : state.singles.get(fixed);
			AtomicReferenceArray<ArrayOfDoublesUpdatableSketch> arr = build.cmpl.get(other);
			if (arr != null) {
				arr.set(x, sketch);
			}
			return;
		}
		case REC_PAIR_TRIPLE:
		case REC_PAIR_COMP1:
		case REC_PAIR_COMP2: {
			Pair pair = PAIR_VALUES[axisA];
			PairBuild build = isDelete ? state.delPairs.get(pair) : state.pairs.get(pair);
			PairBuild.Row row = build.getOrCreateRow(x);
			Map<Integer, ArrayOfDoublesUpdatableSketch> target;
			if (recType == REC_PAIR_TRIPLE) {
				target = row.triples;
			} else if (recType == REC_PAIR_COMP1) {
				target = row.comp1;
			} else {
				target = row.comp2;
			}
			if (sketch == null) {
				target.remove(y);
				if (row.triples.isEmpty() && row.comp1.isEmpty() && row.comp2.isEmpty()) {
					build.rows.remove(x);
				}
			} else {
				target.put(y, sketch);
			}
			return;
		}
		default:
			throw new IllegalStateException("Unknown sketch record type: " + recType);
		}
	}

	private void flushDirtySketches() throws IOException {
		flushDirtySketches(bufA);
		flushDirtySketches(bufB);
	}

	private void flushDirtySketches(State currentState) throws IOException {
		byte currentSlot = slotByte(slotOf(currentState));
		int[] pending;
		synchronized (sketchCacheLock) {
			pending = cacheDirectory.snapshotDirtyEntries(currentSlot);
		}

		for (int entryId : pending) {
			SketchAddress address;
			synchronized (sketchCacheLock) {
				if (!cacheDirectory.isDirty(entryId, currentSlot)) {
					continue;
				}
				address = cacheDirectory.toSketchAddress(entryId);
			}
			appendDirtySketchIfResident(entryId, address, currentState);
		}
	}

	private boolean appendDirtySketchIfResident(int entryId, SketchAddress address, State state) throws IOException {
		synchronized (state) {
			ArrayOfDoublesUpdatableSketch sketch = getResidentSketch(state, address);
			if (sketch == null) {
				return false;
			}
			byte currentSlot = slotByte(slotOf(state));
			if (sketch.hasMemorySegment()) {
				clearDirtyMappedSketch(entryId, currentSlot);
				return true;
			}
			TrackedByteArray payload = serializeTrackedNativeSketchPayload(MemoryCategory.SERIALIZATION_BUFFERS,
					transientOwner(MEMORY_OWNER_SERIALIZATION_BUFFER, entryId), sketch);
			try {
				synchronized (persistLock) {
					appendNativeSketchPayload(state, entryId, address, payload.bytes);
				}
			} finally {
				releaseTrackedBuffer(payload);
			}
			return true;
		}
	}

	private void appendSketchPayload(State state, SketchAddress address, ArrayOfDoublesUpdatableSketch sketch)
			throws IOException {
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(address);
		}
		if (sketch.hasMemorySegment()) {
			clearDirtyMappedSketch(entryId, slotByte(slotOf(state)));
			return;
		}
		TrackedByteArray payload = serializeTrackedNativeSketchPayload(MemoryCategory.SERIALIZATION_BUFFERS,
				transientOwner(MEMORY_OWNER_SERIALIZATION_BUFFER, entryId), sketch);
		try {
			appendNativeSketchPayload(state, entryId, address, payload.bytes);
		} finally {
			releaseTrackedBuffer(payload);
		}
	}

	private void appendSketchPayload(State state, int entryId, SketchAddress address,
			ArrayOfDoublesUpdatableSketch sketch)
			throws IOException {
		if (sketch.hasMemorySegment()) {
			clearDirtyMappedSketch(entryId, slotByte(slotOf(state)));
			return;
		}
		TrackedByteArray payload = serializeTrackedNativeSketchPayload(MemoryCategory.SERIALIZATION_BUFFERS,
				transientOwner(MEMORY_OWNER_SERIALIZATION_BUFFER, entryId), sketch, false);
		try {
			appendNativeSketchPayload(state, entryId, address, payload.bytes);
		} finally {
			releaseTrackedBuffer(payload);
		}
	}

	private void appendNativeSketchPayload(State state, int entryId, SketchAddress address, byte[] payload)
			throws IOException {
		SketchEstimatorPersistenceStore store = persistenceStore;
		if (store != null) {
			byte slot = slotByte(slotOf(state));
			SketchEstimatorPersistenceStore.Ref persistedRef = store.appendFramedPayload(slot, fileKindFor(address),
					SKETCH_PAYLOAD_FORMAT_NATIVE, payload, slotGenerations[slot]);
			synchronized (sketchCacheLock) {
				cacheDirectory.setPersistedRef(entryId, slot, persistedRef.fileKind, persistedRef.offset,
						persistedRef.length, persistedRef.generation);
				cacheDirectory.clearDirty(entryId, slot);
				indexDirty.set(true);
			}
			return;
		}
		throw new IOException("No directory-backed sketch store configured");
	}

	private void clearDirtyMappedSketch(int entryId, byte slot) {
		synchronized (sketchCacheLock) {
			cacheDirectory.clearDirty(entryId, slot);
		}
	}

	private static byte fileKindFor(SketchAddress address) {
		switch (address.recType) {
		case REC_GLOBAL_COMPONENT:
			return SketchEstimatorPersistenceStore.FILE_KIND_GLOBAL;
		case REC_SINGLE_TRIPLE:
		case REC_SINGLE_CPL:
			return SketchEstimatorPersistenceStore.FILE_KIND_SINGLES;
		case REC_PAIR_TRIPLE:
		case REC_PAIR_COMP1:
		case REC_PAIR_COMP2:
			return SketchEstimatorPersistenceStore.FILE_KIND_PAIRS;
		default:
			throw new IllegalStateException("Unknown sketch record type: " + address.recType);
		}
	}

	private TrackedByteArray serializeTrackedNativeSketchPayload(MemoryCategory category, long ownerId,
			ArrayOfDoublesUpdatableSketch sketch)
			throws IOException {
		return serializeTrackedNativeSketchPayload(category, ownerId, sketch, true);
	}

	private TrackedByteArray serializeTrackedNativeSketchPayload(MemoryCategory category, long ownerId,
			ArrayOfDoublesUpdatableSketch sketch,
			boolean enforceCapacity)
			throws IOException {
		long predictedBytes = estimateByteArrayBytes(Math.max(128, sketch.getCurrentBytes()));
		if (enforceCapacity) {
			ensureEstimatorCapacity(predictedBytes, true);
		}
		reserveTrackedMemory(category, ownerId, predictedBytes);
		try {
			byte[] payload = TupleSketchOps.toByteArray(sketch);
			replaceTrackedMemory(category, ownerId, estimateByteArrayBytes(payload.length));
			return new TrackedByteArray(payload, category, ownerId);
		} catch (RuntimeException e) {
			releaseTrackedMemory(category, ownerId);
			throw e;
		}
	}

	private ArrayOfDoublesUpdatableSketch readSketchFromStore(SketchEstimatorPersistenceStore store,
			PersistedSketchRef persistedSketchRef, byte slot) throws IOException {
		SketchEstimatorPersistenceStore.Ref storeRef = persistedSketchRef.storeRef(slot);
		try {
			return store.readFramedPayload(storeRef, SKETCH_PAYLOAD_FORMAT_NATIVE, TupleSketchOps::wrapUpdatable);
		} catch (RuntimeException e) {
			return store.readFramedPayload(storeRef, SKETCH_PAYLOAD_FORMAT_NATIVE, TupleSketchOps::heapify);
		}
	}

	private void releaseTrackedBuffer(TrackedByteArray trackedByteArray) {
		if (trackedByteArray != null) {
			releaseTrackedMemory(trackedByteArray.category, trackedByteArray.ownerId);
		}
	}

	List<DebugSketchAddress> debugResidentSketches() {
		List<DebugSketchAddress> resident = new ArrayList<>();
		synchronized (sketchCacheLock) {
			for (int node = residentLru.headNode(); node != -1; node = residentLru.nextNode(node)) {
				int entryId = residentLru.entryId(node);
				BufferSlot slot = residentLru.slot(node) == 0 ? BufferSlot.A : BufferSlot.B;
				resident.add(new DebugSketchAddress(slot, cacheDirectory.toSketchAddress(entryId)));
			}
		}
		return resident;
	}

	List<DebugSketchAddress> debugPersistedSketches() {
		List<DebugSketchAddress> persisted = new ArrayList<>();
		synchronized (sketchCacheLock) {
			for (byte slot = 0; slot < 2; slot++) {
				BufferSlot bufferSlot = slot == 0 ? BufferSlot.A : BufferSlot.B;
				for (PersistedSketchEntry entry : cacheDirectory.snapshotPersistedEntries(slot)) {
					persisted.add(new DebugSketchAddress(bufferSlot, entry.address));
				}
			}
		}
		return persisted;
	}

	int debugPendingIncrementalCount() {
		synchronized (incrementalBufferLock) {
			return incrementalBufferCount;
		}
	}

	void debugFlushPendingIncremental() {
		flushPendingIncremental();
	}

